-- „1001 Deadly Checkmates": Nach-(Re-)Import-Fixup — NACH JEDEM NEUIMPORT EINSPIELEN.
-- Macht zwei Dinge:
--   1) Kapitelnamen entschärfen: „Chapter N: <Motiv>" → „Chapter N" (das Motiv wäre sonst ein
--      Spoiler). Re-Import überschreibt das Chapter-Feld → daher nach jedem Import erneut nötig.
--   2) Vorberechnete Tipps wiederherstellen (Sicherungsnetz, falls Buch gelöscht + neu importiert
--      oder unter anderem Nutzer/bid importiert wurde). Beim normalen Re-Import bleibt HintsJson
--      ohnehin erhalten — dann sind die Tipp-UPDATEs nur idempotente No-ops.
--
-- Matcht per stabilem Suffix (Kapitel.Nummer, z. B. :003.004) bzw. Buchdatei → trifft sowohl den
-- Chessable-Kurs (chessable-u5-49690.pgn) als auch die firstkey-Kopie (…_firstkey.pgn), Dev wie Prod.
--
-- Anwenden (Beispiel Dev):
--   docker exec -i rookhub-mariadb-dev mariadb -u<user> -p'<pw>' rookhub < scripts/hints/1001_deadly_checkmates.sql
-- (Prod analog gegen den rookhub-mariadb-Container.)
--
-- Stand Tipps: 1018 Puzzles (vollständiges Buch, 002.002–019.056). Charge 1 = 003.004–003.011,
-- Charge 2 = die übrigen 1010 (per Multi-Agent generiert, de/en/hr, Anti-Leak Stufe 1+2).

-- 1) Kapitelnamen entschärfen (idempotent: bereits gekürzte „Chapter N" haben keinen Doppelpunkt).
UPDATE BookPuzzles SET Chapter = SUBSTRING_INDEX(Chapter, ':', 1)
  WHERE BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn')
    AND Chapter LIKE 'Chapter %:%';

-- 2) Tipps (wiederherstellen / sichern):

UPDATE BookPuzzles SET HintsJson='{"de":["Der König klebt am Rand und sein einziger Verteidiger ist gefesselt.","Ein Turm gibt das Matt, unterstützt von deinem Läufer; der gegnerische Läufer kann nicht eingreifen.","Turm nach c8 – matt."],"en":["The king is stuck on the back rank and its only defender is pinned.","A rook delivers mate, supported by your bishop; the defending bishop cannot interpose.","Rook to c8 — mate."],"hr":["Kralj je zaglavljen na zadnjem redu, a jedini branitelj mu je vezan.","Top daje mat uz potporu tvojeg lovca; protivnički lovac ne može se umiješati.","Top na c8 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der gegnerische König steht ungeschützt im Zentrum, eingeengt von eigenen Figuren.","Ein Springerschach nimmt ihm jedes Fluchtfeld; nichts kann schlagen oder dazwischenziehen.","Springer nach f4 – matt."],"en":["The enemy king is caught in the open centre, boxed in by its own men.","A knight check seals every escape; nothing can capture or block it.","Knight to f4 — mate."],"hr":["Protivnički kralj zaglavljen je u središtu, stiješnjen vlastitim figurama.","Šah skakačem oduzima mu svako polje za bijeg; ništa ne može uzeti ni zakloniti.","Skakač na f4 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der gegnerische König ist zu weit vorgerückt und deine Figuren umzingeln ihn.","Ein Springerschach beendet die Partie; der Turm sperrt bereits den Fluchtweg.","Springer nach e4 – matt."],"en":["The enemy king has advanced too far and your pieces surround it.","A knight check finishes it; the rook already cuts off the escape.","Knight to e4 — mate."],"hr":["Protivnički kralj otišao je predaleko naprijed, a tvoje figure ga okružuju.","Šah skakačem završava partiju; top već presijeca put za bijeg.","Skakač na e4 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist ringsum von Bauern eingemauert; ein Schach genügt.","Schwenke den Turm auf die offene Linie; alle Fluchtfelder sind bereits gedeckt.","Turm nach f3 – matt."],"en":["The white king is walled in by pawns on every side; one check is enough.","Swing your rook onto the open file; every flight square is already covered.","Rook to f3 — mate."],"hr":["Bijeli kralj je sa svih strana zazidan pješacima; jedan šah je dovoljan.","Prebaci top na otvorenu liniju; sva polja za bijeg već su pokrivena.","Top na f3 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Ein aufgedecktes Doppelschach lässt dem König nur die Flucht, die ihm fehlt.","Zieh den Springer so, dass er Schach bietet und zugleich die Dame Schach gibt.","Springer nach f6 – Doppelschach und matt."],"en":["A discovered double check leaves the king nothing but to run, and it cannot.","Move the knight so it gives check while your queen unveils a second check.","Knight to f6 — double check and mate."],"hr":["Otkriveni dvostruki šah ne ostavlja kralju ništa osim bijega, kojeg nema.","Pomakni skakača tako da daje šah dok dama otkriva drugi šah.","Skakač na f6 — dvostruki šah i mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der in die Ecke gedrängte König hat kaum Felder; dein Läufer deckt still den Rest.","Bring die Dame auf die Grundreihe und beherrsche Reihe und Fluchtdiagonale.","Dame nach b1 – matt."],"en":["The cornered king has almost no squares, and your bishop quietly guards the rest.","Bring your queen to the back rank to seize the row and the escape diagonal.","Queen to b1 — mate."],"hr":["Kralj sabijen u kut gotovo da nema polja, a tvoj lovac tiho čuva ostatak.","Dovedi damu na zadnji red i preuzmi red i dijagonalu za bijeg.","Dama na b1 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König kommt aus seiner eigenen Grundreihe nicht heraus; der schlagende Bauer ist gefesselt.","Ein Springer dringt mit Schach ein; der Turm auf der offenen Linie lähmt den einzigen Schlag.","Springer nach b3 – matt."],"en":["The king cannot escape its own back rank, and the pawn that could capture is pinned.","A knight leaps in with check; the rook on the open file freezes the only capture.","Knight to b3 — mate."],"hr":["Kralj ne može pobjeći iz vlastitog zadnjeg reda, a pješak koji bi uzeo je vezan.","Skakač uskače sa šahom; top na otvorenoj liniji sprječava jedino uzimanje.","Skakač na b3 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an den Rand getrieben; beide Läufer und Bauern decken die Ausgänge.","Ein ruhiges Läuferschach auf der Diagonale nimmt das letzte Feld.","Läufer nach f4 – matt."],"en":["The black king is driven to the edge; both your bishops and pawns cover the exits.","A quiet bishop check along the diagonal takes the last square.","Bishop to f4 — mate."],"hr":["Crni kralj je sabijen na rub; oba tvoja lovca i pješaci pokrivaju izlaze.","Tihi šah lovcem po dijagonali oduzima posljednje polje.","Lovac na f4 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');

-- ===== Charge 2: restliche 1010 Puzzles (002.002–019.056), generiert 2026-06-22 =====
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist auf dem Königsflügel angreifbar, sobald die Verteidigung wegbricht.","Eine schwere Figur dringt zur entscheidenden letzten Reihe vor und zwingt den weißen König in die Enge.","Bauer schlägt auf c5 – der Beginn eines erzwungenen Matts."],"en":["The white king is vulnerable on the kingside once the defence is stripped away.","A heavy piece breaks through to the back and drives the white king into a net.","Pawn takes on c5 — the start of a forced mate."],"hr":["Bijeli kralj je ranjiv na kraljevom krilu čim padne obrana.","Teška figura probija do zadnje linije i tjera bijelog kralja u mrežu.","Pješak uzima na c5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:002.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Bauern eingeklemmt und kann seinem Versteck nicht entkommen.","Ein Opfer reißt die Königsstellung auf, dann erledigen Turm und Läufer den Rest.","Dame schlägt auf h7 – der Beginn eines erzwungenen Matts."],"en":["The black king is boxed in behind his own pawns with no real escape.","A sacrifice tears open the king''s cover, and the rook and bishop finish the job.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj je zatvoren iza vlastitih pješaka i nema pravoga bijega.","Žrtva otvara kraljev zaklon, a top i lovac dovršavaju posao.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:002.003' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist mitten im Brett gefangen und findet kein Fluchtfeld.","Ein Turm gibt auf der offenen Linie das entscheidende Schach.","Turm nach e1 – matt."],"en":["The black king is caught in the centre with no escape square.","A rook delivers the decisive check down the open file.","Rook to e1 — mate."],"hr":["Crni kralj je zarobljen u sredini ploče i nema polja za bijeg.","Top daje odlučujući šah po otvorenoj liniji.","Top na e1 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht im Kreuzfeuer der weißen Figuren und kann nicht entweichen.","Ein Läufer schlägt auf der Diagonale zu und setzt den eingeklemmten König matt.","Läufer schlägt auf e8 – matt."],"en":["The black king sits in the crossfire of White''s pieces with no way out.","A bishop strikes along the diagonal to mate the boxed-in king.","Bishop takes on e8 — mate."],"hr":["Crni kralj je u unakrsnoj vatri bijelih figura i nema izlaza.","Lovac udara po dijagonali i matira stiješnjenog kralja.","Lovac uzima na e8 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand eingeschnürt und hat keine Felder mehr.","Ein bescheidener Bauernzug nimmt dem König das letzte Fluchtfeld und der Turm mattet.","Bauer nach f4 – matt."],"en":["The black king is hemmed in on the edge with no squares left.","A quiet pawn move takes the king''s last flight square and the rook mates.","Pawn to f4 — mate."],"hr":["Crni kralj je stiješnjen na rubu i nema više polja.","Tihi potez pješaka uzima kralju zadnje polje za bijeg, a top matira.","Pješak na f4 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist eingekreist und die Felder um ihn sind alle gedeckt oder versperrt.","Ein Läuferzug ohne Schach nimmt dem König das letzte Atemfeld.","Läufer nach d6 – matt."],"en":["The black king is surrounded, every square around him covered or blocked.","A quiet bishop move strips the king of his last breathing square.","Bishop to d6 — mate."],"hr":["Crni kralj je okružen, sva su polja oko njega pokrivena ili zatvorena.","Tihi potez lovca oduzima kralju zadnje polje za disanje.","Lovac na d6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König im Zentrum ist plötzlich von einem versteckten Springerangriff bedroht.","Ein Springer springt heran und gibt dem König im offenen Feld matt.","Springer nach g3 – matt."],"en":["The white king in the centre is suddenly caught by a hidden knight attack.","A knight leaps in and mates the exposed king in the open.","Knight to g3 — mate."],"hr":["Bijeli kralj u centru iznenada je uhvaćen skrivenim napadom skakača.","Skakač uskače i matira izloženog kralja na otvorenom.","Skakač na g3 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke eingeklemmt und seine eigenen Figuren rauben ihm die Felder.","Ein Springer landet erstickend dicht am König und beendet die Partie.","Springer nach g6 – matt."],"en":["The black king is jammed in the corner, his own pieces stealing his squares.","A knight lands smotheringly close to the king and ends it.","Knight to g6 — mate."],"hr":["Crni kralj je stiješnjen u kutu, a vlastite mu figure kradu polja.","Skakač slijeće gušeći tik uz kralja i završava partiju.","Skakač na g6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist unzureichend gedeckt und gegen eine Damen-Springer-Attacke wehrlos.","Die Dame dringt ein und treibt den König in ein tödliches Netz.","Dame nach f1 – der Beginn eines erzwungenen Matts."],"en":["The white king is poorly shielded and helpless against a queen-and-knight attack.","The queen plunges in and herds the king into a lethal net.","Queen to f1 — the start of a forced mate."],"hr":["Bijeli kralj je slabo zaštićen i bespomoćan protiv napada dame i skakača.","Dama prodire i tjera kralja u smrtonosnu mrežu.","Dama na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt am Rand und seine Bauern verstellen ihm jede Flucht.","Ein Turm dringt in die hinterste Reihe ein und schnürt den König mit Läuferhilfe ein.","Turm nach a1 – der Beginn eines erzwungenen Matts."],"en":["The white king clings to the edge with his own pawns blocking any flight.","A rook invades the back and, with the bishop''s help, seals the king in.","Rook to a1 — the start of a forced mate."],"hr":["Bijeli kralj se drži ruba, a vlastiti mu pješaci zatvaraju svaki bijeg.","Top upada na zadnju liniju i uz pomoć lovca zatvara kralja.","Top na a1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König hat eine schwache letzte Reihe und steht offen für einen Damenüberfall.","Die Dame dringt entscheidend ein und der König findet kein Entkommen mehr.","Dame nach e3 – der Beginn eines erzwungenen Matts."],"en":["The white king has a weak back rank and lies open to a queen raid.","The queen forces her way in and the king can no longer escape.","Queen to e3 — the start of a forced mate."],"hr":["Bijeli kralj ima slabu zadnju liniju i otvoren je za napad dame.","Dama se silom probija i kralj više nema bijega.","Dama na e3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht entblößt am Rand und ist einem Damenangriff ausgeliefert.","Die Dame schlägt einen Bauern und jagt den König in ein Mattnetz.","Dame schlägt auf c4 – der Beginn eines erzwungenen Matts."],"en":["The white king stands exposed on the edge, prey to a queen attack.","The queen grabs a pawn and drives the king into a mating net.","Queen takes on c4 — the start of a forced mate."],"hr":["Bijeli kralj stoji izložen na rubu, plijen napada dame.","Dama uzima pješaka i tjera kralja u matnu mrežu.","Dama uzima na c4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und der weiße Freibauer verstärkt das Mattbild.","Ein Turm zieht in die hinterste Reihe und ein Bauer liefert den Todesstoß.","Turm nach h8 – der Beginn eines erzwungenen Matts."],"en":["The black king is pinned to the edge while White''s passed pawn sets up the mate.","A rook swings to the back rank and a pawn delivers the killing blow.","Rook to h8 — the start of a forced mate."],"hr":["Crni kralj je prikovan uz rub dok bijeli prolazni pješak priprema mat.","Top prelazi na zadnju liniju, a pješak zadaje smrtni udarac.","Top na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König hat eine völlig ungedeckte letzte Reihe.","Ein Damenopfer räumt die Linie, dann mattet ein Turm auf der Grundreihe.","Dame nach e1 – der Beginn eines erzwungenen Matts."],"en":["The white king has a completely undefended back rank.","A queen sacrifice clears the line, then a rook mates on the first rank.","Queen to e1 — the start of a forced mate."],"hr":["Bijeli kralj ima potpuno nezaštićenu zadnju liniju.","Žrtva dame čisti liniju, a zatim top matira na prvoj liniji.","Dama na e1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist mitten im Brett gefährlich exponiert.","Ein Bauernvorstoß lockt den König heraus, dann setzt der Turm matt.","Bauer nach e5 – der Beginn eines erzwungenen Matts."],"en":["The white king is dangerously exposed in the centre of the board.","A pawn thrust lures the king forward, then the rook delivers mate.","Pawn to e5 — the start of a forced mate."],"hr":["Bijeli kralj je opasno izložen u sredini ploče.","Prodor pješaka mami kralja naprijed, a zatim top daje mat.","Pješak na e5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.024' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist eingeengt und ein Springer lauert auf ein vernichtendes Schach.","Ein Damenzug fesselt die Verteidigung, dann gibt der Springer das Mattschach.","Dame nach a8 – der Beginn eines erzwungenen Matts."],"en":["The black king is cramped and a knight lurks ready for a crushing check.","A queen move ties down the defence, then the knight gives the mating check.","Queen to a8 — the start of a forced mate."],"hr":["Crni kralj je stiješnjen, a skakač vreba spreman za razoran šah.","Potez dame veže obranu, a zatim skakač daje matni šah.","Dama na a8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.025' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist am Rand gefangen und die eigenen Bauern und Figuren versperren ihm alles.","Ein ruhiger Königszug stellt eine unausweichliche Mattdrohung des Turms her.","König nach f7 – der Beginn eines erzwungenen Matts."],"en":["The white king is trapped on the edge, his own pawns and pieces blocking everything.","A quiet king move sets up an unstoppable mating threat from the rook.","King to f7 — the start of a forced mate."],"hr":["Bijeli kralj je zarobljen na rubu, a vlastiti pješaci i figure sve mu zatvaraju.","Tihi potez kralja stvara nezaustavljivu matnu prijetnju topom.","Kralj na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.026' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht in der Ecke und ist anfällig für einen Springervorstoß.","Ein Springer springt mit Schach heran und treibt den König ins Matt.","Springer nach e7 – der Beginn eines erzwungenen Matts."],"en":["The black king sits in the corner, vulnerable to a knight leap.","A knight jumps in with check and forces the king toward mate.","Knight to e7 — the start of a forced mate."],"hr":["Crni kralj je u kutu, ranjiv na skok skakača.","Skakač uskače sa šahom i tjera kralja prema matu.","Skakač na e7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.027' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht offen im Zentrum und kann einem Turmangriff nicht entrinnen.","Ein Turm schlägt einen Bauern und schnürt den König dann mit einem zweiten Turmschach ein.","Turm schlägt auf d6 – der Beginn eines erzwungenen Matts."],"en":["The black king is open in the centre and cannot escape a rook attack.","A rook grabs a pawn and then seals the king with a second rook check.","Rook takes on d6 — the start of a forced mate."],"hr":["Crni kralj je otvoren u centru i ne može pobjeći napadu topa.","Top uzima pješaka, a zatim drugim šahom topa zatvara kralja.","Top uzima na d6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.028' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Bauern eingeschlossen und schlecht geschützt.","Ein Damenopfer öffnet den Weg, dann mattet der Läufer dicht am König.","Dame schlägt auf h6 – der Beginn eines erzwungenen Matts."],"en":["The black king is shut in behind his pawns and poorly protected.","A queen sacrifice opens the way, then the bishop mates right beside the king.","Queen takes on h6 — the start of a forced mate."],"hr":["Crni kralj je zatvoren iza svojih pješaka i slabo zaštićen.","Žrtva dame otvara put, a zatim lovac matira tik uz kralja.","Dama uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.029' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch einen bereits dicht herangerückten Läufer mit angegriffen.","Ein Damenopfer zieht den König heraus, dann setzt der Läufer matt.","Dame schlägt auf f7 – der Beginn eines erzwungenen Matts."],"en":["The black king is already harassed by a bishop sitting close to his shelter.","A queen sacrifice drags the king out, then the bishop delivers mate.","Queen takes on f7 — the start of a forced mate."],"hr":["Crnog kralja već uznemiruje lovac smješten tik uz njegov zaklon.","Žrtva dame izvlači kralja, a zatim lovac daje mat.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.030' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand kann der vereinten Turm- und Läuferdrohung nicht entkommen.","Ein Läuferzug erzwingt eine Schwächung, dann dringt der Turm zum Matt durch.","Läufer schlägt auf b4 – der Beginn eines erzwungenen Matts."],"en":["The black king on the edge cannot escape the combined rook-and-bishop threat.","A bishop move forces a weakening, then the rook breaks through to mate.","Bishop takes on b4 — the start of a forced mate."],"hr":["Crni kralj na rubu ne može pobjeći združenoj prijetnji topa i lovca.","Potez lovca prisiljava na slabljenje, a zatim top probija do mata.","Lovac uzima na b4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.031' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke und seine eigenen Steine engen ihn ein.","Ein Damenopfer lenkt den König ab, dann erledigt der Springer den Rest.","Dame schlägt auf h6 – der Beginn eines erzwungenen Matts."],"en":["The black king clings to the corner, hemmed in by his own men.","A queen sacrifice diverts the king, then the knight finishes the job.","Queen takes on h6 — the start of a forced mate."],"hr":["Crni kralj se drži kuta, stiješnjen vlastitim figurama.","Žrtva dame odvlači kralja, a zatim skakač dovršava posao.","Dama uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.032' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand entblößt und einem Spurwechsel der Figuren ausgeliefert.","Ein Springer schlägt mit Schach und lenkt den König ab, dann dringt der Turm ein.","Springer schlägt auf e6 – der Beginn eines erzwungenen Matts."],"en":["The black king is bared on the edge, at the mercy of the attacking pieces.","A knight captures with check to divert the king, then the rook invades.","Knight takes on e6 — the start of a forced mate."],"hr":["Crni kralj je ogoljen na rubu, prepušten napadačkim figurama.","Skakač uzima sa šahom da odvuče kralja, a zatim top upada.","Skakač uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.033' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke eingeklemmt und die Verteidiger sind überlastet.","Ein Damenopfer beseitigt einen Verteidiger, dann gibt die Dame das Matt am Rand.","Dame schlägt auf h6 – der Beginn eines erzwungenen Matts."],"en":["The black king is jammed in the corner and the defenders are overloaded.","A queen sacrifice removes a defender, then the queen mates on the edge.","Queen takes on h6 — the start of a forced mate."],"hr":["Crni kralj je stiješnjen u kutu, a branitelji su preopterećeni.","Žrtva dame uklanja branitelja, a zatim dama matira na rubu.","Dama uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.034' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke gefangen und seine eigenen Bauern ersticken ihn.","Ein Springeropfer reißt die Königsstellung auf, dann mattet der Turm.","Springer schlägt auf g6 – der Beginn eines erzwungenen Matts."],"en":["The black king is trapped in the corner, smothered by his own pawns.","A knight sacrifice tears open the king''s shelter, then the rook mates.","Knight takes on g6 — the start of a forced mate."],"hr":["Crni kralj je zarobljen u kutu, ugušen vlastitim pješacima.","Žrtva skakača otvara kraljev zaklon, a zatim top matira.","Skakač uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.035' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht ungeschützt im Freien und kann den Damen nicht entkommen.","Ein Damenopfer lockt den König heraus, dann gibt die andere Dame matt.","Dame schlägt auf e3 – der Beginn eines erzwungenen Matts."],"en":["The white king stands unguarded in the open, unable to escape the queens.","A queen sacrifice lures the king forward, then the other queen mates.","Queen takes on e3 — the start of a forced mate."],"hr":["Bijeli kralj stoji nezaštićen na otvorenom i ne može pobjeći damama.","Žrtva dame mami kralja naprijed, a zatim druga dama matira.","Dama uzima na e3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.036' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke eingeschnürt und reif für einen Springersprung.","Ein Springer springt mit Schach heran, dann mattet die Dame dicht am König.","Springer nach f6 – der Beginn eines erzwungenen Matts."],"en":["The black king is hemmed into the corner, ripe for a knight leap.","A knight jumps in with check, then the queen mates right next to the king.","Knight to f6 — the start of a forced mate."],"hr":["Crni kralj je stiješnjen u kut, zreo za skok skakača.","Skakač uskače sa šahom, a zatim dama matira tik uz kralja.","Skakač na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.037' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist eingeengt und ein Opfer macht ihn vollends wehrlos.","Ein Turmopfer zieht den König ins Schussfeld, dann dringt die Dame zum Matt durch.","Turm schlägt auf f8 – der Beginn eines erzwungenen Matts."],"en":["The black king is cramped, and a sacrifice strips away his last defence.","A rook sacrifice draws the king into the firing line, then the queen mates.","Rook takes on f8 — the start of a forced mate."],"hr":["Crni kralj je stiješnjen, a žrtva mu oduzima posljednju obranu.","Žrtva topa povlači kralja u liniju vatre, a zatim dama daje mat.","Top uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.038' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht im Freien und kann dem Springerangriff nicht ausweichen.","Ein Bauernvorstoß öffnet die Linie, dann gibt der Springer das Mattschach.","Bauer nach g4 – der Beginn eines erzwungenen Matts."],"en":["The black king is out in the open and cannot dodge the knight attack.","A pawn thrust opens the line, then the knight gives the mating check.","Pawn to g4 — the start of a forced mate."],"hr":["Crni kralj je na otvorenom i ne može izbjeći napad skakača.","Prodor pješaka otvara liniju, a zatim skakač daje matni šah.","Pješak na g4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.039' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und hat kaum Luft zum Atmen.","Eine Dame leitet das Matt ein, danach erledigt der Turm den Rest.","Dame nach h3 – Beginn eines erzwungenen Matts."],"en":["The black king clings to the edge with barely any breathing room.","A queen begins the mating attack, then a rook finishes the job.","Queen to h3 — the start of a forced mate."],"hr":["Crni kralj se drži ruba ploče i jedva da diše.","Dama započinje matni napad, a top potom dovršava posao.","Dama na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.040' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König wird ans Brettende getrieben und das Netz zieht sich zu.","Erst lockt der Turm den König weiter, dann gibt der Springer den Todesstoß.","Turm nach f4 – Beginn eines erzwungenen Matts."],"en":["The king is herded toward the edge and the net tightens.","A rook lures the king first, then the knight delivers the final blow.","Rook to f4 — the start of a forced mate."],"hr":["Kralja se tjera prema rubu i mreža se steže.","Top najprije mami kralja, a skakač zatim zadaje konačni udarac.","Top na f4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.041' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König geht ruhig zur Seite und überlässt dem Läufer das Wort.","Ein bescheidener Königszug ist ein tödliches Zugzwang-Matt.","König nach g2 – matt."],"en":["The white king quietly steps aside and lets the bishop do the talking.","A modest king move is a deadly stalemate-style mating blow.","King to g2 — mate."],"hr":["Bijeli kralj mirno se odmiče i prepušta riječ lovcu.","Skroman kraljev potez je smrtonosan matni udarac.","Kralj na g2 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.042' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
