UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König leidet an der schwachen Grundreihe und ein Opfer lenkt ab.","Ein Turmopfer lenkt einen Verteidiger weg, dann dringt der andere Turm matt ein.","Turm schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king suffers from a weak back rank and a sacrifice deflects.","A rook sacrifice deflects a defender, then the other rook invades for mate.","Rook takes on f8 — the start of a forced mate."],"hr":["Crni kralj pati zbog slabog zadnjeg reda, a žrtva odvlači.","Žrtva topa odvlači branitelja, a zatim drugi top prodire u mat.","Top uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.060' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in die Ecke getrieben und zwei Springer weben das Netz.","Ein Springer treibt den König in die Ecke, dann setzt der andere Springer matt.","Springer nach f6 – Beginn eines erzwungenen Matts."],"en":["The black king is driven into the corner and two knights weave the net.","A knight forces the king into the corner, then the other knight delivers mate.","Knight to f6 — the start of a forced mate."],"hr":["Crni kralj se tjera u kut, a dva skakača pletu mrežu.","Skakač tjera kralja u kut, a zatim drugi skakač daje mat.","Skakač na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.061' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke fast erstickt und ein Bauer rückt tödlich vor.","Ein Springer öffnet die Linie, dann setzt der vorrückende Bauer matt.","Springer schlägt auf c6 – Beginn eines erzwungenen Matts."],"en":["The black king is nearly smothered in the corner and a pawn pushes in for the kill.","A knight clears the line, then the advancing pawn delivers mate.","Knight takes on c6 — the start of a forced mate."],"hr":["Crni kralj je gotovo ugušen u kutu, a pješak smrtonosno napreduje.","Skakač oslobađa liniju, a zatim napredujući pješak daje mat.","Skakač uzima na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.062' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt am Rand und ein Opfer treibt ihn nach vorn.","Ein Turmopfer lockt den König, dann setzt die Dame matt.","Turm schlägt auf h4 – Beginn eines erzwungenen Matts."],"en":["The white king clings to the edge and a sacrifice pushes it forward.","A rook sacrifice lures the king, then the queen delivers mate.","Rook takes on h4 — the start of a forced mate."],"hr":["Bijeli kralj se drži ruba, a žrtva ga gura naprijed.","Žrtva topa mami kralja, a zatim dama daje mat.","Top uzima na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.063' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke gefangen und ein Opfer reißt die Deckung weg.","Ein Turmopfer lenkt den König ab, dann setzt die Dame matt.","Turm schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king is trapped in the corner and a sacrifice strips its cover.","A rook sacrifice deflects the king, then the queen delivers mate.","Rook takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj je zarobljen u kutu, a žrtva mu skida zaklon.","Žrtva topa odvlači kralja, a zatim dama daje mat.","Top uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.064' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf dunklen Feldern verwundbar und ein Opfer öffnet sie.","Ein Damenopfer lenkt einen Verteidiger ab, dann schlägt der Bauer tödlich ein.","Dame nach g5 – Beginn eines erzwungenen Matts."],"en":["The black king is vulnerable on the dark squares and a sacrifice opens them.","A queen sacrifice deflects a defender, then the pawn strikes fatally.","Queen to g5 — the start of a forced mate."],"hr":["Crni kralj je ranjiv na crnim poljima, a žrtva ih otvara.","Žrtva dame odvlači branitelja, a zatim pješak smrtonosno udara.","Dama na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.065' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird mit einem Opfer aus der Deckung gelockt.","Ein Damenopfer öffnet die Linie, dann springt der Springer zum Matt.","Dame schlägt auf h5 – Beginn eines erzwungenen Matts."],"en":["The black king is coaxed out of its shelter with a sacrifice.","A queen sacrifice opens the line, then the knight leaps in for mate.","Queen takes on h5 — the start of a forced mate."],"hr":["Crni kralj se žrtvom izvlači iz zaklona.","Žrtva dame otvara liniju, a zatim skakač uskače u mat.","Dama uzima na h5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.066' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt am Rand und ein Opfer reißt die Bauerndeckung auf.","Ein Läuferopfer öffnet die Stellung, dann schlägt der Bauer tödlich durch.","Läufer schlägt auf g4 – Beginn eines erzwungenen Matts."],"en":["The white king clings to the edge and a sacrifice tears open its pawn cover.","A bishop sacrifice opens the position, then the pawn strikes fatally.","Bishop takes on g4 — the start of a forced mate."],"hr":["Bijeli kralj se drži ruba, a žrtva mu otvara pješački zaklon.","Žrtva lovca otvara položaj, a zatim pješak smrtonosno udara.","Lovac uzima na g4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.067' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird mit einem Opfer auf ein tödliches Feld gezogen.","Ein Damenopfer lockt den König, dann setzt der Läufer matt.","Dame schlägt auf f2 – Beginn eines erzwungenen Matts."],"en":["The white king is dragged onto a fatal square by a sacrifice.","A queen sacrifice lures the king, then the bishop delivers mate.","Queen takes on f2 — the start of a forced mate."],"hr":["Bijeli kralj se žrtvom navlači na smrtonosno polje.","Žrtva dame mami kralja, a zatim lovac daje mat.","Dama uzima na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.068' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und ein Opfer beseitigt den Verteidiger.","Ein Damenopfer lenkt einen Springer ab, dann schlägt der Bauer matt.","Dame nach g3 – Beginn eines erzwungenen Matts."],"en":["The black king clings to the edge and a sacrifice removes its defender.","A queen sacrifice deflects a knight, then the pawn delivers mate.","Queen to g3 — the start of a forced mate."],"hr":["Crni kralj se drži ruba, a žrtva uklanja branitelja.","Žrtva dame odvlači skakača, a zatim pješak daje mat.","Dama na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.069' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht ungeschützt am Rand und kann durch ein Bauern-Vorrücken erstickt werden.","Eine Figur lenkt den weißen König ab, dann gibt ein Bauer das tödliche Schach.","Turm nach e1 – Beginn eines erzwungenen Matts."],"en":["The white king is exposed on the edge and can be smothered by an advancing pawn.","A piece deflects the white king, then a pawn delivers the killing check.","Rook to e1 — the start of a forced mate."],"hr":["Bijeli kralj je nezaštićen uz rub i može biti ugušen napredovanjem pješaka.","Figura odvlači bijelog kralja, a zatim pješak daje smrtonosni šah.","Top na e1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.070' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und hat fast keine Luft mehr.","Erst lockt ein Damenopfer den Bauern weg, dann dringt ein Turm zum Mattfeld vor.","Dame nach h4 – Beginn eines erzwungenen Matts."],"en":["The black king is pinned to the edge with almost no breathing room.","A queen sacrifice first lures a pawn away, then a rook crashes through to the mating square.","Queen to h4 — the start of a forced mate."],"hr":["Crni kralj je prikovan uz rub i gotovo da nema zraka.","Žrtva dame najprije odvlači pješaka, a zatim top prodire do polja mata.","Dama na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.071' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König lässt sich aus seiner Bauerndeckung herauslocken.","Ein Bauernopfer öffnet die Stellung, dann liefert die Dame das Schlussschach.","Bauer nach h6 – Beginn eines erzwungenen Matts."],"en":["The black king can be dragged out from behind its pawn cover.","A pawn sacrifice opens the position, then the queen delivers the final check.","Pawn to h6 — the start of a forced mate."],"hr":["Crni kralj se može izvući iza svoje pješačke zaštite.","Žrtva pješaka otvara poziciju, a zatim dama daje završni šah.","Pješak na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.072' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt hinter seinen eigenen Figuren in der Falle.","Mit Opfern wird die letzte Reihe geöffnet, bevor ein Turm Matt setzt.","Turm nach g8 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped behind its own crowded pieces.","Sacrifices pry open the back rank before a rook finishes the job.","Rook to g8 — the start of a forced mate."],"hr":["Crni kralj je zarobljen iza vlastitih nagomilanih figura.","Žrtve otvaraju posljednju liniju prije nego top zadaje mat.","Top na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.073' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird aufs offene Feld getrieben und vom Läuferpaar eingefangen.","Ein Turmopfer zieht den König heran, dann setzt ein Bauer mit Läuferhilfe matt.","Turm schlägt auf f6 – Beginn eines erzwungenen Matts."],"en":["The black king is driven into the open and netted by the bishops.","A rook sacrifice pulls the king forward, then a pawn mates with bishop support.","Rook takes on f6 — the start of a forced mate."],"hr":["Crni kralj se tjera na otvoreno i hvata ga par lovaca.","Žrtva topa privlači kralja, a zatim pješak uz pomoć lovca daje mat.","Top uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.074' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird durch ein Doppelturm-Manöver erstickt.","Ein Turm dringt entscheidend ein, der zweite Turm gibt dann das Mattschach.","Turm nach d3 – Beginn eines erzwungenen Matts."],"en":["The white king gets smothered by a doubled-rook manoeuvre.","One rook penetrates decisively, then the second rook delivers the mating check.","Rook to d3 — the start of a forced mate."],"hr":["Bijeli kralj biva ugušen manevrom dvaju topova.","Jedan top odlučujuće prodire, a zatim drugi top daje mat-šah.","Top na d3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.075' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht eingemauert am Rand und der Läufer kontrolliert das Fluchtfeld.","Der Läufer gibt das entscheidende Schach – mattgesetzt durch König und Diagonale.","Läufer nach g4 – matt."],"en":["The black king is boxed in on the edge with the bishop covering its escape.","The bishop delivers the decisive check, the king cut off by king and diagonal.","Bishop to g4 — mate."],"hr":["Crni kralj je zazidan uz rub, a lovac pokriva polje za bijeg.","Lovac daje odlučujući šah, kralja zatvaraju kralj i dijagonala.","Lovac na g4 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.076' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf der letzten Reihe eingesperrt.","Ein Turmopfer lockt eine Figur weg, dann setzt die Dame über die lange Diagonale matt.","Turm nach f8 – Beginn eines erzwungenen Matts."],"en":["The black king is locked in on the back rank.","A rook sacrifice lures a piece away, then the queen mates down the long diagonal.","Rook to f8 — the start of a forced mate."],"hr":["Crni kralj je zatvoren na posljednjoj liniji.","Žrtva topa odvlači figuru, a zatim dama daje mat po dugoj dijagonali.","Top na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.077' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht entblößt in der Brettmitte.","Erst lockt ein Läufer den König vor, dann setzt der zweite Läufer matt.","Läufer nach e4 – Beginn eines erzwungenen Matts."],"en":["The black king stands exposed in the centre of the board.","One bishop first lures the king forward, then the other bishop mates.","Bishop to e4 — the start of a forced mate."],"hr":["Crni kralj stoji izložen u sredini ploče.","Jedan lovac najprije izmamljuje kralja, a zatim drugi lovac daje mat.","Lovac na e4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.078' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand gefangen und kann erstickt werden.","Ein Damenopfer öffnet die Reihe, dann gibt ein Bauer das Mattschach.","Dame nach h8 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped on the edge and ripe for smothering.","A queen sacrifice opens the rank, then a pawn delivers the mating check.","Queen to h8 — the start of a forced mate."],"hr":["Crni kralj je zarobljen uz rub i može biti ugušen.","Žrtva dame otvara liniju, a zatim pješak daje mat-šah.","Dama na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.079' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springer setzt mit Hilfe der Figuren ein erstickendes Netz um den schwarzen König.","Ein Springer treibt den König in die Ecke, dann setzt der zweite Springer matt.","Springer nach d6 – Beginn eines erzwungenen Matts."],"en":["A knight weaves a smothering net around the black king with its pieces.","One knight drives the king into the corner, then the other knight mates.","Knight to d6 — the start of a forced mate."],"hr":["Skakač uz pomoć figura plete ugušujuću mrežu oko crnog kralja.","Jedan skakač tjera kralja u kut, a zatim drugi skakač daje mat.","Skakač na d6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.080' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird an den Rand getrieben und vom Turm gestellt.","Erst geht der König vor, dann liefert der Turm an der Seite das Mattschach.","Bauer nach g5 – Beginn eines erzwungenen Matts."],"en":["The white king is pushed to the edge and caught by the rook.","First the king advances, then the rook delivers the mating check from the side.","Pawn to g5 — the start of a forced mate."],"hr":["Bijeli kralj se tjera uz rub i hvata ga top.","Najprije kralj napreduje, a zatim top sa strane daje mat-šah.","Pješak na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.081' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf der letzten Reihe hinter seinen Bauern eingeschlossen.","Ein Damenopfer räumt die Linie, dann setzt ein Turm auf der letzten Reihe matt.","Dame schlägt auf c6 – Beginn eines erzwungenen Matts."],"en":["The black king is shut in on the back rank behind its pawns.","A queen sacrifice clears the file, then a rook mates on the back rank.","Queen takes on c6 — the start of a forced mate."],"hr":["Crni kralj je zatvoren na posljednjoj liniji iza svojih pješaka.","Žrtva dame čisti liniju, a zatim top daje mat na posljednjoj liniji.","Dama uzima na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.082' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und ein Springer nimmt ihm die Felder.","Der Springer engt den König ein, dann gibt der Turm seitlich das Mattschach.","Springer nach g3 – Beginn eines erzwungenen Matts."],"en":["The black king is stuck on the edge with a knight stealing its squares.","The knight restricts the king, then the rook delivers the mating check from the side.","Knight to g3 — the start of a forced mate."],"hr":["Crni kralj je zaglavljen uz rub, a skakač mu oduzima polja.","Skakač sužava kralja, a zatim top sa strane daje mat-šah.","Skakač na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.083' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird in die Ecke gedrängt und von Läufer und Springer erstickt.","Ein Läufer schneidet die Flucht ab, dann setzt ein Springer matt.","Läufer nach d5 – Beginn eines erzwungenen Matts."],"en":["The white king is forced into the corner and smothered by bishop and knight.","A bishop cuts off the escape, then a knight delivers mate.","Bishop to d5 — the start of a forced mate."],"hr":["Bijeli kralj se tjera u kut i guše ga lovac i skakač.","Lovac presijeca bijeg, a zatim skakač daje mat.","Lovac na d5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.084' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird an den Rand getrieben, wo Dame und Bauern das Netz schließen.","Erst gibt die Dame das treibende Schach, dann macht ein Bauer das Netz dicht.","Dame nach f1 – Beginn eines erzwungenen Matts."],"en":["The white king is driven to the edge where queen and pawns close the net.","The queen gives the driving check first, then a pawn seals the mating net.","Queen to f1 — the start of a forced mate."],"hr":["Bijeli kralj se tjera uz rub gdje dama i pješaci zatvaraju mrežu.","Dama najprije daje tjerajući šah, a zatim pješak zatvara mrežu mata.","Dama na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.085' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in die Brettmitte gelockt und eingekreist.","Ein Springer lockt mit Schach den König vor, dann setzt ein Turm matt.","Springer nach f3 – Beginn eines erzwungenen Matts."],"en":["The black king is lured into the centre and surrounded.","A knight check pulls the king forward, then a rook delivers mate.","Knight to f3 — the start of a forced mate."],"hr":["Crni kralj se izmamljuje u sredinu ploče i opkoljava.","Skakač šahom privlači kralja, a zatim top daje mat.","Skakač na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.086' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht in der Ecke und kann erstickt werden.","Ein Springer treibt den König in die Ecke, dann setzt der zweite Springer matt.","Springer nach g3 – Beginn eines erzwungenen Matts."],"en":["The white king sits in the corner, ripe for a smothered mate.","One knight drives the king into the corner, then the other knight mates.","Knight to g3 — the start of a forced mate."],"hr":["Bijeli kralj je u kutu i može biti ugušen.","Jedan skakač tjera kralja u kut, a zatim drugi skakač daje mat.","Skakač na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.087' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Springer- und Bauernduo eingeengt.","Ein Springer nimmt dem König die Felder, dann setzt ein Bauer matt.","Springer nach h6 – Beginn eines erzwungenen Matts."],"en":["The black king is hemmed in by a knight-and-pawn duo.","A knight strips the king of its squares, then a pawn delivers mate.","Knight to h6 — the start of a forced mate."],"hr":["Crni kralj je stiješnjen dvojcem skakača i pješaka.","Skakač oduzima kralju polja, a zatim pješak daje mat.","Skakač na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.088' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke gefangen und kann erstickt werden.","Ein Springer treibt den König in die Ecke, dann setzt ein Turm matt.","Springer schlägt auf f6 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped in the corner and can be smothered.","A knight drives the king into the corner, then a rook delivers mate.","Knight takes on f6 — the start of a forced mate."],"hr":["Crni kralj je zarobljen u kutu i može biti ugušen.","Skakač tjera kralja u kut, a zatim top daje mat.","Skakač uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.089' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird am Rand vom Turmpaar gejagt.","Ein Turm lenkt den Läufer ab, dann liefert der zweite Turm das Mattschach.","Turm nach g3 – Beginn eines erzwungenen Matts."],"en":["The black king is hunted along the edge by the pair of rooks.","One rook deflects the bishop, then the other rook delivers the mating check.","Rook to g3 — the start of a forced mate."],"hr":["Crni kralj je progonjen uz rub parom topova.","Jedan top odvlači lovca, a zatim drugi top daje mat-šah.","Top na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.090' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird vorgetrieben und vom Läufer eingefangen.","Erst lockt ein Turm den König vor, dann setzt der Läufer matt.","Turm schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king is driven forward and netted by the bishop.","First a rook lures the king forward, then the bishop delivers mate.","Rook takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj se tjera naprijed i hvata ga lovac.","Najprije top izmamljuje kralja, a zatim lovac daje mat.","Top uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.091' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht in der Ecke fest und wird erdrückt.","Ein Turmopfer treibt den König in die Ecke, dann setzt der zweite Turm matt.","Turm schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king is stuck in the corner and gets crushed.","A rook sacrifice forces the king into the corner, then the other rook mates.","Rook takes on g7 — the start of a forced mate."],"hr":["Crni kralj je zaglavljen u kutu i biva smrvljen.","Žrtva topa tjera kralja u kut, a zatim drugi top daje mat.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.092' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein klassisches Läuferopfer aufgerissen.","Ein Läuferopfer holt den König heraus, dann setzt ein Springer matt.","Läufer schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is ripped open by a classic bishop sacrifice.","A bishop sacrifice draws the king out, then a knight delivers mate.","Bishop takes on h7 — the start of a forced mate."],"hr":["Crni kralj se otvara klasičnom žrtvom lovca.","Žrtva lovca izvlači kralja, a zatim skakač daje mat.","Lovac uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.093' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist von seinen eigenen Bauern auf der Grundreihe eingesperrt.","Die Dame dringt auf der letzten Reihe ein und gibt das Schlussschach.","Dame schlägt auf d8 – matt."],"en":["The black king is shut in on the back rank by its own pawns.","The queen penetrates the back rank and delivers the final check.","Queen takes on d8 — mate."],"hr":["Crni kralj je zatvoren na posljednjoj liniji vlastitim pješacima.","Dama prodire na posljednju liniju i daje završni šah.","Dama uzima na d8 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf der Grundreihe gefangen.","Ein Damenopfer überlastet die Verteidigung, dann setzt ein Turm matt.","Dame schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped on the back rank.","A queen sacrifice overloads the defence, then a rook delivers mate.","Queen takes on f8 — the start of a forced mate."],"hr":["Crni kralj je zarobljen na posljednjoj liniji.","Žrtva dame preopterećuje obranu, a zatim top daje mat.","Dama uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König leidet an einer Schwäche auf der Grundreihe.","Ein Damenopfer zieht den deckenden Turm weg, dann setzt der schwarze Turm matt.","Dame schlägt auf f2 – Beginn eines erzwungenen Matts."],"en":["The white king suffers from a back-rank weakness.","A queen sacrifice drags the defending rook away, then the black rook mates.","Queen takes on f2 — the start of a forced mate."],"hr":["Bijeli kralj pati od slabosti na posljednjoj liniji.","Žrtva dame odvlači branećeg topa, a zatim crni top daje mat.","Dama uzima na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf der Grundreihe eingeschlossen.","Ein Damenopfer beseitigt den Verteidiger, dann setzt der Turm auf der letzten Reihe matt.","Dame schlägt auf c8 – Beginn eines erzwungenen Matts."],"en":["The black king is locked in on the back rank.","A queen sacrifice removes the defender, then the rook mates on the back rank.","Queen takes on c8 — the start of a forced mate."],"hr":["Crni kralj je zatvoren na posljednjoj liniji.","Žrtva dame uklanja branitelja, a zatim top daje mat na posljednjoj liniji.","Dama uzima na c8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird in die Ecke getrieben, wo seine Grundreihe zusammenbricht.","Ein Springerschach jagt den König in die Ecke, dann setzen die Türme auf der Grundreihe matt.","Springer nach e3 – Beginn eines erzwungenen Matts."],"en":["The white king is forced into the corner where its back rank collapses.","A knight check chases the king into the corner, then the rooks mate on the back rank.","Knight to e3 — the start of a forced mate."],"hr":["Bijeli kralj se tjera u kut gdje mu se posljednja linija ruši.","Šah skakačem tjera kralja u kut, a zatim topovi daju mat na posljednjoj liniji.","Skakač na e3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist von seinen eigenen Bauern auf der Grundreihe gefangen.","Ein Damenopfer lenkt den Springer ab, dann setzt der Turm auf der letzten Reihe matt.","Dame schlägt auf b8 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped on the back rank by its own pawns.","A queen sacrifice deflects the knight, then the rook mates on the back rank.","Queen takes on b8 — the start of a forced mate."],"hr":["Crni kralj je zarobljen na posljednjoj liniji vlastitim pješacima.","Žrtva dame odvlači skakača, a zatim top daje mat na posljednjoj liniji.","Dama uzima na b8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die hintere Reihe des weißen Königs ist tödlich verwundbar.","Mit einem Opfer lockst du eine Figur weg, dann schlägt dein Turm auf der Grundreihe zu.","Turm schlägt auf f1 – beginnt das erzwungene Matt."],"en":["The white king''s back rank is fatally exposed.","A sacrifice clears the way so your rook can crash through on the first rank.","Rook takes on f1 — starting the forced mate."],"hr":["Zadnji red bijelog kralja je smrtonosno ranjiv.","Žrtvom raščišćavaš put da tvoj top udari po prvom redu.","Top uzima na f1 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und die Grundreihe ist eine offene Wunde.","Erst lenkst du den verteidigenden Turm mit einem Damenopfer weg, dann gibt dein Turm das Matt.","Dame schlägt auf g8 – leitet das erzwungene Matt ein."],"en":["The black king is pinned to the edge and the back rank is wide open.","A queen sacrifice drags the defending rook away, then your rook delivers mate.","Queen takes on g8 — beginning the forced mate."],"hr":["Crni kralj je prikovan uz rub, a zadnji red je otvorena rana.","Žrtvom dame odvlačiš branećeg topa, a onda tvoj top daje mat.","Dama uzima na g8 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Grundreihe des weißen Königs ist der wunde Punkt.","Dein Turm dringt auf der Grundreihe ein, dann entscheidet ein Läufer.","Turm schlägt auf e1 – Beginn des erzwungenen Matts."],"en":["The white king''s back rank is the soft spot.","Your rook invades the first rank and a bishop seals the deal.","Rook takes on e1 — start of the forced mate."],"hr":["Zadnji red bijelog kralja je slaba točka.","Tvoj top prodire po prvom redu, a lovac sve zaključuje.","Top uzima na e1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht ungemütlich und seine Grundreihe ist anfällig.","Ein Damenopfer öffnet den Weg, dann schlägt dein Turm auf der Grundreihe ein.","Dame schlägt auf d2 – startet das erzwungene Matt."],"en":["The white king is uneasy and his back rank is vulnerable.","A queen sacrifice opens the lane so your rook can strike on the first rank.","Queen takes on d2 — launching the forced mate."],"hr":["Bijeli kralj stoji nelagodno, a zadnji red mu je ranjiv.","Žrtva dame otvara put da tvoj top udari po prvom redu.","Dama uzima na d2 — pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand eingesperrt und die Grundreihe ist offen.","Du opferst die Dame, um den König festzunageln, dann gibt der Turm das Matt.","Dame schlägt auf f8 – leitet das erzwungene Matt ein."],"en":["The black king is boxed in on the edge with an open back rank.","Sacrifice the queen to fix the king in place, then the rook mates.","Queen takes on f8 — beginning the forced mate."],"hr":["Crni kralj je zatvoren uz rub, a zadnji red je otvoren.","Žrtvuješ damu da fiksiraš kralja, a onda top daje mat.","Dama uzima na f8 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Grundreihe des weißen Königs ist tödlich schwach.","Ein Opfer räumt den Verteidiger weg, dann dringt dein Turm ein.","Dame schlägt auf f3 – Beginn des erzwungenen Matts."],"en":["The white king''s back rank is fatally weak.","A sacrifice removes the defender, then your rook breaks in.","Queen takes on f3 — start of the forced mate."],"hr":["Zadnji red bijelog kralja je smrtonosno slab.","Žrtva uklanja branitelja, a onda tvoj top prodire.","Dama uzima na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt am Rand fest und seine Grundreihe ist die Achillesferse.","Mit einem Damenopfer lenkst du den König ab, dann schlägt dein Turm auf der Grundreihe ein.","Dame schlägt auf f8 – leitet das erzwungene Matt ein."],"en":["The black king is stuck on the edge and the back rank is his Achilles heel.","A queen sacrifice deflects the king, then your rook strikes on the first rank.","Queen takes on f8 — beginning the forced mate."],"hr":["Crni kralj je zaglavljen uz rub, a zadnji red mu je Ahilova peta.","Žrtvom dame odvlačiš kralja, a onda tvoj top udara po prvom redu.","Dama uzima na f8 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand gefangen und die Grundreihe ist offen.","Du opferst die Dame, um den König zu fesseln, dann gibt dein Turm das Matt.","Dame schlägt auf g8 – startet das erzwungene Matt."],"en":["The black king is trapped on the edge with an open back rank.","Sacrifice the queen to tie down the king, then your rook delivers mate.","Queen takes on g8 — launching the forced mate."],"hr":["Crni kralj je zarobljen uz rub, a zadnji red je otvoren.","Žrtvuješ damu da svežeš kralja, a onda tvoj top daje mat.","Dama uzima na g8 — pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke und braucht nur einen Stoß.","Erst lenkst du den verteidigenden Turm mit einem Damenopfer ab, dann schlägt dein Turm zu.","Dame schlägt auf e5 – Beginn des erzwungenen Matts."],"en":["The black king clings to the corner and needs just one push.","First a queen sacrifice deflects the defending rook, then your rook strikes.","Queen takes on e5 — start of the forced mate."],"hr":["Crni kralj je u kutu i treba samo jedan udarac.","Prvo žrtvom dame odvlačiš branećeg topa, a onda tvoj top udara.","Dama uzima na e5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand gefangen und kann nicht entkommen.","Erst opferst du den Turm, um den König festzulegen, dann übernimmt der zweite Turm das Matt.","Turm schlägt auf g8 – leitet das erzwungene Matt ein."],"en":["The black king is caught on the edge with no way out.","First a rook sacrifice fixes the king, then the other rook takes over the mate.","Rook takes on g8 — beginning the forced mate."],"hr":["Crni kralj je zarobljen uz rub i nema izlaza.","Prvo žrtvom topa fiksiraš kralja, a onda drugi top preuzima mat.","Top uzima na g8 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt in der Ecke fest und seine Grundreihe ist verwundbar.","Mit einem Damenopfer ziehst du den Verteidiger weg, dann gibt dein Turm das Matt.","Dame schlägt auf f8 – startet das erzwungene Matt."],"en":["The black king is stuck in the corner and his back rank is vulnerable.","A queen sacrifice pulls away the defender, then your rook delivers mate.","Queen takes on f8 — launching the forced mate."],"hr":["Crni kralj je zaglavljen u kutu, a zadnji red mu je ranjiv.","Žrtvom dame odvlačiš branitelja, a onda tvoj top daje mat.","Dama uzima na f8 — pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird am Rand mattgesetzt, sobald sein Bauernschild fällt.","Ein Damenopfer reißt die Königsstellung auf, dann dringt dein Turm auf der Grundreihe ein.","Dame schlägt auf g7 – leitet das erzwungene Matt ein."],"en":["The black king is mated on the edge once his pawn shield falls.","A queen sacrifice rips open the king''s shelter, then your rook invades the back rank.","Queen takes on g7 — beginning the forced mate."],"hr":["Crni kralj biva matiran uz rub čim mu padne pješački štit.","Žrtva dame razbija kraljevo zaklon, a onda tvoj top prodire po zadnjem redu.","Dama uzima na g7 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand gefangen, Läufer und Türme weben ein Mattnetz.","Ein Damenopfer treibt den König, dann arbeiten Läufer und Turm zusammen zum Matt.","Dame schlägt auf f8 – Beginn des erzwungenen Matts."],"en":["The black king is trapped on the edge as bishops and rooks weave a mating net.","A queen sacrifice drives the king, then bishop and rook combine to mate.","Queen takes on f8 — start of the forced mate."],"hr":["Crni kralj je zarobljen uz rub dok lovci i topovi pletu matnu mrežu.","Žrtva dame goni kralja, a onda lovac i top zajedno daju mat.","Dama uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in der Ecke eingeschnürt, ein Springer hilft beim Netz.","Ein Damenopfer und ein Springermanöver sperren den König ein, dann entscheidet der Turm.","Dame schlägt auf f8 – leitet das erzwungene Matt ein."],"en":["The black king gets laced into the corner with a knight helping the net.","A queen sacrifice and a knight maneuver cage the king, then the rook decides.","Queen takes on f8 — beginning the forced mate."],"hr":["Crni kralj biva stisnut u kut uz pomoć skakača.","Žrtva dame i manevar skakača zatvaraju kralja, a onda top odlučuje.","Dama uzima na f8 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke eingesperrt und kann nicht atmen.","Deine beiden Türme arbeiten zusammen, einer fixiert, der andere setzt matt.","Turm nach b8 – Beginn des erzwungenen Matts."],"en":["The black king is shut into the corner with no air.","Your two rooks work in tandem, one fixing, the other mating.","Rook to b8 — start of the forced mate."],"hr":["Crni kralj je zatvoren u kutu i ne može disati.","Tvoja dva topa rade zajedno, jedan fiksira, drugi mati.","Top na b8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und die Grundreihe ist sein Verhängnis.","Du opferst Dame und Turm, um die Verteidigung wegzuräumen, dann setzt dein Turm matt.","Dame schlägt auf g8 – leitet das erzwungene Matt ein."],"en":["The black king clings to the edge and the back rank is his undoing.","Queen and rook sacrifices clear the defense, then your rook mates.","Queen takes on g8 — beginning the forced mate."],"hr":["Crni kralj je uz rub, a zadnji red mu je propast.","Žrtve dame i topa raščišćavaju obranu, a onda tvoj top mati.","Dama uzima na g8 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.024' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird Schritt für Schritt in die Ecke getrieben.","Mit aufeinanderfolgenden Opfern lockst du den König heraus, dann fängt ihn der Turm.","Dame schlägt auf f7 – Beginn des erzwungenen Matts."],"en":["The black king is driven step by step into the corner.","Successive sacrifices coax the king out, then the rook traps him.","Queen takes on f7 — start of the forced mate."],"hr":["Crni kralj se korak po korak tjera u kut.","Uzastopne žrtve izvlače kralja, a onda ga top hvata.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.025' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird Schritt für Schritt in die Ecke gejagt.","Deine Dame treibt den König, dann gibt sie selbst das Matt in der Ecke.","Dame nach d4 – leitet das erzwungene Matt ein."],"en":["The white king is hunted step by step into the corner.","Your queen drives the king and then delivers mate in the corner herself.","Queen to d4 — beginning the forced mate."],"hr":["Bijeli kralj se korak po korak goni u kut.","Tvoja dama tjera kralja, a onda mu sama daje mat u kutu.","Dama na d4 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.026' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand gefangen und die Grundreihe ist die Schwäche.","Ein Damenopfer entfernt den Schutz, dann dringen deine Türme auf der Grundreihe ein.","Dame schlägt auf f6 – Beginn des erzwungenen Matts."],"en":["The black king is trapped on the edge and the back rank is the weakness.","A queen sacrifice strips the cover, then your rooks crash through on the first rank.","Queen takes on f6 — start of the forced mate."],"hr":["Crni kralj je zarobljen uz rub, a zadnji red je slabost.","Žrtva dame skida zaštitu, a onda tvoji topovi probijaju po prvom redu.","Dama uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.027' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Grundreihe des weißen Königs ist tödlich verwundbar.","Du räumst die Verteidiger mit Opfern weg, dann setzt dein Turm matt.","Dame nach e3 – leitet das erzwungene Matt ein."],"en":["The white king''s back rank is fatally exposed.","Sacrifices sweep away the defenders, then your rook mates.","Queen to e3 — beginning the forced mate."],"hr":["Zadnji red bijelog kralja je smrtonosno ranjiv.","Žrtvama uklanjaš branitelje, a onda tvoj top mati.","Dama na e3 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.028' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird im Bauernschwarm an seinem König eingeschnürt.","Mit einer Reihe von Schlägen und Opfern öffnest du den König, dann setzt deine Dame matt.","Dame schlägt auf f6 – Beginn des erzwungenen Matts."],"en":["The black king gets laced in among his own pawns.","A string of captures and sacrifices pries the king open, then your queen mates.","Queen takes on f6 — start of the forced mate."],"hr":["Crni kralj biva stisnut među vlastitim pješacima.","Nizom udaraca i žrtava otvaraš kralja, a onda tvoja dama mati.","Dama uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.029' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt am Rand fest und seine Grundreihe ist offen.","Ein Damenopfer reißt das Königsfeld auf, dann übernimmt dein Turm das Matt.","Dame schlägt auf g7 – leitet das erzwungene Matt ein."],"en":["The black king is stuck on the edge with an open back rank.","A queen sacrifice tears open the king''s square, then your rook takes over the mate.","Queen takes on g7 — beginning the forced mate."],"hr":["Crni kralj je zaglavljen uz rub, a zadnji red mu je otvoren.","Žrtva dame razbija kraljevo polje, a onda tvoj top preuzima mat.","Dama uzima na g7 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.030' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Grundreihe des weißen Königs ist sein Untergang.","Ein Damenopfer lenkt den König ab, dann schlägt dein Turm auf der Grundreihe ein.","Dame schlägt auf a1 – startet das erzwungene Matt."],"en":["The white king''s back rank is his downfall.","A queen sacrifice deflects the king, then your rook strikes on the first rank.","Queen takes on a1 — launching the forced mate."],"hr":["Zadnji red bijelog kralja je njegova propast.","Žrtva dame odvlači kralja, a onda tvoj top udara po prvom redu.","Dama uzima na a1 — pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.031' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Grundreihe des weißen Königs ist tödlich schwach.","Mit Opfer und Springergabel räumst du den Verteidiger weg, dann dringt dein Turm ein.","Dame schlägt auf f1 – Beginn des erzwungenen Matts."],"en":["The white king''s back rank is fatally weak.","A sacrifice and a knight fork clear the defender, then your rook invades.","Queen takes on f1 — start of the forced mate."],"hr":["Zadnji red bijelog kralja je smrtonosno slab.","Žrtvom i skakačevom viljuškom uklanjaš branitelja, a onda tvoj top prodire.","Dama uzima na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.032' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand gefangen und die Grundreihe ist offen.","Ein Damenopfer lenkt den Verteidiger ab, dann setzt dein Turm matt.","Dame schlägt auf f7 – leitet das erzwungene Matt ein."],"en":["The black king is trapped on the edge with an open back rank.","A queen sacrifice deflects the defender, then your rook mates.","Queen takes on f7 — beginning the forced mate."],"hr":["Crni kralj je zarobljen uz rub, a zadnji red je otvoren.","Žrtva dame odvlači branitelja, a onda tvoj top mati.","Dama uzima na f7 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.033' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird am Rand erstickt, sobald sein Schild fällt.","Ein Damenopfer und ein Springervorstoß sperren den König ein, dann dringt dein Turm ein.","Dame schlägt auf g7 – Beginn des erzwungenen Matts."],"en":["The black king is smothered on the edge once his shield falls.","A queen sacrifice and a knight thrust cage the king, then your rook invades.","Queen takes on g7 — start of the forced mate."],"hr":["Crni kralj biva ugušen uz rub čim mu padne štit.","Žrtva dame i prodor skakača zatvaraju kralja, a onda tvoj top prodire.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.034' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt in der Ecke fest und kann nicht entkommen.","Du opferst die Dame und schaltest mit dem Läufer den Verteidiger aus, dann gibt dein Turm das Matt.","Dame schlägt auf f8 – leitet das erzwungene Matt ein."],"en":["The black king is stuck in the corner with no escape.","Sacrifice the queen and use the bishop to take out the defender, then your rook mates.","Queen takes on f8 — beginning the forced mate."],"hr":["Crni kralj je zaglavljen u kutu i nema bijega.","Žrtvuješ damu i lovcem isključiš branitelja, a onda tvoj top daje mat.","Dama uzima na f8 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.035' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird in die Ecke gedrängt und seine Grundreihe versagt.","Mit Opfern lockst du den König und räumst auf, dann setzt dein Turm matt.","Dame schlägt auf f4 – Beginn des erzwungenen Matts."],"en":["The white king is squeezed into the corner and his back rank gives way.","Sacrifices lure the king and clear the path, then your rook mates.","Queen takes on f4 — start of the forced mate."],"hr":["Bijeli kralj se stišće u kut, a zadnji red mu popušta.","Žrtvama mamiš kralja i čistiš put, a onda tvoj top mati.","Dama uzima na f4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.036' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand gefangen und die Grundreihe ist die Schwäche.","Erst lenkst du mit Läufer und Opfern die Verteidigung ab, dann dringt dein Turm ein.","Läufer schlägt auf d5 – leitet das erzwungene Matt ein."],"en":["The black king is trapped on the edge and the back rank is the weakness.","First bishop and sacrifices deflect the defense, then your rook breaks in.","Bishop takes on d5 — beginning the forced mate."],"hr":["Crni kralj je zarobljen uz rub, a zadnji red je slabost.","Prvo lovcem i žrtvama odvlačiš obranu, a onda tvoj top prodire.","Lovac uzima na d5 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.037' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und seine Grundreihe ist offen.","Ein Damenopfer reißt die Stellung auf, dann setzt dein Turm auf der Grundreihe matt.","Dame schlägt auf f7 – leitet das erzwungene Matt ein."],"en":["The black king clings to the edge with an open back rank.","A queen sacrifice tears the position open, then your rook mates on the first rank.","Queen takes on f7 — beginning the forced mate."],"hr":["Crni kralj je uz rub, a zadnji red mu je otvoren.","Žrtva dame razbija poziciju, a onda tvoj top mati po prvom redu.","Dama uzima na f7 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.038' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und seine Deckung lässt sich wegräumen.","Opfere zuerst, um die Verteidiger zu beseitigen, dann gibt ein Turm das Matt.","Läufer schlägt auf e6 – Beginn eines erzwungenen Matts."],"en":["The black king is pinned to the edge and his cover can be stripped away.","Sacrifice first to remove the defenders, then a rook delivers mate.","Bishop takes on e6 — the start of a forced mate."],"hr":["Crni kralj je prikovan uz rub, a njegov zaklon može se ukloniti.","Najprije žrtvuj da ukloniš branitelje, a zatim top daje mat.","Lovac uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.039' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der eingeengte König an der Kante ist anfällig für ein Schwerfiguren-Matt.","Lenke den Verteidiger mit einem Damenopfer ab, dann setzt ein Turm matt.","Dame nach b8 – Auftakt zu erzwungenem Matt."],"en":["The boxed-in king on the edge is vulnerable to a heavy-piece mate.","Deflect the defender with a queen sacrifice, then a rook mates.","Queen to b8 — the start of a forced mate."],"hr":["Stiješnjeni kralj uz rub ranjiv je na mat teškim figurama.","Odvuci branitelja žrtvom dame, a zatim top daje mat.","Dama na b8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.040' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der gegnerische König ist an der Kante eingesperrt und die Bauernkette schirmt ihn nicht.","Treibe den König mit Turmschach in die Enge und dann setzt ein Turm matt.","Turm schlägt auf h4 – Beginn eines erzwungenen Matts."],"en":["The enemy king is shut in on the edge and his pawns give him no shelter.","Drive the king with a rook check, then a rook finishes with mate.","Rook takes on h4 — the start of a forced mate."],"hr":["Protivnički kralj zatvoren je uz rub i pješaci ga ne štite.","Potjeraj kralja topovskim šahom, a zatim top daje mat.","Top uzima na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.041' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand kann den Vorstoß deiner Figuren auf der Grundreihe nicht abwehren.","Räume mit einem Turmopfer die Linie frei, dann setzt der Läufer matt.","Turm schlägt auf c8 – Auftakt zu erzwungenem Matt."],"en":["The king on the edge cannot cope with your pieces crashing through the back.","Clear the file with a rook sacrifice, then a bishop delivers mate.","Rook takes on c8 — the start of a forced mate."],"hr":["Kralj uz rub ne može zaustaviti prodor tvojih figura po zadnjoj liniji.","Otvori liniju žrtvom topa, a zatim lovac daje mat.","Top uzima na c8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.042' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König in der Ecke ist von eigenen Figuren erstickt und kaum zu verteidigen.","Eine zentrale Dame und der Turm an der Grundreihe weben das Mattnetz.","Dame nach d5 – Beginn eines erzwungenen Matts."],"en":["The king in the corner is hemmed in by his own pieces and hard to defend.","A centralizing queen and the back-rank rook weave the mating net.","Queen to d5 — the start of a forced mate."],"hr":["Kralj u kutu sputan je vlastitim figurama i teško ga je braniti.","Centralizirana dama i top na zadnjoj liniji pletu matnu mrežu.","Dama na d5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.043' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist hinter der Bauernreihe gefangen, die Grundreihe ist die Achillesferse.","Opfere, um den Verteidiger wegzulocken, dann setzt eine Figur an der Grundreihe matt.","Dame schlägt auf h2 – Auftakt zu erzwungenem Matt."],"en":["The white king is trapped behind his pawns and the back rank is his weakness.","Sacrifice to lure away the defender, then mate on the back rank.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj zarobljen je iza svojih pješaka, a zadnja linija je slabost.","Žrtvuj da odvučeš branitelja, a zatim mat na zadnjoj liniji.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.044' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke und seine Deckung ist überlastet.","Schlage den verteidigenden Turm und liefere dann ein Schwerfiguren-Matt.","Turm schlägt auf a8 – Beginn eines erzwungenen Matts."],"en":["The black king clings to the corner and his defence is overloaded.","Take the defending rook, then finish with a heavy-piece mate.","Rook takes on a8 — the start of a forced mate."],"hr":["Crni kralj se drži u kutu, a njegova obrana je preopterećena.","Uzmi branećeg topa, a zatim završi matom teškom figurom.","Top uzima na a8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.045' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König in der Ecke wird von der überlasteten Verteidigung im Stich gelassen.","Opfere die Dame zur Ablenkung, dann setzen die Türme an der Grundreihe matt.","Dame schlägt auf d5 – Auftakt zu erzwungenem Matt."],"en":["The king in the corner is let down by his overworked defence.","Sacrifice the queen to deflect, then the rooks mate on the back rank.","Queen takes on d5 — the start of a forced mate."],"hr":["Kralja u kutu izdaje preopterećena obrana.","Žrtvuj damu radi odvlačenja, a zatim topovi daju mat na zadnjoj liniji.","Dama uzima na d5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.046' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwache Grundreihe und der bloßgelegte König am Rand sind der Schlüssel.","Reiße mit einem Damenopfer die Bauerndeckung auf, dann setzen Turm und Läufer matt.","Dame schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["The weak back rank and the exposed king on the edge are the key.","Rip open the pawn cover with a queen sacrifice, then rook and bishop mate.","Queen takes on f7 — the start of a forced mate."],"hr":["Slaba zadnja linija i otvoreni kralj uz rub su ključ.","Razbij pješački zaklon žrtvom dame, a zatim top i lovac daju mat.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.047' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke eingeklemmt und kann nicht entkommen.","Opfere die Dame, dann übernehmen Läufer und Turm das Matt.","Dame schlägt auf c8 – Auftakt zu erzwungenem Matt."],"en":["The black king is jammed in the corner with no way out.","Sacrifice the queen, then a bishop and rook carry out the mate.","Queen takes on c8 — the start of a forced mate."],"hr":["Crni kralj zaglavljen je u kutu i nema izlaza.","Žrtvuj damu, a zatim lovac i top izvode mat.","Dama uzima na c8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.048' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird von einem koordinierten Figurensturm überwältigt.","Opfere zuerst die Türme, dann setzt die Dame mit Läuferhilfe matt.","Turm schlägt auf g8 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge is overwhelmed by a coordinated assault.","Sacrifice the rooks first, then the queen mates with the bishop''s help.","Rook takes on g8 — the start of a forced mate."],"hr":["Crnog kralja uz rub svladava usklađeni napad figura.","Najprije žrtvuj topove, a zatim dama daje mat uz pomoć lovca.","Top uzima na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.049' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird in die Ecke getrieben und seine Grundreihe bricht zusammen.","Opfere, um die Verteidiger zu beseitigen, dann setzt ein Turm an der Grundreihe matt.","Dame schlägt auf f1 – Auftakt zu erzwungenem Matt."],"en":["The white king is driven into the corner and his back rank collapses.","Sacrifice to remove the defenders, then a rook mates on the back rank.","Queen takes on f1 — the start of a forced mate."],"hr":["Bijeli kralj je potjeran u kut, a zadnja linija mu se ruši.","Žrtvuj da ukloniš branitelje, a zatim top daje mat na zadnjoj liniji.","Dama uzima na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.050' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König versteckt sich am Rand, doch seine Bauerndeckung zerfällt.","Opfere die Dame, dann setzen die Türme mit Hilfe des Freibauern matt.","Dame schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["The black king hides on the edge, but his pawn cover falls apart.","Sacrifice the queen, then the rooks mate with the advanced pawn''s help.","Queen takes on f7 — the start of a forced mate."],"hr":["Crni kralj skriva se uz rub, ali pješački mu se zaklon raspada.","Žrtvuj damu, a zatim topovi daju mat uz pomoć naprednog pješaka.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.051' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand kann das Eindringen auf der Grundreihe nicht aufhalten.","Opfere die Dame zur Ablenkung, dann setzen Turm und Läufer matt.","Dame schlägt auf e8 – Auftakt zu erzwungenem Matt."],"en":["The black king on the edge can''t stop the invasion of the back rank.","Sacrifice the queen to deflect, then rook and bishop deliver mate.","Queen takes on e8 — the start of a forced mate."],"hr":["Crni kralj uz rub ne može zaustaviti prodor po zadnjoj liniji.","Žrtvuj damu radi odvlačenja, a zatim top i lovac daju mat.","Dama uzima na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.052' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke ist von eigenen Figuren erstickt.","Opfere Turm und Dame, um die Deckung zu zertrümmern, dann setzt der zweite Turm matt.","Turm schlägt auf g8 – Beginn eines erzwungenen Matts."],"en":["The black king in the corner is smothered by his own pieces.","Sacrifice rook and queen to smash the cover, then the other rook mates.","Rook takes on g8 — the start of a forced mate."],"hr":["Crni kralj u kutu ugušen je vlastitim figurama.","Žrtvuj top i damu da razbiješ zaklon, a zatim drugi top daje mat.","Top uzima na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.053' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König am Rand ist gegen ein Matt auf der freigelegten Linie wehrlos.","Opfere zur Beseitigung der Verteidiger, dann setzt ein Turm an der Grundreihe matt.","Turm schlägt auf g3 – Auftakt zu erzwungenem Matt."],"en":["The white king on the edge is defenceless against mate down the open line.","Sacrifice to remove the defenders, then a rook mates on the back rank.","Rook takes on g3 — the start of a forced mate."],"hr":["Bijeli kralj uz rub bespomoćan je protiv mata po otvorenoj liniji.","Žrtvuj da ukloniš branitelje, a zatim top daje mat na zadnjoj liniji.","Top uzima na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.054' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird in die Ecke gezwungen und seine Grundreihe ist tödlich schwach.","Locke mit Opfern die Verteidiger weg, dann setzt der Turm an der Grundreihe matt.","Dame nach d4 – Beginn eines erzwungenen Matts."],"en":["The white king is forced into the corner and his back rank is fatally weak.","Lure the defenders away with sacrifices, then the rook mates on the back rank.","Queen to d4 — the start of a forced mate."],"hr":["Bijeli kralj prisiljen je u kut, a zadnja linija mu je kobno slaba.","Odvuci branitelje žrtvama, a zatim top daje mat na zadnjoj liniji.","Dama na d4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.055' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch ein langes Figurenfeuer mattgesetzt.","Beginne mit einem Springeropfer, dann übernehmen Türme und Läufer das Matt.","Springer schlägt auf e6 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge is mated by a long barrage of pieces.","Open with a knight sacrifice, then rooks and bishop carry out the mate.","Knight takes on e6 — the start of a forced mate."],"hr":["Crni kralj uz rub matiran je dugim nizom udaraca figura.","Otvori skakačkom žrtvom, a zatim topovi i lovac izvode mat.","Skakač uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.056' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch geöffnete Linien zum eigenen Bauern bloßgestellt.","Opfere, um Linie und Diagonale zu öffnen, dann setzen Läufer und Turm matt.","Turm schlägt auf b7 – Auftakt zu erzwungenem Matt."],"en":["The black king is laid bare as lines toward his own pawns are opened.","Sacrifice to open the line and diagonal, then bishop and rook mate.","Rook takes on b7 — the start of a forced mate."],"hr":["Crni kralj ostaje otkriven dok se otvaraju linije prema vlastitim pješacima.","Žrtvuj da otvoriš liniju i dijagonalu, a zatim lovac i top daju mat.","Top uzima na b7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.057' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird an die Kante getrieben, wo die Türme ein Netz spinnen.","Opfere einen Turm zum Anlocken, dann setzt der andere Turm an der Kante matt.","Turm schlägt auf h3 – Beginn eines erzwungenen Matts."],"en":["The white king is driven to the edge, where the rooks spin a net.","Sacrifice one rook to lure him out, then the other rook mates on the edge.","Rook takes on h3 — the start of a forced mate."],"hr":["Bijeli kralj je potjeran uz rub, gdje topovi pletu mrežu.","Žrtvuj jedan top da ga izvučeš, a zatim drugi top daje mat uz rub.","Top uzima na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in die Ecke getrieben, während deine beiden Läufer das Mattnetz weben.","Ein Läuferschach treibt den König weiter; Turm und zweiter Läufer nehmen ihm jedes Feld.","Läufer nach g7 – erzwingt das Matt."],"en":["The black king is driven into the corner while your two bishops weave the mating net.","A bishop check forces the king along; the rook and the second bishop strip away every square.","Bishop to g7 — forcing mate."],"hr":["Crni kralj je natjeran u kut dok tvoja dva lovca pletu matnu mrežu.","Šah lovcem tjera kralja dalje; top i drugi lovac oduzimaju mu svako polje.","Lovac na g7 — prisiljava mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Im Endspiel ist der schwarze König am Rand gegen die Läufer hilflos.","Lenke zuerst den Verteidiger ab, dann setzt ein Läufer mit dem Kollegen matt.","Läufer nach g7 – Beginn eines erzwungenen Matts."],"en":["In the endgame the black king on the edge is helpless against the bishops.","Deflect the defender first, then one bishop mates alongside its partner.","Bishop to g7 — the start of a forced mate."],"hr":["U završnici je crni kralj uz rub bespomoćan protiv lovaca.","Najprije odvuci branitelja, a zatim jedan lovac daje mat uz svog para.","Lovac na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Im Endspiel ist der schwarze König am Rand gefangen und der Bauer erledigt den Rest.","Ein einziger Königszug stellt die fatale Zugzwang-Stellung her.","König nach g4 – Beginn eines erzwungenen Matts."],"en":["In the endgame the black king is trapped on the edge and a pawn does the rest.","A single king move sets up the fatal zugzwang position.","King to g4 — the start of a forced mate."],"hr":["U završnici je crni kralj zarobljen uz rub, a pješak obavlja ostalo.","Jedan potez kraljem stvara koban položaj cugcvanga.","Kralj na g4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König in der Mitte wird von den schwarzen Figuren eingekreist.","Treibe den König mit einem Läuferschach in die Enge, dann setzt der Springer matt.","Läufer schlägt auf d2 – Beginn eines erzwungenen Matts."],"en":["The white king in the centre is hunted down by the black pieces.","Corner the king with a bishop check, then the knight delivers mate.","Bishop takes on d2 — the start of a forced mate."],"hr":["Bijelog kralja u sredini opkoljavaju crne figure.","Stjeraj kralja lovčevim šahom, a zatim skakač daje mat.","Lovac uzima na d2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Im Endspiel sitzt der weiße König in der Ecke fest und kann nicht entkommen.","Opfere einen Springer, um den König festzunageln, dann setzt der andere Springer matt.","Springer schlägt auf f2 – Beginn eines erzwungenen Matts."],"en":["In the endgame the white king is stuck in the corner with no escape.","Sacrifice a knight to pin the king down, then the other knight mates.","Knight takes on f2 — the start of a forced mate."],"hr":["U završnici je bijeli kralj zaglavljen u kutu i nema bijega.","Žrtvuj jednog skakača da prikuješ kralja, a zatim drugi skakač daje mat.","Skakač uzima na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Im Endspiel wird der weiße König am Rand von Turm und Springer eingefangen.","Treibe den König zuerst mit einem Königszug, dann setzt der Springer matt.","König nach h5 – Beginn eines erzwungenen Matts."],"en":["In the endgame the white king on the edge is netted by rook and knight.","Push the king with a king move first, then the knight delivers mate.","King to h5 — the start of a forced mate."],"hr":["U završnici bijelog kralja uz rub hvataju top i skakač.","Najprije potjeraj kralja potezom kralja, a zatim skakač daje mat.","Kralj na h5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Im Endspiel ist der schwarze König gefangen und ein Tempo entscheidet alles.","Ein stiller Bauernzug setzt den König in Zugzwang, dann gibt der Turm das Matt.","Bauer nach f3 – Beginn eines erzwungenen Matts."],"en":["In the endgame the black king is trapped and a single tempo decides.","A quiet pawn move puts the king in zugzwang, then the rook gives mate.","Pawn to f3 — the start of a forced mate."],"hr":["U završnici je crni kralj zarobljen, a jedan tempo odlučuje.","Tihi potez pješakom stavlja kralja u cugcvang, a zatim top daje mat.","Pješak na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird von den weißen Schwerfiguren überrannt.","Bringe einen Turm mit Schach ins Spiel, dann setzt der andere Turm matt.","Turm nach g3 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge is overrun by the white heavy pieces.","Bring a rook in with check, then the other rook delivers mate.","Rook to g3 — the start of a forced mate."],"hr":["Crnog kralja uz rub pregaze bijele teške figure.","Uvedi jedan top sa šahom, a zatim drugi top daje mat.","Top na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Im Endspiel wird der weiße König durch Dame und Läufer ins Mattnetz gezwungen.","Schiebe den König mit einem Damenschach an die Kante, dann setzt der Läufer matt.","Dame nach g5 – Beginn eines erzwungenen Matts."],"en":["In the endgame the white king is forced into a net by queen and bishop.","Push the king to the edge with a queen check, then the bishop mates.","Queen to g5 — the start of a forced mate."],"hr":["U završnici dama i lovac tjeraju bijelog kralja u matnu mrežu.","Potjeraj kralja uz rub daminim šahom, a zatim lovac daje mat.","Dama na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Im Endspiel ist der schwarze König in der Ecke von den Läufern eingesperrt.","Bringe den Turm mit Schach in Stellung, dann setzt er mit den Läufern matt.","Turm nach c8 – Beginn eines erzwungenen Matts."],"en":["In the endgame the black king in the corner is boxed in by the bishops.","Bring the rook in with check, then it mates supported by the bishops.","Rook to c8 — the start of a forced mate."],"hr":["U završnici je crni kralj u kutu zatvoren lovcima.","Uvedi top sa šahom, a zatim on daje mat uz potporu lovaca.","Top na c8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an den Rand gedrängt und hat kaum Luft.","Deine Türme treiben den König ins offene Feld, dann setzt der Bauer den Schlusspunkt.","Turm nach h5 – Beginn eines erzwungenen Matts."],"en":["The black king is pushed to the edge with barely any air.","Your rooks drive the king into the open, then a pawn finishes the job.","Rook to h5 — the start of a forced mate."],"hr":["Crni kralj je potisnut na rub i jedva diše.","Tvoji topovi tjeraju kralja na otvoreno, a pješak zadaje završni udarac.","Top na h5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Grundreihe des Gegners ist tödlich schwach.","Ein Turmopfer öffnet den Weg, dann erledigt der Läufer alles.","Turm nach e1 – Beginn eines erzwungenen Matts."],"en":["The opponent''s back rank is fatally weak.","A rook sacrifice clears the path, then the bishop finishes.","Rook to e1 — the start of a forced mate."],"hr":["Protivnička posljednja linija je smrtonosno slaba.","Žrtva topa otvara put, a zatim lovac sve dovršava.","Top na e1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
