UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke ist matt-reif.","Ein Springer zieht heran, dann erzwingt der Turm das Matt.","Springer nach f5 – Beginn eines erzwungenen Matts."],"en":["The black king in the corner is ripe for mate.","A knight comes in, then a rook forces the mate.","Knight to f5 — the start of a forced mate."],"hr":["Crni kralj u kutu je zreo za mat.","Skakač pristiže, a zatim top prisiljava mat.","Skakač na f5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.035' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist im offenen Feld ungeschützt.","Ein Damenschach treibt den König, dann setzt die Dame matt.","Dame schlägt auf g6 – Beginn eines erzwungenen Matts."],"en":["The black king is unguarded out in the open.","A queen check drives the king, then the queen mates.","Queen takes on g6 — the start of a forced mate."],"hr":["Crni kralj je nezaštićen na otvorenom.","Šah damom tjera kralja, a zatim dama matira.","Dama uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.036' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird durch Bauern und Figuren festgenagelt.","Ein Bauer rückt vor und drängt den König, dann setzt der Springer matt.","Bauer nach f2 – Beginn eines erzwungenen Matts."],"en":["The white king is pinned down by pawns and pieces.","A pawn pushes forward to press the king, then a knight mates.","Pawn to f2 — the start of a forced mate."],"hr":["Bijeli kralj je prikovan pješacima i figurama.","Pješak napreduje i pritišće kralja, a zatim skakač matira.","Pješak na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.037' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird von der Dame eingekreist, eine Umwandlung droht.","Trotz neuer gegnerischer Dame setzt deine Dame das Matt durch.","König nach e2 – Beginn eines erzwungenen Matts."],"en":["The white king is netted by the queen, with a promotion looming.","Even after the opponent promotes, your queen forces the mate.","King to e2 — the start of a forced mate."],"hr":["Bijeli kralj je opkoljen damom, a prijeti pretvorba.","Čak i nakon protivničke pretvorbe, tvoja dama prisiljava mat.","Kralj na e2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.038' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird von Bauern eingeschnürt.","Ein Turmopfer treibt den König, dann walzen die Bauern zum Matt.","Turm nach g8 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge is fenced in by pawns.","A rook sacrifice drives the king, then pawns roll in for mate.","Rook to g8 — the start of a forced mate."],"hr":["Crni kralj na rubu je ograđen pješacima.","Žrtva topa tjera kralja, a zatim pješaci nadiru u mat.","Top na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.039' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand hat fast keine Felder mehr.","Ein Turmopfer öffnet alles, dann gibt der Bauer das Mattschach.","Turm schlägt auf h4 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge has almost no squares left.","A rook sacrifice opens everything, then a pawn gives mate.","Rook takes on h4 — the start of a forced mate."],"hr":["Crni kralj na rubu jedva da ima polja.","Žrtva topa sve otvara, a zatim pješak daje mat.","Top uzima na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.040' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird von Dame und Springer eingefangen.","Ein Damenschach jagt den König, dann setzt die Dame matt.","Dame schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped by the queen and knight.","A queen check chases the king, then the queen mates.","Queen takes on f8 — the start of a forced mate."],"hr":["Crni kralj je uhvaćen damom i skakačem.","Šah damom goni kralja, a zatim dama matira.","Dama uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.041' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König im offenen Feld ist schutzlos.","Ein Damenschach lenkt eine Figur ab, dann mattet die Dame.","Dame schlägt auf e6 – Beginn eines erzwungenen Matts."],"en":["The black king out in the open is defenceless.","A queen check deflects a piece, then the queen mates.","Queen takes on e6 — the start of a forced mate."],"hr":["Crni kralj na otvorenom je bespomoćan.","Šah damom odvlači figuru, a zatim dama matira.","Dama uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.042' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Im Bauernendspiel läuft ein Freibauer unaufhaltsam durch.","Dein König schirmt den Bauern, der zur neuen Dame wird und mattet.","König nach f3 – Beginn eines erzwungenen Matts."],"en":["In the pawn endgame a passed pawn runs through unstoppably.","Your king shepherds the pawn, which promotes and mates.","King to f3 — the start of a forced mate."],"hr":["U pješačkoj završnici slobodnjak nezaustavljivo prolazi.","Tvoj kralj štiti pješaka koji se pretvara i matira.","Kralj na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.043' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an den Rand gedrängt, und ein zentralisierter Springer würde alles ändern.","Dein König selbst schafft die Mattfalle, indem er dem Springer Deckung gibt.","König nach d6 – matt."],"en":["The black king is pushed to the edge and a well-placed minor piece would change everything.","Your own king steps up to support the mating net.","King to d6 — mate."],"hr":["Crni kralj je potisnut na rub, a dobro postavljena figura mijenja sve.","Tvoj vlastiti kralj se uključuje da podrži matnu mrežu.","Kralj na d6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.044' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke und ist von der eigenen Bauernmasse eingeengt.","Springer und Bauern weben zusammen das Mattnetz um den eingesperrten König.","Springer nach b5 leitet das erzwungene Matt ein."],"en":["The black king is jammed into the corner, boxed in by its own pawns.","A knight and pawns combine to seal the net around the trapped king.","Knight to b5 starts the forced mate."],"hr":["Crni kralj je stisnut u kut, zatvoren vlastitim pješacima.","Skakač i pješaci zajedno zatvaraju mrežu oko zarobljenog kralja.","Skakač na b5 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.045' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König steht im Zentrum frei, doch deine Bauern schneiden ihm die Fluchtfelder ab.","Ein Turm jagt den König, während die Bauernkette ihn festhält.","Turm nach d6 beginnt das erzwungene Matt."],"en":["The king is exposed in the centre while your pawns cut off its escape.","A rook hunts the king as the pawn chain pins it down.","Rook to d6 begins the forced mate."],"hr":["Kralj je izložen u središtu dok mu tvoji pješaci sijeku polja za bijeg.","Top lovi kralja dok ga pješački lanac drži na mjestu.","Top na d6 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.046' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an seinem eigenen Flügel eingeklemmt und schlecht beschützt.","Turm und Läufer bündeln ihre Kraft auf den entblößten König.","Turm nach b8 startet das erzwungene Matt."],"en":["The black king is hemmed in on its own wing and poorly guarded.","A rook and bishop pool their force against the exposed king.","Rook to b8 launches the forced mate."],"hr":["Crni kralj je sabijen na vlastitom krilu i slabo čuvan.","Top i lovac udružuju snagu protiv izloženog kralja.","Top na b8 pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.047' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der eingeengte König wird durch einen Freibauern an der Umwandlung und einen aktiven Läufer gefesselt.","Ein Läufer öffnet die Linie, danach gibt der Turm das tödliche Schach.","Läufer nach d5 leitet das erzwungene Matt ein."],"en":["The cramped king is tied down by a passed pawn and an active bishop.","A bishop clears the way, then a rook delivers the killing check.","Bishop to d5 starts the forced mate."],"hr":["Stiješnjeni kralj je vezan prolaznim pješakom i aktivnim lovcem.","Lovac otvara liniju, a zatim top daje smrtonosni šah.","Lovac na d5 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.048' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in eine Zwangslage gelockt, in der jeder Zug ihn ins Verderben führt.","Ein Läufer und ein vorrückender Bauer treiben den König ins Matt.","Läufer nach g5 leitet das erzwungene Matt ein."],"en":["The black king is lured into a bind where every move walks into disaster.","A bishop and an advancing pawn drive the king to its end.","Bishop to g5 begins the forced mate."],"hr":["Crni kralj je namamljen u stisku gdje ga svaki potez vodi u propast.","Lovac i napredujući pješak tjeraju kralja u mat.","Lovac na g5 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.049' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf engem Raum gefangen, sobald die Verteidigerin verschwindet.","Ein Bauernopfer zieht die Dame ab, dann schlägt die eigene Dame quer übers Brett zu.","Bauer nach f4 leitet das erzwungene Matt ein."],"en":["The black king is trapped in a small box once its defender is gone.","A pawn sacrifice deflects the queen, then your own queen strikes across the board.","Pawn to f4 begins the forced mate."],"hr":["Crni kralj je zarobljen u malom prostoru čim mu nestane branitelj.","Žrtva pješaka odvlači damu, a zatim tvoja dama udara preko ploče.","Pješak na f4 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.050' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist auf der Flucht und findet kein sicheres Feld.","Ein Läufer eröffnet die Jagd, dann setzt der Turm dem König nach.","Läufer schlägt auf c2 und beginnt das erzwungene Matt."],"en":["The white king is on the run with no safe square to be found.","A bishop opens the hunt, then a rook chases the king down.","Bishop takes on c2 to begin the forced mate."],"hr":["Bijeli kralj je u bijegu i nema sigurnog polja.","Lovac otvara lov, a zatim top progoni kralja.","Lovac uzima na c2 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.051' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an den Rand getrieben und kann der Dame nicht entkommen.","Die Dame allein jagt den König über das offene Brett ins Matt.","Dame nach h8 leitet das erzwungene Matt ein."],"en":["The black king is forced to the edge and cannot escape the queen.","The queen alone hunts the king across the open board to mate.","Queen to h8 begins the forced mate."],"hr":["Crni kralj je potjeran na rub i ne može pobjeći dami.","Sama dama lovi kralja preko otvorene ploče do mata.","Dama na h8 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.052' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist an den Rand gedrängt und in eine Mattfalle gelockt.","Ein Läufer schließt das Netz, dann liefert der Turm das Schach.","Läufer nach f7 leitet das erzwungene Matt ein."],"en":["The white king is driven to the edge and lured into a mating net.","A bishop closes the net, then a rook supplies the check.","Bishop to f7 begins the forced mate."],"hr":["Bijeli kralj je potisnut na rub i namamljen u matnu mrežu.","Lovac zatvara mrežu, a zatim top daje šah.","Lovac na f7 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.053' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird an den Rand getrieben, wo sein letztes Feld zur Falle wird.","Ein Läufer schneidet das entscheidende Feld ab und vollendet das Netz.","Läufer nach f2 leitet das erzwungene Matt ein."],"en":["The white king is driven to the edge where its last square becomes a trap.","A bishop cuts off the key square and completes the net.","Bishop to f2 begins the forced mate."],"hr":["Bijeli kralj je potjeran na rub gdje mu posljednje polje postaje zamka.","Lovac siječe ključno polje i zatvara mrežu.","Lovac na f2 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.054' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist eingeklemmt, seine eigenen Bauern und Figuren versperren die Flucht.","Ein Turm rückt vor und ein Bauer riegelt das letzte Schlupfloch zu.","Turm nach e6 leitet das erzwungene Matt ein."],"en":["The black king is boxed in, its own pawns and pieces blocking escape.","A rook advances and a pawn seals the final escape route.","Rook to e6 begins the forced mate."],"hr":["Crni kralj je zatvoren, vlastiti pješaci i figure blokiraju bijeg.","Top napreduje, a pješak zatvara posljednji izlaz.","Top na e6 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.055' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt am Rand, eingezwängt von seinen eigenen Bauern.","Zwei Türme weben gemeinsam das Mattnetz um den festsitzenden König.","Turm nach e2 leitet das erzwungene Matt ein."],"en":["The white king clings to the edge, hemmed in by its own pawns.","Two rooks weave the net together around the stuck king.","Rook to e2 begins the forced mate."],"hr":["Bijeli kralj se drži ruba, sabijen vlastitim pješacima.","Dva topa zajedno pletu mrežu oko zaglavljenog kralja.","Top na e2 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.056' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König im Zentrum wird in ein enges Korsett gezwängt.","Ein Turm und ein Läufer treiben den König, ein Bauer setzt den Schlusspunkt.","Turm nach f1 leitet das erzwungene Matt ein."],"en":["The white king in the centre is squeezed into a tight box.","A rook and a bishop drive the king while a pawn delivers the finish.","Rook to f1 begins the forced mate."],"hr":["Bijeli kralj u središtu je stisnut u uski okvir.","Top i lovac tjeraju kralja dok pješak postavlja završnicu.","Top na f1 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.057' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird zur Seite gelockt, wo ihn eine Gabel überrascht.","Der König wird zunächst auf ein ungünstiges Feld getrieben, dann schlägt der Springer zu.","König nach h6 leitet das erzwungene Matt ein."],"en":["The white king is coaxed to a square where a knight fork awaits.","First the king is forced to an awkward square, then the knight strikes.","King to h6 begins the forced mate."],"hr":["Bijeli kralj je namamljen na polje gdje ga čeka skakačeva vilica.","Najprije se kralj tjera na nezgodno polje, a zatim skakač udara.","Kralj na h6 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.058' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht im Zentrum frei und lässt sich Schritt für Schritt einkreisen.","Bauer, König und Turm rücken zusammen vor und schnüren das Netz zu.","Bauer nach f3 leitet das erzwungene Matt ein."],"en":["The black king stands exposed in the centre and can be squeezed step by step.","Pawn, king and rook advance together to tighten the net.","Pawn to f3 begins the forced mate."],"hr":["Crni kralj stoji izložen u središtu i može se korak po korak opkoliti.","Pješak, kralj i top zajedno napreduju i stežu mrežu.","Pješak na f3 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.059' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und ist von eigenen und gegnerischen Steinen umstellt.","Ein Läufer räumt den Weg, dann gibt ein Bauer das entscheidende Schach.","Läufer schlägt auf b5 und beginnt das erzwungene Matt."],"en":["The black king is stuck on the edge, surrounded by pieces of both colours.","A bishop clears the path, then a pawn gives the decisive check.","Bishop takes on b5 to begin the forced mate."],"hr":["Crni kralj je zaglavljen na rubu, okružen figurama obje boje.","Lovac čisti put, a zatim pješak daje odlučujući šah.","Lovac uzima na b5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.060' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird durch eigene Bauern und vorrückende Steine immer enger eingeschlossen.","Ein Turm liefert das Schach, gestützt von einem Läufer und Bauern.","Turm schlägt auf g4 und beginnt das erzwungene Matt."],"en":["The white king is squeezed ever tighter by its own pawns and advancing pieces.","A rook delivers the check, backed by a bishop and a pawn.","Rook takes on g4 to begin the forced mate."],"hr":["Bijeli kralj je sve čvršće stisnut vlastitim pješacima i napredujućim figurama.","Top daje šah, podržan lovcem i pješakom.","Top uzima na g4 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.061' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König in der Ecke hat kaum Luft, eine kleine Lockung genügt.","Der Turm gibt ein Schach, das den König ins endgültige Matt zwingt.","Turm nach e1 leitet das erzwungene Matt ein."],"en":["The white king in the corner has almost no air, and a small lure is enough.","A rook check forces the king toward the final mate.","Rook to e1 begins the forced mate."],"hr":["Bijeli kralj u kutu jedva diše, dovoljna je mala primamka.","Topov šah tjera kralja prema konačnom matu.","Top na e1 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.062' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Dame steht ungeschützt und der König wird in eine Gabel gezwungen.","Die schwarze Dame jagt den König und greift dabei die feindliche Dame mit an.","Dame nach d1 leitet das erzwungene Matt ein."],"en":["The white queen is loose and the king can be forced into a fork.","The black queen hunts the king while also targeting the enemy queen.","Queen to d1 begins the forced mate."],"hr":["Bijela dama je nezaštićena, a kralj se može natjerati u vilicu.","Crna dama lovi kralja i istovremeno cilja protivničku damu.","Dama na d1 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.063' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König im Zentrum wird Schritt für Schritt eingekreist.","Ein Bauer treibt den König, dann setzen die Türme das Matt.","Bauer nach d5 leitet das erzwungene Matt ein."],"en":["The black king in the centre can be encircled step by step.","A pawn drives the king, then the rooks finish the mate.","Pawn to d5 begins the forced mate."],"hr":["Crni kralj u središtu se može korak po korak opkoliti.","Pješak tjera kralja, a zatim topovi završavaju mat.","Pješak na d5 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.064' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird von vorrückenden Steinen eingeschnürt.","Türme und ein Bauer treiben den König, bis er kein Feld mehr hat.","Turm nach h4 leitet das erzwungene Matt ein."],"en":["The black king on the edge is hemmed in by advancing pieces.","Rooks and a pawn drive the king until it runs out of squares.","Rook to h4 begins the forced mate."],"hr":["Crni kralj na rubu je sabijen napredujućim figurama.","Topovi i pješak tjeraju kralja dok mu ne ponestane polja.","Top na h4 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.065' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist tief im schwarzen Lager gefangen und überdehnt.","Ein Läufer wird abgelenkt, dann liefert der Turm das tödliche Schach.","Läufer nach d6 leitet das erzwungene Matt ein."],"en":["The white king is trapped deep in Black''s camp and overextended.","A bishop is deflected, then a rook delivers the deadly check.","Bishop to d6 begins the forced mate."],"hr":["Bijeli kralj je zarobljen duboko u crnom taboru i prenapregnut.","Lovac se odvlači, a zatim top daje smrtonosni šah.","Lovac na d6 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.066' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand, und ein Freibauer steht kurz vor der Umwandlung.","Ein Turmopfer zieht den König heran, dann wird der Bauer zur Dame.","Turm nach h8 leitet das erzwungene Matt ein."],"en":["The black king is glued to the edge while a passed pawn nears promotion.","A rook sacrifice draws the king in, then the pawn becomes a queen.","Rook to h8 begins the forced mate."],"hr":["Crni kralj je prilijepljen za rub dok je prolazni pješak pred promocijom.","Žrtva topa privlači kralja, a zatim pješak postaje dama.","Top na h8 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.067' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt eingeklemmt zwischen eigenen und feindlichen Steinen.","Ein Springer schließt das Netz, das schon ein zweiter Springer aufgebaut hat.","Springer nach h6 leitet das erzwungene Matt ein."],"en":["The black king sits wedged between its own and enemy pieces.","A knight closes the net that a second knight has already built.","Knight to h6 begins the forced mate."],"hr":["Crni kralj je zaglavljen između vlastitih i neprijateljskih figura.","Skakač zatvara mrežu koju je drugi skakač već izgradio.","Skakač na h6 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.068' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König am Rand ist von seinen eigenen Bauern eingeengt.","Ein Turm wird abgelenkt, dann gibt ein Bauer das erstickende Schach.","Turm schlägt auf h3 und beginnt das erzwungene Matt."],"en":["The white king on the edge is cramped by its own pawns.","A rook is deflected, then a pawn delivers the suffocating check.","Rook takes on h3 to begin the forced mate."],"hr":["Bijeli kralj na rubu je stiješnjen vlastitim pješacima.","Top se odvlači, a zatim pješak daje gušeći šah.","Top uzima na h3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.069' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke fast erstickt und braucht nur noch wenig Druck.","Bauern und Springer arbeiten zusammen, um den König festzunageln.","Bauer nach a7 leitet das erzwungene Matt ein."],"en":["The black king is nearly smothered in the corner and needs only a little push.","Pawns and knights work together to pin the king down.","Pawn to a7 begins the forced mate."],"hr":["Crni kralj je gotovo ugušen u kutu i treba mu samo mali pritisak.","Pješaci i skakači surađuju kako bi prikovali kralja.","Pješak na a7 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.070' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird in ein immer engeres Netz getrieben.","Ein Läufer schneidet ab, Bauern und der eigene König engen ihn weiter ein.","Läufer nach g6 leitet das erzwungene Matt ein."],"en":["The black king on the edge is driven into an ever-tightening net.","A bishop cuts in while pawns and your king close the gap.","Bishop to g6 begins the forced mate."],"hr":["Crni kralj na rubu se tjera u sve užu mrežu.","Lovac siječe dok pješaci i tvoj kralj zatvaraju prazninu.","Lovac na g6 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.071' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird auf ein Feld gelockt, von dem es kein Entkommen gibt.","Ein Bauer öffnet die Linie, dann gibt der Läufer das stille Mattschach.","Bauer nach e5 leitet das erzwungene Matt ein."],"en":["The white king is lured to a square from which there is no escape.","A pawn opens the line, then a bishop delivers the quiet mating check.","Pawn to e5 begins the forced mate."],"hr":["Bijeli kralj je namamljen na polje s kojeg nema bijega.","Pješak otvara liniju, a zatim lovac daje tihi matni šah.","Pješak na e5 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.072' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch vorrückende Bauern und den eigenen König eingeschnürt.","Ein Bauer wird geopfert, dann setzt der Turm das Matt.","Turm nach c8 leitet das erzwungene Matt ein."],"en":["The black king on the edge is hemmed in by advancing pawns and your king.","A pawn is sacrificed, then a rook delivers the mate.","Rook to c8 begins the forced mate."],"hr":["Crni kralj na rubu je sabijen napredujućim pješacima i tvojim kraljem.","Pješak se žrtvuje, a zatim top postavlja mat.","Top na c8 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.073' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
