UPDATE BookPuzzles SET HintsJson='{"de":["Die schwache Grundreihe des weißen Königs entscheidet.","Ein Damenopfer lenkt ab, dann schlägt der Turm auf der Reihe ein.","Dame nach h1 – Beginn eines erzwungenen Matts."],"en":["The white king''s weak back rank decides matters.","A queen sacrifice deflects, then the rook strikes on the rank.","Queen to h1 — starting a forced mate."],"hr":["Slabi zadnji red bijelog kralja odlučuje.","Žrtva dame odvlači, a zatim top udara po redu.","Dama na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die lange Diagonale zum weißen König ist tödlich offen.","Ein Damenopfer beseitigt den Blocker, der Läufer setzt matt.","Dame nach b2 – Beginn eines erzwungenen Matts."],"en":["The long diagonal to the white king lies fatally open.","A queen sacrifice removes the blocker, the bishop mates.","Queen to b2 — starting a forced mate."],"hr":["Duga dijagonala prema bijelom kralju kobno je otvorena.","Žrtva dame uklanja blokatora, a lovac daje mat.","Dama na b2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke ist hinter dünner Deckung bloß.","Ein Turmopfer reißt die Stellung auf, der Läufer setzt matt.","Turm nach h6 – Beginn eines erzwungenen Matts."],"en":["The black king in the corner is bare behind thin cover.","A rook sacrifice tears it open, the bishop delivers mate.","Rook to h6 — starting a forced mate."],"hr":["Crni kralj u kutu je ogoljen iza tankog zaklona.","Žrtva topa otvara položaj, a lovac daje mat.","Top na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist auf der ersten Reihe verwundbar, und ein Verteidiger lässt sich beseitigen.","Du opferst zunächst, um eine Linie zu öffnen, dann gibt ein Läufer das tödliche Schach.","Dame schlägt auf f3 – Beginn eines erzwungenen Matts."],"en":["The white king is vulnerable on the back rank and a key defender can be removed.","Sacrifice first to open the line, then a bishop delivers the deadly check.","Queen takes on f3 — the start of a forced mate."],"hr":["Bijeli kralj je ranjiv na zadnjoj liniji, a ključni branitelj može biti uklonjen.","Najprije žrtvuj da otvoriš liniju, a zatim lovac daje smrtonosni šah.","Dama uzima na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Bauern eingemauert und kaum geschützt.","Ein Damenopfer reißt die Stellung auf, dann jagt ein Turm den König ins Matt.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is walled in behind its pawns and poorly guarded.","A queen sacrifice tears the position open, then a rook chases the king to mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj je zazidan iza svojih pješaka i slabo zaštićen.","Žrtva dame razbija položaj, a zatim top tjera kralja u mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke gedrängt, und seine erste Reihe ist schwach.","Erst lockst du den König mit einem Opfer, dann liefert ein Turm das Matt.","Dame schlägt auf h1 – Beginn eines erzwungenen Matts."],"en":["The white king is forced into the corner and its back rank is weak.","First lure the king with a sacrifice, then a rook delivers the mate.","Queen takes on h1 — the start of a forced mate."],"hr":["Bijeli kralj je stjeran u kut, a zadnja linija mu je slaba.","Najprije namami kralja žrtvom, a zatim top daje mat.","Dama uzima na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt in der Ecke und hat kein Luftloch.","Ein Opfer schaltet einen Verteidiger aus, dann setzt ein Läufer matt.","Dame schlägt auf f3 – Beginn eines erzwungenen Matts."],"en":["The white king is stuck in the corner with no luft.","A sacrifice removes a defender, then a bishop delivers mate.","Queen takes on f3 — the start of a forced mate."],"hr":["Bijeli kralj je zaglavljen u kutu bez zračne rupe.","Žrtva uklanja branitelja, a zatim lovac daje mat.","Dama uzima na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist am Rand gefangen und sein Verteidiger überlastet.","Du opferst die Dame, um abzulenken, dann macht ein Turm den Sack zu.","Dame schlägt auf a1 – Beginn eines erzwungenen Matts."],"en":["The white king is trapped on the edge and its defender is overloaded.","Sacrifice the queen to deflect, then a rook finishes the job.","Queen takes on a1 — the start of a forced mate."],"hr":["Bijeli kralj je zarobljen na rubu, a branitelj mu je preopterećen.","Žrtvuj damu da odvučeš branitelja, a zatim top dovršava posao.","Dama uzima na a1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist entblößt, und die langen Diagonalen weisen direkt auf ihn.","Nach einem Abtausch übernimmt ein Läufer die tödliche Diagonale.","Dame schlägt auf d5 – Beginn eines erzwungenen Matts."],"en":["The white king is exposed and the long diagonals point straight at it.","After an exchange a bishop seizes the deadly diagonal.","Queen takes on d5 — the start of a forced mate."],"hr":["Bijeli kralj je izložen, a duge dijagonale upiru ravno u njega.","Nakon razmjene lovac preuzima smrtonosnu dijagonalu.","Dama uzima na d5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König hat eine bröckelnde Deckung, und ein Springer steht zum Sprung bereit.","Ein Damenopfer öffnet den Weg, dann gibt ein Springer das letzte Schach.","Dame schlägt auf f3 – Beginn eines erzwungenen Matts."],"en":["The white king''s cover is crumbling and a knight is poised to leap.","A queen sacrifice opens the way, then a knight gives the final check.","Queen takes on f3 — the start of a forced mate."],"hr":["Zaklon bijelog kralja se raspada, a skakač je spreman za skok.","Žrtva dame otvara put, a zatim skakač daje posljednji šah.","Dama uzima na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König leidet unter einer schwachen Grundreihe.","Erst lenkst du einen Turm ab, dann dringt der eigene Turm ein und setzt matt.","Dame schlägt auf d8 – Beginn eines erzwungenen Matts."],"en":["The black king suffers from a weak back rank.","First deflect a rook, then your own rook breaks in to mate.","Queen takes on d8 — the start of a forced mate."],"hr":["Crni kralj pati od slabe zadnje linije.","Najprije odvuci top, a zatim tvoj top provaljuje i daje mat.","Dama uzima na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke gequetscht und seine Grundreihe ist verwundbar.","Ein Turmopfer holt den König heraus, dann setzt die Dame matt.","Turm schlägt auf h1 – Beginn eines erzwungenen Matts."],"en":["The white king is jammed in the corner and its back rank is vulnerable.","A rook sacrifice drags the king out, then the queen mates.","Rook takes on h1 — the start of a forced mate."],"hr":["Bijeli kralj je stiješnjen u kut, a zadnja linija mu je ranjiva.","Žrtva topa izvlači kralja, a zatim dama daje mat.","Top uzima na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter zerschlagenen Bauern fast ohne Schutz.","Ein Damenopfer beseitigt den letzten Verteidiger, dann arbeiten Turm und Läufer zusammen.","Dame schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king has almost no shelter behind shattered pawns.","A queen sacrifice removes the last defender, then rook and bishop combine.","Queen takes on g7 — the start of a forced mate."],"hr":["Crni kralj gotovo da nema zaklona iza razbijenih pješaka.","Žrtva dame uklanja posljednjeg branitelja, a zatim top i lovac surađuju.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke, und seine Bauern bieten kein Luftloch.","Du lenkst den König mit einem Turm ab, dann setzt die Dame an der Seite matt.","Turm schlägt auf d7 – Beginn eines erzwungenen Matts."],"en":["The black king is stuck in the corner with no luft from its pawns.","Deflect the king with a rook, then the queen mates from the side.","Rook takes on d7 — the start of a forced mate."],"hr":["Crni kralj je zaglavljen u kutu, a pješaci mu ne daju zračnu rupu.","Odvuci kralja topom, a zatim dama daje mat sa strane.","Top uzima na d7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist eingeengt, und seine Schutzbauern lassen sich aufreißen.","Ein Damenopfer öffnet die Stellung, dann liefert ein Turm das Matt.","Dame schlägt auf h6 – Beginn eines erzwungenen Matts."],"en":["The black king is cramped and its sheltering pawns can be torn away.","A queen sacrifice opens the position, then a rook delivers mate.","Queen takes on h6 — the start of a forced mate."],"hr":["Crni kralj je skučen, a pješaci koji ga štite mogu biti otrgnuti.","Žrtva dame otvara položaj, a zatim top daje mat.","Dama uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.024' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke getrieben, und seine erste Reihe ist schwach.","Nach einem Opfer übernimmt ein Turm die Grundreihe zum Matt.","Dame schlägt auf f2 – Beginn eines erzwungenen Matts."],"en":["The white king is driven into the corner and its back rank is weak.","After a sacrifice a rook takes over the back rank for mate.","Queen takes on f2 — the start of a forced mate."],"hr":["Bijeli kralj je stjeran u kut, a zadnja linija mu je slaba.","Nakon žrtve top preuzima zadnju liniju za mat.","Dama uzima na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.025' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist nackt, und seine Verteidiger lassen sich abräumen.","Ein Damenopfer leitet ein, dann setzt ein Springer den König matt.","Dame schlägt auf e8 – Beginn eines erzwungenen Matts."],"en":["The black king is bare and its defenders can be swept away.","A queen sacrifice begins it, then a knight delivers mate to the king.","Queen takes on e8 — the start of a forced mate."],"hr":["Crni kralj je razgolićen, a branitelji mu mogu biti pometeni.","Žrtva dame započinje, a zatim skakač daje mat kralju.","Dama uzima na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.026' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke gedrängt und sein Schutz fragwürdig.","Ein Damenopfer macht den Weg frei, dann hüpft ein Springer zum Erstickungsmatt.","Dame schlägt auf g2 – Beginn eines erzwungenen Matts."],"en":["The white king is pushed into the corner with shaky cover.","A queen sacrifice clears the way, then a knight hops in for a smothered mate.","Queen takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj je stjeran u kut s klimavim zaklonom.","Žrtva dame čisti put, a zatim skakač uskače za ugušeni mat.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.027' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter durchlöcherten Bauern wehrlos.","Reihenweise Opfer reißen die Königsstellung auf, dann setzt ein Turm matt.","Turm schlägt auf h8 – Beginn eines erzwungenen Matts."],"en":["The black king is defenceless behind broken-up pawns.","A cascade of sacrifices rips the king open, then a rook delivers mate.","Rook takes on h8 — the start of a forced mate."],"hr":["Crni kralj je bespomoćan iza razbijenih pješaka.","Niz žrtava razdire kraljev položaj, a zatim top daje mat.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.028' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist auf der Grundreihe verwundbar, und ein Verteidiger ist überlastet.","Erst beseitigst du einen Verteidiger durch Opfer, dann setzt ein Turm matt.","Dame schlägt auf g3 – Beginn eines erzwungenen Matts."],"en":["The white king is vulnerable on the back rank and a defender is overloaded.","First remove a defender by sacrifice, then a rook delivers mate.","Queen takes on g3 — the start of a forced mate."],"hr":["Bijeli kralj je ranjiv na zadnjoj liniji, a branitelj je preopterećen.","Najprije ukloni branitelja žrtvom, a zatim top daje mat.","Dama uzima na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.029' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter zerstörten Bauern fast schutzlos.","Ein Damenopfer öffnet die Königsstellung, dann gibt ein Läufer das letzte Schach.","Dame schlägt auf f6 – Beginn eines erzwungenen Matts."],"en":["The black king is nearly shelterless behind wrecked pawns.","A queen sacrifice opens the king''s position, then a bishop gives the final check.","Queen takes on f6 — the start of a forced mate."],"hr":["Crni kralj je gotovo bez zaklona iza razrušenih pješaka.","Žrtva dame otvara kraljev položaj, a zatim lovac daje posljednji šah.","Dama uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.030' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf seiner Reihe eingeengt, und ein Turm steht aggressiv.","Erst lenkst du die Dame ab, dann jagt ein Turm den König ins Matt.","Dame schlägt auf e6 – Beginn eines erzwungenen Matts."],"en":["The black king is hemmed in on its rank and a rook stands aggressively.","First deflect the queen, then a rook chases the king to mate.","Queen takes on e6 — the start of a forced mate."],"hr":["Crni kralj je stiješnjen na svojoj liniji, a top stoji agresivno.","Najprije odvuci damu, a zatim top tjera kralja u mat.","Dama uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.031' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt in der Ecke und ist erstickt von eigenen Figuren.","Nach einem ablenkenden Opfer setzt ein Turm den eingeengten König matt.","Turm schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king clings to the corner, smothered by its own pieces.","After a deflecting sacrifice a rook mates the boxed-in king.","Rook takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj se drži kuta, ugušen vlastitim figurama.","Nakon žrtve za odvlačenje top daje mat zatočenom kralju.","Top uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.032' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke gefangen, und die lange Diagonale ist tödlich.","Ein Turmopfer lenkt die Verteidigung ab, dann liefert ein Läufer das Matt.","Turm schlägt auf f2 – Beginn eines erzwungenen Matts."],"en":["The white king is trapped in the corner and the long diagonal is lethal.","A rook sacrifice deflects the defence, then a bishop delivers mate.","Rook takes on f2 — the start of a forced mate."],"hr":["Bijeli kralj je zarobljen u kutu, a duga dijagonala je smrtonosna.","Žrtva topa odvlači obranu, a zatim lovac daje mat.","Top uzima na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.033' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter aufgerissenen Bauern fast schutzlos.","Eine Reihe von Opfern legt den König frei, dann setzt ein Läufer matt.","Springer schlägt auf f6 – Beginn eines erzwungenen Matts."],"en":["The black king is almost shelterless behind torn-open pawns.","A series of sacrifices lays the king bare, then a bishop delivers mate.","Knight takes on f6 — the start of a forced mate."],"hr":["Crni kralj je gotovo bez zaklona iza razderanih pješaka.","Niz žrtava razgoljuje kralja, a zatim lovac daje mat.","Skakač uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.034' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an den Rand gedrängt, und ein Bauer stützt das Mattnetz.","Ein Damenopfer öffnet die Linie, dann arbeiten Turm und Läufer zum Matt zusammen.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is forced to the edge and a pawn anchors the mating net.","A queen sacrifice opens the file, then rook and bishop combine to mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj je stjeran na rub, a pješak učvršćuje matnu mrežu.","Žrtva dame otvara liniju, a zatim top i lovac surađuju za mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.035' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist eingeengt, und seine Verteidiger lassen sich abräumen.","Eine Folge von Opfern und Treibjagd zwingt den König ins Matt durch einen Turm.","Dame schlägt auf d8 – Beginn eines erzwungenen Matts."],"en":["The black king is cramped and its defenders can be cleared away.","A run of sacrifices and a king-hunt force mate by a rook.","Queen takes on d8 — the start of a forced mate."],"hr":["Crni kralj je skučen, a branitelji mu mogu biti uklonjeni.","Niz žrtava i hajka na kralja prisiljavaju mat topom.","Dama uzima na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.036' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke gedrückt und seine Grundreihe schwach.","Nach einem Damenopfer treiben Türme den König ins endgültige Matt.","Dame schlägt auf g2 – Beginn eines erzwungenen Matts."],"en":["The white king is pressed into the corner with a weak back rank.","After a queen sacrifice the rooks drive the king to a final mate.","Queen takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj je pritisnut u kut sa slabom zadnjom linijom.","Nakon žrtve dame topovi tjeraju kralja u konačni mat.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.037' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird in eine lange, erzwungene Treibjagd verwickelt.","Ein Damenopfer leitet ein, dann jagen Türme und Läufer den König bis zum Matt.","Dame schlägt auf g2 – Beginn eines erzwungenen Matts."],"en":["The white king is dragged into a long, forced king-hunt.","A queen sacrifice begins it, then rooks and bishop chase the king to mate.","Queen takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj je uvučen u dugu, prisilnu hajku.","Žrtva dame započinje, a zatim topovi i lovac tjeraju kralja u mat.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.038' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter dünnen Bauern eingeklemmt und schlecht gedeckt.","Mehrere Opfer öffnen die Linien, dann setzt ein Turm den König matt.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is wedged behind thin pawns and poorly guarded.","Several sacrifices open the lines, then a rook mates the king.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj je ukliješten iza tankih pješaka i slabo zaštićen.","Nekoliko žrtava otvara linije, a zatim top daje mat kralju.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.039' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand gefangen, und ein vorgerückter Bauer stützt das Matt.","Ein Schach zwingt den König heran, dann krönt ein neuer Bauer zur Dame das Mattnetz.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped on the edge and an advanced pawn supports the mate.","A check forces the king up, then a fresh pawn promotes to crown the mating net.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj je zarobljen na rubu, a napredovali pješak podupire mat.","Šah tjera kralja naprijed, a zatim novi pješak postaje dama i zaokružuje matnu mrežu.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke gedrängt, und ein vorgerückter Bauer winkt mit der Umwandlung.","Ein Damenopfer beseitigt den Wächter, dann krönt ein Bauer zur Dame und setzt matt.","Dame schlägt auf g2 – Beginn eines erzwungenen Matts."],"en":["The white king is pushed into the corner and an advanced pawn beckons to promote.","A queen sacrifice removes the guard, then a pawn promotes to a queen and mates.","Queen takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj je stjeran u kut, a napredovali pješak mami na promociju.","Žrtva dame uklanja čuvara, a zatim pješak postaje dama i daje mat.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke gefangen, und ein weit vorgerückter Bauer droht zu krönen.","Erst opferst du, um den Wächter wegzulocken, dann setzt eine neue Dame matt.","Dame schlägt auf b1 – Beginn eines erzwungenen Matts."],"en":["The white king is trapped in the corner and a far-advanced pawn threatens to crown.","First sacrifice to lure away the guard, then a new queen delivers mate.","Queen takes on b1 — the start of a forced mate."],"hr":["Bijeli kralj je zarobljen u kutu, a daleko napredovali pješak prijeti promocijom.","Najprije žrtvuj da odvučeš čuvara, a zatim nova dama daje mat.","Dama uzima na b1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist auf den Rand gedrängt und sein einziges Bauernschild bröckelt.","Ein Damenopfer reißt die Rochadestellung auf und ein Bauer wird zur tödlichen neuen Dame.","Dame schlägt auf h2 – Auftakt zu einem erzwungenen Matt."],"en":["The white king is pinned to the edge and its only pawn cover is about to crumble.","A queen sacrifice tears open the shelter so a pawn can promote to a deadly new queen.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj je stisnut uz rub, a jedini pješački štit samo što nije pukao.","Žrtva dame razbija zaklon, a pješak se pretvara u smrtonosnu novu damu.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke und ein Freibauer steht zum Sprung bereit.","Ein Damenopfer lenkt den König weg, dann krönt ein Bauer als neue Dame.","Dame nach h8 – Beginn eines erzwungenen Matts."],"en":["The black king is glued to the corner and a passed pawn is poised to queen.","A queen sacrifice drags the king away so a pawn can crown into a new queen.","Queen to h8 — the start of a forced mate."],"hr":["Crni kralj je prilijepljen uz kut, a prolazni pješak spreman je za pretvorbu.","Žrtva dame odvlači kralja kako bi se pješak pretvorio u novu damu.","Dama na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Beide Seiten haben Freibauern, aber nur Weiß kann mit Tempo zur Dame kommen.","Vorrücken eines Freibauern erzwingt eine neue Dame, die den eingesperrten König mattsetzt.","Bauer nach e7 – Start eines erzwungenen Matts."],"en":["Both sides race pawns, but only White can promote with check and tempo.","Pushing a passed pawn forces a new queen that mates the boxed-in king.","Pawn to e7 — the start of a forced mate."],"hr":["Obje strane jure s pješacima, ali samo bijeli stiže do pretvorbe s tempom.","Napredovanje prolaznog pješaka donosi novu damu koja matira skučenog kralja.","Pješak na e7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König sitzt in der Ecke fest und seine Verteidiger sind überlastet.","Ein Damenopfer öffnet die Tür, dann drückt ein Bauer durch und wird zur Dame.","Dame schlägt auf h2 – Auftakt zu einem erzwungenen Matt."],"en":["The white king is stuck in the corner and its defenders are overloaded.","A queen sacrifice cracks the door so a pawn can break through and promote.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj je zaglavljen u kutu, a njegovi branitelji su preopterećeni.","Žrtva dame otvara vrata kako bi pješak probio i pretvorio se u damu.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in die Ecke gedrängt und ein weit vorgerückter Bauer droht.","Ein Turmopfer und der Vormarsch des Bauern führen zu einer matttragenden Dame.","Turm schlägt auf a6 – Beginn eines erzwungenen Matts."],"en":["The black king is wedged into the corner and a far-advanced pawn looms.","A rook sacrifice and a pawn march bring about a mating new queen.","Rook takes on a6 — the start of a forced mate."],"hr":["Crni kralj je utisnut u kut, a daleko napredovali pješak prijeti.","Žrtva topa i napredovanje pješaka donose damu koja matira.","Top uzima na a6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht entblößt in der Ecke, sein Bauernschild ist angreifbar.","Ein Turmopfer reißt die Front auf, dann krönt ein Bauer mit Schwung.","Turm schlägt auf h6 – Auftakt zu einem erzwungenen Matt."],"en":["The black king sits exposed in the corner with a vulnerable pawn cover.","A rook sacrifice rips the front open before a pawn promotes with force.","Rook takes on h6 — the start of a forced mate."],"hr":["Crni kralj je izložen u kutu, a njegov pješački štit je ranjiv.","Žrtva topa razbija frontu prije nego se pješak silovito pretvori.","Top uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in die Ecke gedrängt und ein weiter Freibauer winkt.","Ein Damenopfer lockt einen Verteidiger weg, dann wandelt ein Bauer um.","Dame schlägt auf d8 – Beginn eines erzwungenen Matts."],"en":["The black king is herded toward the corner and an advanced passer beckons.","A queen sacrifice lures a defender away so a pawn can promote.","Queen takes on d8 — the start of a forced mate."],"hr":["Crni kralj je natjeran prema kutu, a napredni prolaznik mami.","Žrtva dame odvlači branitelja kako bi se pješak pretvorio.","Dama uzima na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["In einem Bauernendspiel zählt jedes Tempo – beide rennen zur Umwandlung.","Ein Bauernopfer und genaues Schachgeben erzwingen die entscheidende neue Dame.","Bauer wird auf h1 zur Dame – Start eines erzwungenen Matts."],"en":["In a pawn endgame every tempo counts as both sides race to promote.","A pawn sacrifice and precise checks force the decisive new queen.","Pawn promotes to a queen on h1 — the start of a forced mate."],"hr":["U pješačkoj završnici svaki tempo je važan dok obje strane jure pretvorbi.","Žrtva pješaka i precizni šahovi donose odlučujuću novu damu.","Pješak se pretvara u damu na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in die Ecke gedrückt und ein Bauer steht vor der Umwandlung.","Ein Damenopfer und das Krönen eines Bauern bahnen den Weg zum Matt.","Dame schlägt auf h7 – Auftakt zu einem erzwungenen Matt."],"en":["The black king is pressed into the corner with a pawn one step from queening.","A queen sacrifice and a pawn''s coronation pave the road to mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj je pritisnut u kut, a pješak je korak do pretvorbe.","Žrtva dame i krunidba pješaka utiru put do mata.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König hat kaum Luft am Rand und die Grundreihe ist verwundbar.","Schwere Figuren räumen die Reihe, dann krönt ein Freibauer entscheidend.","Turm schlägt auf e8 – Beginn eines erzwungenen Matts."],"en":["The black king has little air on the edge and the back rank is fragile.","Heavy pieces clear the rank before a passed pawn promotes decisively.","Rook takes on e8 — the start of a forced mate."],"hr":["Crni kralj ima malo zraka uz rub, a posljednji red je krhak.","Teške figure čiste red prije nego prolaznik odlučujuće pretvara.","Top uzima na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird über das Brett gejagt, kein sicheres Feld bleibt.","Ein Damenopfer und ein durchlaufender Bauer treiben den König ins Matt.","Dame schlägt auf g8 – Auftakt zu einem erzwungenen Matt."],"en":["The black king is hunted across the board with no safe square in sight.","A queen sacrifice and a runner pawn drive the king into mate.","Queen takes on g8 — the start of a forced mate."],"hr":["Crni kralj je progonjen po ploči, nigdje sigurnog polja.","Žrtva dame i jurišni pješak tjeraju kralja u mat.","Dama uzima na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke, das Bauernschild steht unter Beschuss.","Ein Damenopfer öffnet die Linie, dann wandelt ein Bauer todbringend um.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king clings to the corner with its pawn cover under fire.","A queen sacrifice opens the file before a pawn promotes with deadly effect.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj se drži kuta dok mu je pješački štit pod vatrom.","Žrtva dame otvara liniju prije nego se pješak smrtonosno pretvori.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke gequetscht und seine Verteidiger sind überlastet.","Reihenweise Opfer ziehen die Deckung ab, dann wandelt ein Bauer mit Schach um.","Dame schlägt auf g2 – Auftakt zu einem erzwungenen Matt."],"en":["The white king is squeezed into the corner and its defenders are overloaded.","A string of sacrifices strips the guards before a pawn promotes with check.","Queen takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj je stisnut u kut, a njegovi branitelji su preopterećeni.","Niz žrtava skida čuvare prije nego se pješak pretvori uz šah.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König sitzt in der Ecke und ein vorgeschobener Bauer lauert.","Mehrere Opfer beseitigen die Wächter, dann krönt ein Bauer zum Matt.","Dame schlägt auf a2 – Beginn eines erzwungenen Matts."],"en":["The white king sits in the corner with an advanced pawn lurking nearby.","Several sacrifices remove the guardians before a pawn crowns into mate.","Queen takes on a2 — the start of a forced mate."],"hr":["Bijeli kralj sjedi u kutu dok napredni pješak vreba u blizini.","Nekoliko žrtava uklanja čuvare prije nego se pješak okruni u mat.","Dama uzima na a2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf der Grundreihe gefangen und seine Deckung wackelt.","Ein Damenopfer und ein vorrückender Bauer öffnen den Weg zum Mattturm.","Dame schlägt auf f7 – Auftakt zu einem erzwungenen Matt."],"en":["The black king is trapped on the back rank with its cover wobbling.","A queen sacrifice and an advancing pawn clear the way for the mating rook.","Queen takes on f7 — the start of a forced mate."],"hr":["Crni kralj je zarobljen na zadnjem redu, a zaštita mu posrće.","Žrtva dame i napredujući pješak otvaraju put topu koji matira.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steckt im Zentrum fest und kann nicht in Sicherheit fliehen.","Ein durchbrechender Bauer und Linienöffnung führen zur Umwandlung mit Matt.","Bauer nach e6 – Beginn eines erzwungenen Matts."],"en":["The black king is stuck in the centre with no flight to safety.","A breakthrough pawn and an opened file lead to a promotion that mates.","Pawn to e6 — the start of a forced mate."],"hr":["Crni kralj je zaglavljen u centru bez bijega na sigurno.","Probojni pješak i otvorena linija vode pretvorbi koja matira.","Pješak na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König irrt zwischen den Ecken und findet keinen Halt.","Ein Springermanöver schnürt den König ein, dann krönt ein Bauer zum Springer.","Springer nach g6 – Auftakt zu einem erzwungenen Matt."],"en":["The black king shuffles between corners and can find no refuge.","A knight manoeuvre boxes the king in before a pawn promotes to a knight.","Knight to g6 — the start of a forced mate."],"hr":["Crni kralj luta između kutova i ne nalazi utočišta.","Manevar skakača sapinje kralja prije nego se pješak pretvori u skakača.","Skakač na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist auf den Rand gezwungen und seine Wächter sind überlastet.","Ein Damenopfer und eine Umwandlung mit Schach reißen die Stellung auf.","Dame schlägt auf h1 – Beginn eines erzwungenen Matts."],"en":["The white king is forced to the edge and its guards are overloaded.","A queen sacrifice and a check-giving promotion tear the position open.","Queen takes on h1 — the start of a forced mate."],"hr":["Bijeli kralj je natjeran na rub, a njegovi čuvari su preopterećeni.","Žrtva dame i pretvorba sa šahom razbijaju poziciju.","Dama uzima na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt in der Ecke und sein Bauernschild ist angeschlagen.","Ein Damenopfer beseitigt den Verteidiger, dann wandelt ein Bauer um.","Dame schlägt auf g2 – Auftakt zu einem erzwungenen Matt."],"en":["The white king clings to the corner with its pawn cover damaged.","A queen sacrifice removes the defender before a pawn promotes.","Queen takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj se drži kuta dok mu je pješački štit oštećen.","Žrtva dame uklanja branitelja prije nego se pješak pretvori.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.024' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird ins Freie getrieben und gnadenlos verfolgt.","Ein Damenopfer und ein krönender Bauer starten eine erbarmungslose Jagd.","Dame schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king is flushed into the open and hunted without mercy.","A queen sacrifice and a crowning pawn begin a relentless chase.","Queen takes on g7 — the start of a forced mate."],"hr":["Crni kralj je istjeran na otvoreno i nemilosrdno progonjen.","Žrtva dame i pješak koji se kruni pokreću nemilosrdnu hajku.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.025' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
