UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke gefangen und seine Wächter sind überlastet.","Eine Reihe von Opfern zieht die Deckung ab, dann krönt ein Bauer zum Matt.","Dame schlägt auf h3 – Auftakt zu einem erzwungenen Matt."],"en":["The white king is trapped in the corner and its guards are overloaded.","A series of sacrifices peels away the cover before a pawn crowns into mate.","Queen takes on h3 — the start of a forced mate."],"hr":["Bijeli kralj je zarobljen u kutu, a njegovi čuvari su preopterećeni.","Niz žrtava skida zaštitu prije nego se pješak okruni u mat.","Dama uzima na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.032' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht in der Mitte unter Feuer und seine Figuren stehen im Weg.","Ein Läuferopfer und eine Springerumwandlung lenken die Deckung ab.","Läufer schlägt auf e6 – Beginn eines erzwungenen Matts."],"en":["The black king is under fire in the centre with its own pieces in the way.","A bishop sacrifice and an underpromotion to a knight deflect the defence.","Bishop takes on e6 — the start of a forced mate."],"hr":["Crni kralj je pod vatrom u centru, a vlastite mu figure smetaju.","Žrtva lovca i pretvorba u skakača odvlače obranu.","Lovac uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.033' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in die Ecke gedrängt und seine Grundreihe ist verwundbar.","Ein Turmopfer lenkt einen Verteidiger ab, dann liefern Turm und Springer das Matt.","Turm nach a8 – Beginn eines erzwungenen Matts."],"en":["The black king is forced into the corner with a vulnerable back rank.","A rook sacrifice deflects a defender so rook and knight can combine to mate.","Rook to a8 — the start of a forced mate."],"hr":["Crni kralj je natjeran u kut s ranjivim zadnjim redom.","Žrtva topa odvlači branitelja kako bi top i skakač zajedno matirali.","Top na a8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf der Grundreihe eingeklemmt und seine Deckung überlastet.","Ein Damenopfer räumt die Reihe, dann gibt ein Turm das letzte Schach.","Dame schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king is hemmed in on the back rank with an overloaded defence.","A queen sacrifice clears the rank so a rook can deliver the final check.","Queen takes on f8 — the start of a forced mate."],"hr":["Crni kralj je sapet na zadnjem redu s preopterećenom obranom.","Žrtva dame čisti red kako bi top dao završni šah.","Dama uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der gegnerische König ist in der Ecke eingesperrt und braucht nur einen kleinen Stoß.","Ein Springer findet das tödliche Feld, während dein Turm die Fluchtwege versperrt.","Turm nach b8 – Beginn eines erzwungenen Matts."],"en":["The enemy king is boxed into the corner and just needs a final push.","A knight finds the killing square while your rook seals the escape.","Rook to b8 — the start of a forced mate."],"hr":["Protivnički kralj je zatočen u kutu i treba samo posljednji udarac.","Skakač pronalazi smrtonosno polje dok tvoj top zatvara bijeg.","Top na b8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht am Rand erstickt und kann keinem Schach ausweichen.","Ein Turm liefert auf der Grundreihe das ersticke Matt.","Turm nach g1 – matt."],"en":["The white king is stuck on the edge with his own men smothering him.","A rook swings to the back to deliver the final blow.","Rook to g1 — mate."],"hr":["Bijeli kralj je ugušen na rubu i nema kamo pobjeći.","Top dolazi na zadnju liniju i daje završni udarac.","Top na g1 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:008.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung zerfällt, sobald ein Opfer die Linien öffnet.","Ein Läuferopfer reißt die Stellung auf und der Turm dringt entscheidend ein.","Läufer schlägt auf h2 – Auftakt zum erzwungenen Matt."],"en":["The white king''s shelter collapses once a sacrifice tears it open.","A bishop sacrifice clears the way for your rook to crash through.","Bishop takes on h2 — beginning a forced mate."],"hr":["Zaklon bijelog kralja se ruši čim žrtva otvori linije.","Žrtva lovca otvara put topu da prodre odlučujuće.","Lovac uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch ein Opfer schutzlos gemacht.","Ein Damenopfer zieht den König heraus, dann gibt ein Turm das Matt.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["A sacrifice strips the cornered black king of his last defender.","Giving up the queen drags the king out so a rook can finish.","Queen takes on h7 — the start of a forced mate."],"hr":["Žrtva oduzima skučenom crnom kralju posljednju zaštitu.","Žrtva dame izvlači kralja, a zatim top daje mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in eine tödliche Matrix aus Turm und Springern getrieben.","Ein Turmschach lenkt den König, dann setzt ein Springer das Netz.","Turm nach c8 – Auftakt zum erzwungenen Matt."],"en":["The black king is herded into a deadly net of rook and knights.","A rook check drives the king and a knight closes the trap.","Rook to c8 — beginning a forced mate."],"hr":["Crni kralj je natjeran u smrtonosnu mrežu topa i skakača.","Šah topom tjera kralja, a skakač zatvara zamku.","Top na c8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch einen Turm in der Ecke festgenagelt.","Ein Turmopfer auf der Grundreihe öffnet alles, der zweite Turm mattsetzt.","Turm nach h8 – Beginn eines erzwungenen Matts."],"en":["The black king gets pinned to the edge by an invading rook.","A rook check on the back rank lets your other rook strike home.","Rook to h8 — the start of a forced mate."],"hr":["Crni kralj je prikovan uz rub upadom topa.","Šah topom po zadnjoj liniji omogućuje drugom topu da zada udarac.","Top na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Grundreihe ist überlastet und kann das Eindringen nicht halten.","Ein Damenopfer beseitigt den Verteidiger, dann mattet der Turm.","Dame schlägt auf f2 – Auftakt zum erzwungenen Matt."],"en":["White''s back rank is overloaded and cannot hold the invasion.","Sacrificing the queen removes the guard so your rook can mate.","Queen takes on f2 — beginning a forced mate."],"hr":["Bijela zadnja linija je preopterećena i ne može zadržati prodor.","Žrtva dame uklanja branitelja, a zatim top daje mat.","Dama uzima na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird Schritt für Schritt an den Rand getrieben.","Ein Turm und ein Springer arbeiten zusammen, bis der Turm das Matt gibt.","Turm nach f7 – Beginn eines erzwungenen Matts."],"en":["The black king is driven step by step toward the edge.","A rook and a knight cooperate until the rook delivers mate.","Rook to f7 — the start of a forced mate."],"hr":["Crni kralj je korak po korak natjeran prema rubu.","Top i skakač surađuju dok top ne zada mat.","Top na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus seiner Deckung gezogen.","Ein Damenopfer öffnet die h-Linie, dann gibt die Dame das Matt.","Dame schlägt auf h7 – Auftakt zum erzwungenen Matt."],"en":["A sacrifice yanks the black king out from behind his pawns.","Giving up on the rook file opens it so your queen can finish.","Queen takes on h7 — beginning a forced mate."],"hr":["Žrtva izvlači crnog kralja iza njegovih pješaka.","Žrtva otvara liniju, a zatim dama daje mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
