UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke wird von Turm und Springer gejagt.","Springermanöver treiben den König, bis der Turm das Matt gibt.","Turm nach c8 – Auftakt zum erzwungenen Matt."],"en":["The cornered black king is hunted by a rook and a knight.","Knight maneuvers chase the king until the rook delivers mate.","Rook to c8 — beginning a forced mate."],"hr":["Skučenog crnog kralja love top i skakač.","Manevri skakača progone kralja dok top ne zada mat.","Top na c8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.032' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird durch Springermanöver und Bauern eingeschnürt.","Ein Springer schnürt das Netz, dann opfert sich der Turm zum Matt.","Springer nach f6 – Beginn eines erzwungenen Matts."],"en":["The white king is laced into a net by knight maneuvers and pawns.","A knight tightens the net before the rook sacrifices itself to mate.","Knight to f6 — the start of a forced mate."],"hr":["Bijeli kralj je stegnut manevrima skakača i pješacima.","Skakač zatvara mrežu, a zatim se top žrtvuje za mat.","Skakač na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.033' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke fällt einer Reihe von Opfern zum Opfer.","Erst ein Damenopfer, dann ein Bauernschach öffnen den Weg für den Turm.","Dame schlägt auf g6 – Beginn eines erzwungenen Matts."],"en":["The cornered black king falls to a series of sacrifices.","A queen sacrifice and a pawn check clear the path for your rook.","Queen takes on g6 — the start of a forced mate."],"hr":["Skučeni crni kralj pada nakon niza žrtava.","Žrtva dame i šah pješakom otvaraju put topu.","Dama uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.034' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand schlecht geschützt; ein Damenopfer reißt die Stellung auf.","Opfere die Dame, um den König zu entblößen, dann erzwingt Springer und Turm das Matt.","Dame schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king is poorly sheltered on the edge; a queen sacrifice tears it open.","Sacrifice the queen to strip the king, then knight and rook force the mate.","Queen takes on g7 — the start of a forced mate."],"hr":["Crni kralj je slabo zaštićen na rubu; žrtva dame razbija položaj.","Žrtvuj damu da ogoliš kralja, pa skakač i top forsiraju mat.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.035' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König hinter dem Bauernschild lässt sich durch Opfer aufdecken.","Ein Springeropfer und ein Läuferopfer öffnen die Stellung, dann gibt der Turm das Matt.","Springer schlägt auf f6 – Auftakt zum erzwungenen Matt."],"en":["The king behind its pawn shield can be exposed by sacrifices.","A knight sacrifice and a bishop sacrifice rip it open, then a rook mates.","Knight takes on f6 — the start of a forced mate."],"hr":["Kralja iza pješačkog štita razotkrivaju žrtve.","Žrtva skakača i žrtva lovca otvaraju položaj, pa top matira.","Skakač uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.036' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand wird durch ein Damenopfer und Druck auf der siebten Reihe erledigt.","Opfere die Dame, dann dringt der Turm auf der vorletzten Reihe entscheidend ein.","Dame nach f6 – Beginn eines erzwungenen Matts."],"en":["The king on the edge falls to a queen sacrifice and pressure on the seventh rank.","Sacrifice the queen, then a rook breaks in decisively on the seventh.","Queen to f6 — the start of a forced mate."],"hr":["Kralj na rubu pada od žrtve dame i pritiska na sedmom redu.","Žrtvuj damu, pa top odlučno prodire na pretposljednjem redu.","Dama na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.037' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König in der Ecke ist durch eingeklemmte Figuren bewegungslos.","Ein Turmopfer lockt, und ein Bauernzug deckt den Springer für das Erstickungsmatt.","Turm schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The king in the corner is immobilised by its own cramped pieces.","A rook lure followed by a pawn advance sets up the smothered finish.","Rook takes on g7 — the start of a forced mate."],"hr":["Kralj u kutu je nepokretan zbog vlastitih stiješnjenih figura.","Mamac topom pa potez pješaka priprema gušeći završetak.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.038' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der nackte König wird in die Ecke getrieben und im Zusammenspiel mattgesetzt.","Turm und Springer arbeiten zusammen, um den König einzukreisen.","Turm schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["The bare king is driven to the corner and mated by coordination.","A rook and knight work together to net the king.","Rook takes on f7 — the start of a forced mate."],"hr":["Goli kralj je potjeran u kut i matiran suradnjom figura.","Top i skakač zajedno opkoljavaju kralja.","Top uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.039' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König im Zentrum wird von koordinierten leichten Figuren und dem Turm gejagt.","Ein Turmopfer treibt den König, dann setzen die Springer das Netz.","Turm nach d8 – Beginn eines erzwungenen Matts."],"en":["The centralised king is hunted by coordinated minor pieces and the rook.","A rook check drives the king, then the knights weave the net.","Rook to d8 — the start of a forced mate."],"hr":["Kralja u centru love usklađene lake figure i top.","Šah topom tjera kralja, pa skakači pletu mrežu.","Top na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.040' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König im Freien lässt sich mit Bauer und Turm einfangen.","Ein Bauernzug nimmt Fluchtfelder, dann gibt der Turm das Matt.","Bauer nach f4 – Beginn eines erzwungenen Matts."],"en":["The exposed king can be trapped by a pawn and a rook.","A pawn move removes escape squares, then the rook delivers mate.","Pawn to f4 — the start of a forced mate."],"hr":["Otkrivenog kralja moguće je uhvatiti pješakom i topom.","Potez pješaka oduzima polja za bijeg, pa top matira.","Pješak na f4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.041' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König hinter dem Bauernschild fällt durch ein Damenopfer.","Opfere die Dame auf dem Königsflügel, dann setzt der Turm das Matt.","Dame schlägt auf g6 – Beginn eines erzwungenen Matts."],"en":["The king behind its pawns falls to a queen sacrifice.","Sacrifice the queen on the kingside, then a rook delivers mate.","Queen takes on g6 — the start of a forced mate."],"hr":["Kralj iza pješaka pada od žrtve dame.","Žrtvuj damu na kraljevom krilu, pa top matira.","Dama uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.042' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König wird durch Opfer auf der f-Linie freigelegt und vom Springer erstickt.","Ein Damenopfer und ein Turmopfer reißen die Stellung auf, dann mattet der Springer.","Dame schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["The king is exposed by sacrifices on the f-file and smothered by a knight.","A queen sacrifice and a rook sacrifice rip it open, then the knight mates.","Queen takes on f7 — the start of a forced mate."],"hr":["Kralj je razotkriven žrtvama te ga skakač guši.","Žrtva dame i žrtva topa otvaraju položaj, pa skakač matira.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.043' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König an der Grundreihe wird durch eine Opferserie zerlegt.","Ein Damenopfer und ein Turmeinschlag entblößen den König, dann mattet der Springer.","Dame schlägt auf c2 – Beginn eines erzwungenen Matts."],"en":["The white king on the back rank is dismantled by a sacrificial sequence.","A queen sacrifice and a rook strike strip the king, then a knight mates.","Queen takes on c2 — the start of a forced mate."],"hr":["Bijeli kralj na zadnjem redu razbija se nizom žrtava.","Žrtva dame i udar topa ogoljuju kralja, pa skakač matira.","Dama uzima na c2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.044' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand wird durch Ablenkungs- und Räumungsopfer mattgesetzt.","Ein Turmopfer und ein Damenopfer ebnen den Weg, dann mattet der Turm.","Turm schlägt auf e8 – Beginn eines erzwungenen Matts."],"en":["The king on the edge is mated through deflection and clearance sacrifices.","A rook sacrifice and a queen sacrifice clear the way, then a rook mates.","Rook takes on e8 — the start of a forced mate."],"hr":["Kralj na rubu matira se žrtvama odvlačenja i čišćenja.","Žrtva topa i žrtva dame raščišćavaju put, pa top matira.","Top uzima na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.045' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König hinter dem g-Bauern wird durch ein Damenopfer geöffnet.","Opfere die Dame, dann erzwingt der Springer mit dem Turm das Matt.","Dame schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The king behind the g-pawn is opened up by a queen sacrifice.","Sacrifice the queen, then a knight and rook force the mate.","Queen takes on g7 — the start of a forced mate."],"hr":["Kralja iza pješaka otvara žrtva dame.","Žrtvuj damu, pa skakač i top forsiraju mat.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.046' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand wird durch ein Springeropfer in die Falle gelockt.","Ein Springeropfer und der Turm treiben den König, dann mattet der Springer.","Springer schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The king on the edge is lured into a trap by a knight sacrifice.","A knight sacrifice and the rook drive the king, then a knight mates.","Knight takes on f8 — the start of a forced mate."],"hr":["Kralja na rubu mami u zamku žrtva skakača.","Žrtva skakača i top tjeraju kralja, pa skakač matira.","Skakač uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.047' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der unrochierte König im Zentrum fällt durch eine Opferkette.","Ein Turmopfer und Abtäusche legen den König frei, dann mattet der Turm.","Turm schlägt auf e6 – Beginn eines erzwungenen Matts."],"en":["The uncastled king in the centre falls to a chain of sacrifices.","A rook sacrifice and exchanges expose the king, then a rook mates.","Rook takes on e6 — the start of a forced mate."],"hr":["Nerokiran kralj u centru pada od niza žrtava.","Žrtva topa i razmjene razotkrivaju kralja, pa top matira.","Top uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.048' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König in der Ecke wird durch Springer und Turm eingeschnürt.","Ein Springermanöver nimmt Felder, dann gibt der Turm das Matt.","Springer schlägt auf g4 – Beginn eines erzwungenen Matts."],"en":["The white king in the corner is laced in by a knight and rook.","A knight manoeuvre removes squares, then a rook delivers mate.","Knight takes on g4 — the start of a forced mate."],"hr":["Bijeli kralj u kutu stiješnjen je skakačem i topom.","Manevar skakača oduzima polja, pa top matira.","Skakač uzima na g4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.049' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König hinter den Bauern wird durch Opfer auf dem Königsflügel zerschlagen.","Ein Springeropfer und ein Damenopfer reißen auf, dann mattet der Turm.","Springer schlägt auf f6 – Beginn eines erzwungenen Matts."],"en":["The king behind its pawns is smashed by kingside sacrifices.","A knight sacrifice and a queen sacrifice tear it open, then a rook mates.","Knight takes on f6 — the start of a forced mate."],"hr":["Kralja iza pješaka razbijaju žrtve na kraljevom krilu.","Žrtva skakača i žrtva dame otvaraju položaj, pa top matira.","Skakač uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.050' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand wird durch Ablenkung und Springermanöver gefangen.","Ein Turmopfer lenkt ab, dann liefert der Springer den Erstickungsschlag.","Turm schlägt auf e8 – Beginn eines erzwungenen Matts."],"en":["The king on the edge is trapped by deflection and a knight manoeuvre.","A rook deflects, then a knight delivers the smothering blow.","Rook takes on e8 — the start of a forced mate."],"hr":["Kralja na rubu hvataju odvlačenje i manevar skakača.","Top odvlači, pa skakač zadaje gušeći udarac.","Top uzima na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.051' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König hinter dem vorgeschobenen Bauern wird durch Ablenkung erledigt.","Ein Damenopfer lenkt den Verteidiger ab, dann mattet der Läufer.","Dame schlägt auf g5 – Beginn eines erzwungenen Matts."],"en":["The king behind the advanced pawn falls to a deflection.","A queen sacrifice deflects the defender, then a bishop mates.","Queen takes on g5 — the start of a forced mate."],"hr":["Kralj iza istaknutog pješaka pada od odvlačenja.","Žrtva dame odvlači branitelja, pa lovac matira.","Dama uzima na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.052' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König in der Ecke wird durch ein Damenopfer und Springerwirkung mattgesetzt.","Opfere die Dame, lenke den Verteidiger ab, dann mattet der Springer.","Dame schlägt auf a6 – Beginn eines erzwungenen Matts."],"en":["The king in the corner is mated by a queen sacrifice and the knight.","Sacrifice the queen, deflect the defender, then a knight mates.","Queen takes on a6 — the start of a forced mate."],"hr":["Kralja u kutu matira žrtva dame i djelovanje skakača.","Žrtvuj damu, odvuci branitelja, pa skakač matira.","Dama uzima na a6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.053' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König hinter dem Bauernschild fällt durch ein Damenopfer.","Opfere die Dame, dann erledigen Springer und Turm den König.","Dame schlägt auf h8 – Beginn eines erzwungenen Matts."],"en":["The king behind its pawn shield falls to a queen sacrifice.","Sacrifice the queen, then a knight and rook finish the king.","Queen takes on h8 — the start of a forced mate."],"hr":["Kralj iza pješačkog štita pada od žrtve dame.","Žrtvuj damu, pa skakač i top dokrajče kralja.","Dama uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.054' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird durch eine Folge präziser Opfer entblößt.","Ein Springeropfer und ein Damenopfer reißen auf, dann mattet der Turm.","Springer schlägt auf f3 – Beginn eines erzwungenen Matts."],"en":["The white king is laid bare by a string of precise sacrifices.","A knight sacrifice and a queen sacrifice tear it open, then a rook mates.","Knight takes on f3 — the start of a forced mate."],"hr":["Bijeli kralj se ogoljuje nizom preciznih žrtava.","Žrtva skakača i žrtva dame otvaraju, pa top matira.","Skakač uzima na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.055' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird durch ein Damenopfer und Linienöffnung erledigt.","Opfere die Dame, dann dringen Turm und Springer entscheidend ein.","Dame schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king falls to a queen sacrifice that opens the lines.","Sacrifice the queen, then a rook and knight break in decisively.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj pada od žrtve dame koja otvara linije.","Žrtvuj damu, pa top i skakač odlučno prodiru.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.056' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König am Rand wird durch eine Opferserie eingekreist.","Ein Turmopfer und ein zweites Turmopfer entblößen den König, dann mattet die Dame.","Turm schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king on the edge is encircled by a sacrificial sequence.","A rook sacrifice and a second rook sacrifice strip the king, then the queen mates.","Rook takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj na rubu opkoljen je nizom žrtava.","Žrtva topa i druga žrtva topa ogoljuju kralja, pa dama matira.","Top uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:008.057' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die verdoppelten Türme wirken zusammen gegen den König am Rand.","Ein Turmopfer öffnet die Linie, dann mattet das Tandem aus Türmen.","Turm schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The doubled rooks act in concert against the king on the edge.","A rook sacrifice opens the file, then the rook tandem mates.","Rook takes on h7 — the start of a forced mate."],"hr":["Udvojeni topovi djeluju zajedno protiv kralja na rubu.","Žrtva topa otvara liniju, pa tandem topova matira.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand wird vom Damen- und Turmduo überrannt.","Ein Damenopfer öffnet die Linie, dann übernimmt der Turm das Matt.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The king on the edge is overrun by the queen-and-rook duo.","A queen sacrifice opens the file, then a rook takes over the mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Kralja na rubu pregaze dama i top u paru.","Žrtva dame otvara liniju, pa top preuzima mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand wird durch Opfer und Damenwirkung eingeschnürt.","Ein Turmopfer und ein Damenmanöver erzwingen das Matt der Dame.","Turm schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The king on the edge is hemmed in by a sacrifice and the queen.","A rook sacrifice and a queen manoeuvre force a queen mate.","Rook takes on g7 — the start of a forced mate."],"hr":["Kralja na rubu stiješnjuju žrtva i djelovanje dame.","Žrtva topa i manevar dame forsiraju mat damom.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König am Rand fällt der Wirkung der verdoppelten Türme zum Opfer.","Ein Turmopfer und ein Springersprung räumen Felder, dann mattet der Turm.","Turm schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king on the edge succumbs to the doubled rooks'' power.","A rook sacrifice and a knight leap clear squares, then a rook mates.","Rook takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj na rubu pada pred snagom udvojenih topova.","Žrtva topa i skok skakača čiste polja, pa top matira.","Top uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Schwarzen Türme greifen den König am Rand gemeinsam an.","Ein Vorstoß bindet die Verteidigung, dann mattet der Turm in der Ecke.","Turm nach f1 – Beginn eines erzwungenen Matts."],"en":["Black''s rooks combine against the king on the edge.","An advance ties up the defence, then a rook mates in the corner.","Rook to f1 — the start of a forced mate."],"hr":["Crni topovi zajedno napadaju kralja na rubu.","Prodor veže obranu, pa top matira u kutu.","Top na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand wird durch verdoppelte Türme und ein Opfer erledigt.","Ein Damenopfer lenkt ab, dann mattet das Turmpaar auf der offenen Linie.","Dame schlägt auf f6 – Beginn eines erzwungenen Matts."],"en":["The king on the edge falls to the doubled rooks and a sacrifice.","A queen sacrifice deflects, then the rook pair mates down the file.","Queen takes on f6 — the start of a forced mate."],"hr":["Kralj na rubu pada od udvojenih topova i žrtve.","Žrtva dame odvlači, pa par topova matira po liniji.","Dama uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König am Rand wird durch ein Damenopfer und die Türme gefasst.","Opfere die Dame, um die Linie zu öffnen, dann mattet der Turm.","Dame schlägt auf g3 – Beginn eines erzwungenen Matts."],"en":["The white king on the edge is caught by a queen sacrifice and the rooks.","Sacrifice the queen to open the file, then a rook mates.","Queen takes on g3 — the start of a forced mate."],"hr":["Bijelog kralja na rubu hvataju žrtva dame i topovi.","Žrtvuj damu da otvoriš liniju, pa top matira.","Dama uzima na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt in der Ecke und seine Grundreihe ist tödlich verwundbar.","Ein Damenopfer reißt die Linie auf, dann setzen deine Türme nach.","Dame nach a3 – Beginn eines erzwungenen Matts."],"en":["The white king is wedged in the corner and his back rank is fatally weak.","A queen sacrifice tears open the file, then your rooks finish the job.","Queen to a3 — the start of a forced mate."],"hr":["Bijeli kralj je stisnut u kutu, a njegov zadnji red smrtonosno je slab.","Žrtva dame otvara liniju, a zatim tvoji topovi dovršavaju posao.","Dama na a3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König sitzt in der Ecke und seine Verteidiger sind hoffnungslos überlastet.","Ein Damenopfer lenkt einen Turm ab, dann krönen deine Schwerfiguren den Angriff.","Dame nimmt auf f1 – Beginn eines erzwungenen Matts."],"en":["The white king is boxed in the corner and his defenders are hopelessly overworked.","A queen sacrifice deflects a rook, then your heavy pieces crash through.","Queen takes on f1 — the start of a forced mate."],"hr":["Bijeli kralj je zatvoren u kutu, a njegovi branitelji beznadno su preopterećeni.","Žrtva dame odvlači topa, a zatim tvoje teške figure probijaju obranu.","Dama uzima na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Grundreihe ist entblößt und der König hat kein Luftloch.","Ein Damenopfer öffnet die Linie, dann dringt dein Turm ein.","Dame nimmt auf f6 – Beginn eines erzwungenen Matts."],"en":["Black''s back rank lies bare and the king has no luft.","A queen sacrifice opens the file, then your rook invades.","Queen takes on f6 — the start of a forced mate."],"hr":["Crni zadnji red ostao je gol, a kralj nema zračnu rupu.","Žrtva dame otvara liniju, a zatim tvoj top prodire.","Dama uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König hängt an seiner schwachen Grundreihe.","Ein Opfer räumt den Weg, dann setzt dein Turm auf der Grundreihe matt.","Dame nach d5 – Beginn eines erzwungenen Matts."],"en":["The black king is at the mercy of his weak back rank.","A sacrifice clears the path, then your rook mates along the back rank.","Queen to d5 — the start of a forced mate."],"hr":["Crni kralj je prepušten svom slabom zadnjem redu.","Žrtva čisti put, a zatim tvoj top matira po zadnjem redu.","Dama na d5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist an den Rand gedrängt und kaum gedeckt.","Ein Damenopfer zieht den König heraus, dann jagen ihn deine Figuren zu Tode.","Dame nimmt auf h3 – Beginn eines erzwungenen Matts."],"en":["The white king is shoved to the edge and barely defended.","A queen sacrifice drags the king out, then your pieces hunt him down.","Queen takes on h3 — the start of a forced mate."],"hr":["Bijeli kralj je gurnut na rub i jedva branjen.","Žrtva dame izvlači kralja, a zatim ga tvoje figure progone do smrti.","Dama uzima na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf der letzten Reihe eingesperrt und am Rand verletzlich.","Deine Türme arbeiten zusammen und treiben den König ins Matt.","Turm nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is shut in on the last rank and vulnerable at the edge.","Your rooks coordinate to herd the king into mate.","Rook takes on h7 — the start of a forced mate."],"hr":["Crni kralj je zatvoren na zadnjem redu i ranjiv na rubu.","Tvoji topovi surađuju i tjeraju kralja u mat.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht offen im Zentrum und kein Schild kann ihn retten.","Deine Dame und Türme weben ein langes Mattnetz um den nackten König.","Dame nimmt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king stands exposed in the centre with no shelter to save him.","Your queen and rooks weave a long mating net around the bare king.","Queen takes on f8 — the start of a forced mate."],"hr":["Crni kralj stoji izložen u sredini i nijedan štit ga ne može spasiti.","Tvoja dama i topovi pletu dugu matnu mrežu oko golog kralja.","Dama uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König sitzt in der Ecke und seine Deckung ist überlastet.","Ein Damenopfer beseitigt den Verteidiger, dann setzen deine Schwerfiguren nach.","Dame nimmt auf g4 – Beginn eines erzwungenen Matts."],"en":["The white king sits in the corner and his guard is overloaded.","A queen sacrifice removes the defender, then your heavy pieces follow up.","Queen takes on g4 — the start of a forced mate."],"hr":["Bijeli kralj sjedi u kutu, a njegova obrana je preopterećena.","Žrtva dame uklanja branitelja, a zatim tvoje teške figure nastavljaju.","Dama uzima na g4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf der letzten Reihe gefangen und sein Schutz wackelt.","Ein Damenopfer öffnet die Reihe, dann fegen deine Türme durch.","Dame nach f7 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped on the last rank and his cover is crumbling.","A queen sacrifice opens the rank, then your rooks sweep through.","Queen to f7 — the start of a forced mate."],"hr":["Crni kralj je zarobljen na zadnjem redu i njegov zaklon se ruši.","Žrtva dame otvara red, a zatim tvoji topovi prolijeću kroz.","Dama na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt in der Ecke und seine Linien sind tödlich offen.","Ein Turmopfer reißt den König heraus, dann liefert ein zweiter Turm das Matt.","Turm nach g1 – Beginn eines erzwungenen Matts."],"en":["The white king is glued to the corner and his lines are fatally open.","A rook sacrifice prises the king out, then a second rook delivers mate.","Rook to g1 — the start of a forced mate."],"hr":["Bijeli kralj je zalijepljen u kutu, a njegove linije smrtonosno su otvorene.","Žrtva topa izvlači kralja, a zatim drugi top daje mat.","Top na g1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke gefangen und seine Reihen lassen sich aufbrechen.","Eine Reihe von Opfern zerrt den König heraus, dann setzt dein Turm matt.","Dame nimmt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king is caught in the corner and his ranks can be peeled open.","A string of sacrifices drags the king out, then your rook mates.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj je uhvaćen u kutu i njegovi redovi mogu se rastvoriti.","Niz žrtava izvlači kralja, a zatim tvoj top matira.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist entblößt, sobald sein letzter Verteidiger fällt.","Ein Damenopfer lockt einen Verteidiger weg, dann brechen deine Türme durch.","Dame nimmt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king is laid bare once his last defender is removed.","A queen sacrifice lures a defender away, then your rooks break through.","Queen takes on f8 — the start of a forced mate."],"hr":["Crni kralj ostaje gol čim padne njegov posljednji branitelj.","Žrtva dame odmamljuje branitelja, a zatim tvoji topovi probijaju.","Dama uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke gedrängt und seine Deckung überlastet.","Ein Damenopfer öffnet die Linie, dann liefern deine Türme das Matt.","Dame nimmt auf g2 – Beginn eines erzwungenen Matts."],"en":["The white king is forced to the corner and his guard is overloaded.","A queen sacrifice opens the file, then your rooks deliver mate.","Queen takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj je natjeran u kut, a njegova obrana je preopterećena.","Žrtva dame otvara liniju, a zatim tvoji topovi daju mat.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König sitzt in der Ecke und seine Grundreihe ist verwundbar.","Ein Damenopfer reißt die Königsstellung auf, dann setzen deine Türme nach.","Dame nimmt auf g3 – Beginn eines erzwungenen Matts."],"en":["The white king sits in the corner and his back rank is vulnerable.","A queen sacrifice rips open the king''s shelter, then your rooks pile in.","Queen takes on g3 — the start of a forced mate."],"hr":["Bijeli kralj sjedi u kutu, a njegov zadnji red je ranjiv.","Žrtva dame otvara kraljev zaklon, a zatim tvoji topovi nasrću.","Dama uzima na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an den Rand getrieben und kaum verteidigt.","Ein Opfer beseitigt den Verteidiger, dann brechen deine Türme zum König durch.","Läufer nimmt auf h6 – Beginn eines erzwungenen Matts."],"en":["The black king is driven to the edge with scant defence.","A sacrifice removes the defender, then your rooks crash through to the king.","Bishop takes on h6 — the start of a forced mate."],"hr":["Crni kralj je natjeran na rub uz oskudnu obranu.","Žrtva uklanja branitelja, a zatim tvoji topovi probijaju do kralja.","Lovac uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.024' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf den Rand gepresst und sein Schutz bröckelt.","Ein Damenopfer entblößt den König, dann jagen deine Türme ihn ins Matt.","Dame nimmt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king is squeezed to the edge and his cover is breaking up.","A queen sacrifice strips the king bare, then your rooks chase him to mate.","Queen takes on f8 — the start of a forced mate."],"hr":["Crni kralj je stisnut na rub, a njegov zaklon se raspada.","Žrtva dame ogoljuje kralja, a zatim ga tvoji topovi tjeraju u mat.","Dama uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.025' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird an den Rand gezogen und steht völlig blank.","Ein Damenopfer holt den König heraus, dann fangen ihn deine Türme ein.","Dame nimmt auf h5 – Beginn eines erzwungenen Matts."],"en":["The black king is dragged to the edge and left completely exposed.","A queen sacrifice pulls the king out, then your rooks net him.","Queen takes on h5 — the start of a forced mate."],"hr":["Crni kralj je odvučen na rub i ostaje potpuno izložen.","Žrtva dame izvlači kralja, a zatim ga tvoji topovi hvataju.","Dama uzima na h5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.026' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt am Rand und seine Linien sind aufgerissen.","Ein Damenopfer beseitigt die Deckung, dann setzt dein Turm matt.","Dame nimmt auf h4 – Beginn eines erzwungenen Matts."],"en":["The white king is pinned to the edge with his lines torn open.","A queen sacrifice clears the guard, then your rook mates.","Queen takes on h4 — the start of a forced mate."],"hr":["Bijeli kralj je prikovan na rub s otvorenim linijama.","Žrtva dame uklanja obranu, a zatim tvoj top matira.","Dama uzima na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.027' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist eingemauert und seine Bauerndeckung wackelt.","Ein Opfer reißt die Bauernkette auf, dann dringen deine Türme ein.","Dame nimmt auf g6 – Beginn eines erzwungenen Matts."],"en":["The black king is walled in and his pawn cover is shaky.","A sacrifice rips open the pawn cover, then your rooks invade.","Queen takes on g6 — the start of a forced mate."],"hr":["Crni kralj je zazidan, a njegov pješački zaklon je nestabilan.","Žrtva otvara pješačku obranu, a zatim tvoji topovi prodiru.","Dama uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.028' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke gedrängt und seine Deckung überlastet.","Eine Folge von Opfern zerrt den König heraus, dann setzt dein Turm matt.","Dame nimmt auf h1 – Beginn eines erzwungenen Matts."],"en":["The white king is forced to the corner with his guard overloaded.","A sequence of sacrifices drags the king out, then your rook mates.","Queen takes on h1 — the start of a forced mate."],"hr":["Bijeli kralj je natjeran u kut s preopterećenom obranom.","Niz žrtava izvlači kralja, a zatim tvoj top matira.","Dama uzima na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.029' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird an den Rand getrieben und steht schutzlos da.","Ein Damenopfer holt den König heraus, dann setzen deine Türme matt.","Dame nach d7 – Beginn eines erzwungenen Matts."],"en":["The black king is driven to the edge and left without shelter.","A queen sacrifice pulls the king out, then your rooks deliver mate.","Queen to d7 — the start of a forced mate."],"hr":["Crni kralj je natjeran na rub i ostaje bez zaklona.","Žrtva dame izvlači kralja, a zatim tvoji topovi daju mat.","Dama na d7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.030' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand gefangen und sein Schutz schmilzt dahin.","Ein paar Opfer öffnen die Linien, dann setzt dein Turm matt.","Dame nach h4 – Beginn eines erzwungenen Matts."],"en":["The black king is caught at the edge and his cover is melting away.","A couple of sacrifices open the lines, then your rook mates.","Queen to h4 — the start of a forced mate."],"hr":["Crni kralj je uhvaćen na rubu, a njegov zaklon se topi.","Nekoliko žrtava otvara linije, a zatim tvoj top matira.","Dama na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.031' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König irrt im Zentrum umher, ohne sicheren Hafen.","Eine Reihe von Opfern öffnet die Linien, dann setzt dein Turm matt.","Springer nimmt auf c6 – Beginn eines erzwungenen Matts."],"en":["The black king wanders in the centre with no safe haven.","A series of sacrifices opens the lines, then your rook delivers mate.","Knight takes on c6 — the start of a forced mate."],"hr":["Crni kralj luta u sredini bez sigurnog utočišta.","Niz žrtava otvara linije, a zatim tvoj top daje mat.","Skakač uzima na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.032' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird durch ein Opfer aus seiner Deckung gelockt.","Ein Damenopfer öffnet den Weg, dann liefert ein Springer den tödlichen Schlag.","Dame nimmt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king can be lured out of his shelter by a sacrifice.","A queen sacrifice clears the way, then a knight delivers the fatal blow.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj može biti izmamljen iz zaklona žrtvom.","Žrtva dame otvara put, a zatim skakač zadaje smrtonosni udarac.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.033' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter einer Bauernbarriere verschanzt, die zerbrechen kann.","Ein Turmopfer sprengt die Bauern auf, dann dringt deine Dame ein.","Turm nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king hides behind a pawn barrier that can be shattered.","A rook sacrifice blasts open the pawns, then your queen invades.","Rook takes on h7 — the start of a forced mate."],"hr":["Crni kralj se skriva iza pješačke barijere koja se može razbiti.","Žrtva topa razbija pješake, a zatim tvoja dama prodire.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter Bauern verschanzt, die geopfert weg müssen.","Ein Turmopfer öffnet die Königsstellung, dann setzt deine Dame nach.","Turm nimmt auf h6 – Beginn eines erzwungenen Matts."],"en":["The black king shelters behind pawns that must be sacrificed away.","A rook sacrifice prises open the king''s shelter, then your queen follows.","Rook takes on h6 — the start of a forced mate."],"hr":["Crni kralj se skriva iza pješaka koje treba žrtvom ukloniti.","Žrtva topa otvara kraljev zaklon, a zatim tvoja dama nastavlja.","Top uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König hat keinen Fluchtweg, wenn die Linie zu ihm geöffnet wird.","Ein Damenopfer reißt die Linie auf, dann dringt dein Turm vernichtend ein.","Dame nimmt auf g2 – Beginn eines erzwungenen Matts."],"en":["The white king has no escape once the file to him is opened.","A queen sacrifice tears open the file, then your rook invades decisively.","Queen takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj nema bijeg čim se linija prema njemu otvori.","Žrtva dame otvara liniju, a zatim tvoj top odlučujuće prodire.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter wackeligen Bauern verschanzt, die fallen müssen.","Ein Turmopfer reißt die Königsstellung auf, dann setzt deine Dame matt.","Turm nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king hides behind shaky pawns that have to be removed.","A rook sacrifice rips open the king''s shelter, then your queen mates.","Rook takes on h7 — the start of a forced mate."],"hr":["Crni kralj se skriva iza nestabilnih pješaka koje treba ukloniti.","Žrtva topa otvara kraljev zaklon, a zatim tvoja dama matira.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter Bauern verbarrikadiert, die geopfert weg müssen.","Ein Damenopfer öffnet die Königsstellung, dann marschiert dein Bauer zum Matt.","Dame nimmt auf g6 – Beginn eines erzwungenen Matts."],"en":["The black king is barricaded behind pawns that must be sacrificed away.","A queen sacrifice opens the king''s shelter, then your pawn marches to mate.","Queen takes on g6 — the start of a forced mate."],"hr":["Crni kralj je zabarikadiran iza pješaka koje treba žrtvom ukloniti.","Žrtva dame otvara kraljev zaklon, a zatim tvoj pješak korača u mat.","Dama uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Bauern eingeschlossen, die sich sprengen lassen.","Ein Turmopfer reißt die Bauernfront auf, dann setzt deine Dame nach.","Turm nimmt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king is shut in behind his pawns, which can be blown open.","A rook sacrifice tears open the pawn front, then your queen follows up.","Rook takes on g7 — the start of a forced mate."],"hr":["Crni kralj je zatvoren iza svojih pješaka, koje se može razbiti.","Žrtva topa otvara pješačku frontu, a zatim tvoja dama nastavlja.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt an der Ecke und seine eigenen Bauern rauben ihm die Luft.","Ein Läuferopfer reißt die Königsstellung auf, dann gibt deine Dame den Todesstoß.","Läufer schlägt auf g2 – der Beginn eines erzwungenen Matts."],"en":["The white king is wedged into the corner and his own pawns smother him.","A bishop sacrifice tears open the shelter, then your queen finishes the job.","Bishop takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj je stisnut u kutu, a vlastiti pješaci mu oduzimaju zrak.","Žrtva lovca razbija zaklon, a zatim dama zadaje konačni udarac.","Lovac uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt am Rand und die Felder vor ihm sind durchlöchert.","Ein Läuferopfer zieht den König ins Freie, dann jagt deine Dame ihn nieder.","Läufer schlägt auf g6 – der Beginn eines erzwungenen Matts."],"en":["The black king is pinned to the edge and the squares around him are full of holes.","A bishop sacrifice drags the king out, then your queen runs him down.","Bishop takes on g6 — the start of a forced mate."],"hr":["Crni kralj je prikovan uz rub, a polja oko njega su puna rupa.","Žrtva lovca izvlači kralja, a zatim ga dama goni do kraja.","Lovac uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Bauern gefangen und die letzte Reihe ist verwundbar.","Ein Turmopfer öffnet die Stellung, dann dringen Turm und Dame entscheidend ein.","Turm schlägt auf g7 – der Beginn eines erzwungenen Matts."],"en":["The black king is trapped behind his pawns and the back rank is fragile.","A rook sacrifice cracks the position, then rook and queen break through.","Rook takes on g7 — the start of a forced mate."],"hr":["Crni kralj je zarobljen iza svojih pješaka, a zadnji red je ranjiv.","Žrtva topa razbija položaj, a zatim top i dama prodiru odlučujuće.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König hat fast keine Verteidiger und sein Rochadeschutz wackelt.","Ein Läuferopfer reißt die Bauern weg, dann erledigen Dame und Springer den Rest.","Läufer schlägt auf h7 – der Beginn eines erzwungenen Matts."],"en":["The black king has almost no defenders and his castled cover is crumbling.","A bishop sacrifice rips away the pawns, then queen and knight finish him.","Bishop takes on h7 — the start of a forced mate."],"hr":["Crni kralj nema gotovo nikakvih branitelja, a zaklon rošade se ruši.","Žrtva lovca otkida pješake, a zatim dama i skakač završavaju posao.","Lovac uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht ungeschützt im Zentrum und kann nirgends hin.","Ein Bauernopfer öffnet die Linie, dann übernehmen deine schweren Figuren.","Turm schlägt auf e6 – der Beginn eines erzwungenen Matts."],"en":["The black king stands exposed in the centre with nowhere to run.","A pawn sacrifice opens a line, then your heavy pieces take over.","Rook takes on e6 — the start of a forced mate."],"hr":["Crni kralj stoji nezaštićen u centru i nema kamo pobjeći.","Žrtva pješaka otvara liniju, a zatim teške figure preuzimaju vodstvo.","Top uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klemmt in der Ecke und seine Verteidiger sind überlastet.","Ein Springeropfer lenkt ab, dann brechen Turm und Dame zur Ecke durch.","Springer schlägt auf c6 – der Beginn eines erzwungenen Matts."],"en":["The black king is jammed in the corner and his defenders are overloaded.","A knight sacrifice deflects, then rook and queen break through to the corner.","Knight takes on c6 — the start of a forced mate."],"hr":["Crni kralj je stisnut u kutu, a njegovi branitelji su preopterećeni.","Žrtva skakača odvlači obranu, a zatim top i dama probijaju do kuta.","Skakač uzima na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht am Rand und seine letzte Reihe ist tödlich schwach.","Ein Turmopfer öffnet die Bahn, dann fällt das Matt auf der zweiten Reihe.","Turm schlägt auf b2 – der Beginn eines erzwungenen Matts."],"en":["The white king is on the edge and his back rank is fatally weak.","A rook sacrifice clears the way, then mate lands on the second rank.","Rook takes on b2 — the start of a forced mate."],"hr":["Bijeli kralj je na rubu, a njegov zadnji red je smrtonosno slab.","Žrtva topa raščišćava put, a zatim mat pada na drugom redu.","Top uzima na b2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und seine Bauern bieten kaum Schutz.","Ein Turmopfer reißt die Königsstellung auf, dann gibt der Springer das Matt.","Turm schlägt auf g7 – der Beginn eines erzwungenen Matts."],"en":["The black king clings to the edge and his pawns give little cover.","A rook sacrifice rips open the shelter, then the knight delivers mate.","Rook takes on g7 — the start of a forced mate."],"hr":["Crni kralj se drži uz rub, a pješaci mu pružaju slabu zaštitu.","Žrtva topa razbija zaklon, a zatim skakač zadaje mat.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Bauern eingeklemmt und die Diagonale ist offen.","Ein Damenopfer lockt den König heraus, dann gibt der Läufer das Matt.","Dame schlägt auf h6 – der Beginn eines erzwungenen Matts."],"en":["The black king is boxed in by his pawns and the diagonal lies open.","A queen sacrifice lures the king out, then the bishop delivers mate.","Queen takes on h6 — the start of a forced mate."],"hr":["Crni kralj je zatvoren vlastitim pješacima, a dijagonala je otvorena.","Žrtva dame mami kralja van, a zatim lovac zadaje mat.","Dama uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt am Rand und seine Bauerndeckung ist zerfetzt.","Ein Turmopfer öffnet die Stellung, dann liefern Turm und Dame das Matt.","Turm schlägt auf g6 – der Beginn eines erzwungenen Matts."],"en":["The black king sits on the edge with his pawn cover in tatters.","A rook sacrifice opens things up, then rook and queen combine for mate.","Rook takes on g6 — the start of a forced mate."],"hr":["Crni kralj sjedi na rubu, a pješačka zaštita mu je razderana.","Žrtva topa otvara položaj, a zatim top i dama zajedno daju mat.","Top uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist am Rand und seine Bauernkette wird zur Falle.","Ein Damenopfer reißt die Deckung weg, dann schlägt ein Bauer entscheidend ein.","Dame schlägt auf g3 – der Beginn eines erzwungenen Matts."],"en":["The white king is on the edge and his pawn chain becomes a trap.","A queen sacrifice tears away the cover, then a pawn strikes decisively.","Queen takes on g3 — the start of a forced mate."],"hr":["Bijeli kralj je na rubu, a njegov lanac pješaka postaje zamka.","Žrtva dame otkida obranu, a zatim pješak udara odlučujuće.","Dama uzima na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird an den Rand getrieben und seine Verteidiger geben nach.","Ein Turmopfer öffnet die Bahn, dann jagen Dame und Turm den König nieder.","Turm schlägt auf g6 – der Beginn eines erzwungenen Matts."],"en":["The black king is forced to the edge as his defenders give way.","A rook sacrifice clears the path, then queen and rook hunt the king down.","Rook takes on g6 — the start of a forced mate."],"hr":["Crni kralj je potjeran na rub dok mu branitelji popuštaju.","Žrtva topa raščišćava put, a zatim dama i top love kralja.","Top uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
