UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Bauern gefangen und die Reihen sind offen.","Ein Turmopfer zieht den König weg, dann dringen Dame und Springer ein.","Turm schlägt auf e7 – der Beginn eines erzwungenen Matts."],"en":["The black king is trapped behind his pawns and the ranks lie open.","A rook sacrifice pulls the king away, then queen and knight invade.","Rook takes on e7 — the start of a forced mate."],"hr":["Crni kralj je zarobljen iza svojih pješaka, a redovi su otvoreni.","Žrtva topa odvlači kralja, a zatim dama i skakač prodiru.","Top uzima na e7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt in der Ecke und seine Randbauern fesseln ihn.","Ein Turmopfer reißt die Stellung auf, dann verfolgen Türme und Dame den König.","Turm schlägt auf h6 – der Beginn eines erzwungenen Matts."],"en":["The black king sits in the corner with his edge pawns hemming him in.","A rook sacrifice rips the position open, then rooks and queen chase the king.","Rook takes on h6 — the start of a forced mate."],"hr":["Crni kralj sjedi u kutu, a rubni pješaci ga sputavaju.","Žrtva topa razbija položaj, a zatim topovi i dama gone kralja.","Top uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an den Rand gedrängt und seine Figuren stehen abseits.","Ein Turmopfer treibt den König ins Freie, dann jagen Türme und Dame ihn nieder.","Turm schlägt auf g6 – der Beginn eines erzwungenen Matts."],"en":["The black king is pushed to the edge with his pieces standing aside.","A rook sacrifice drives the king into the open, then rooks and queen run him down.","Rook takes on g6 — the start of a forced mate."],"hr":["Crni kralj je potjeran na rub, a njegove figure stoje sa strane.","Žrtva topa goni kralja u otvoreno, a zatim ga topovi i dama love.","Top uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.024' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
