UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke und seine Deckung ist im Zugzwang.","Ein Turmopfer zieht den König heraus, dann jagen Dame und Läufer ihn nieder.","Turm schlägt auf h7 – der Beginn eines erzwungenen Matts."],"en":["The black king clings to the corner and his cover runs out of moves.","A rook sacrifice pulls the king out, then queen and bishop chase him down.","Rook takes on h7 — the start of a forced mate."],"hr":["Crni kralj se drži u kutu, a njegova obrana ostaje bez poteza.","Žrtva topa izvlači kralja, a zatim ga dama i lovac gone.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.027' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
