UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Bauern eingeklemmt und überlastet verteidigt.","Ein Turmopfer öffnet die Stellung, dann brechen Springer und Dame durch.","Turm schlägt auf g7 – der Beginn eines erzwungenen Matts."],"en":["The black king is wedged behind his pawns and defended by overloaded pieces.","A rook sacrifice opens the position, then knight and queen break through.","Rook takes on g7 — the start of a forced mate."],"hr":["Crni kralj je stisnut iza pješaka i branjen preopterećenim figurama.","Žrtva topa otvara položaj, a zatim skakač i dama probijaju.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.031' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
