UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an den Rand gedrängt und die Linie zu ihm öffnet sich.","Ein Damenmanöver bereitet alles vor, dann reißt ein Turmschlag die Deckung weg.","Turm zieht nach h3 – der Beginn eines erzwungenen Matts."],"en":["The black king is pushed to the edge and the file towards him is opening.","A queen manoeuvre sets things up, then a rook strike tears away the cover.","Rook to h3 — the start of a forced mate."],"hr":["Crni kralj je potjeran na rub, a linija prema njemu se otvara.","Manevar dame sve priprema, a zatim udar topa otkida obranu.","Top na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.034' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und seine Bauern sind morsch.","Ein Läuferopfer reißt die Deckung auf, dann jagt deine Dame den König nieder.","Läufer schlägt auf h5 – der Beginn eines erzwungenen Matts."],"en":["The black king clings to the edge and his pawns are rotten.","A bishop sacrifice rips open the cover, then your queen runs the king down.","Bishop takes on h5 — the start of a forced mate."],"hr":["Crni kralj se drži uz rub, a njegovi pješaci su trošni.","Žrtva lovca razbija obranu, a zatim dama goni kralja.","Lovac uzima na h5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.035' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt am Rand und seine Verteidiger sind überlastet.","Ein Turmopfer lenkt einen Verteidiger ab, dann brechen Dame und Türme durch.","Turm schlägt auf g6 – der Beginn eines erzwungenen Matts."],"en":["The black king sits on the edge and his defenders are overloaded.","A rook sacrifice deflects a defender, then queen and rooks break through.","Rook takes on g6 — the start of a forced mate."],"hr":["Crni kralj sjedi na rubu, a njegovi branitelji su preopterećeni.","Žrtva topa odvlači branitelja, a zatim dama i topovi probijaju.","Top uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.036' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht ungeschützt im Zentrum und ist von Feldern umstellt.","Ein Turmopfer lenkt einen Verteidiger ab, dann jagen Dame und Springer den König.","Turm schlägt auf c6 – der Beginn eines erzwungenen Matts."],"en":["The black king stands exposed in the centre, ringed by covered squares.","A rook sacrifice deflects a defender, then queen and knight hunt the king.","Rook takes on c6 — the start of a forced mate."],"hr":["Crni kralj stoji nezaštićen u centru, okružen pokrivenim poljima.","Žrtva topa odvlači branitelja, a zatim ga dama i skakač love.","Top uzima na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.037' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist im Zentrum gefangen und seine Verteidiger sind überlastet.","Ein Turmopfer lenkt einen Verteidiger ab, dann brechen Dame und Läufer durch.","Turm schlägt auf f7 – der Beginn eines erzwungenen Matts."],"en":["The black king is caught in the centre and his defenders are overloaded.","A rook sacrifice deflects a defender, then queen and bishop break through.","Rook takes on f7 — the start of a forced mate."],"hr":["Crni kralj je zarobljen u centru, a njegovi branitelji su preopterećeni.","Žrtva topa odvlači branitelja, a zatim dama i lovac probijaju.","Top uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.038' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Rochadestellung ist bereits aufgerissen und der König steht ungeschützt da.","Ein Damenopfer reißt die Bauerndeckung ein, dann setzt eine Figur auf der Diagonale matt.","Die Dame schlägt auf h6 und leitet ein erzwungenes Matt ein."],"en":["Black''s castled position is already torn open and the king stands exposed.","A queen sacrifice rips away the pawn cover, then a piece mates along the diagonal.","Queen takes on h6, starting a forced mate."],"hr":["Crna rošada je već razbijena i kralj stoji nezaštićen.","Žrtva dame ruši pješačku zaštitu, a zatim figura matira po dijagonali.","Dama uzima na h6 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.039' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke eingeklemmt und kann der Annäherung nicht entkommen.","Mit Opfern lockst du die Verteidiger weg, dann gibt deine Dame das Matt aus der Nähe.","Der Läufer schlägt auf d4 und startet ein erzwungenes Matt."],"en":["The white king is boxed into the corner and cannot escape the closing net.","Sacrifices peel away the defenders, then your queen mates from close range.","Bishop takes on d4, beginning a forced mate."],"hr":["Bijeli kralj je stiješnjen u kutu i ne može pobjeći stezanju mreže.","Žrtvama odvlačiš branitelje, a zatim tvoja dama matira iz blizine.","Lovac uzima na d4 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.040' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht entblößt in der Brettmitte und die Linien gegen ihn öffnen sich.","Ein Damenopfer und ein Läufer treiben den König ins Verderben, geführt von deinen Schwerfiguren.","Die Dame schlägt auf d7 und leitet ein erzwungenes Matt ein."],"en":["The black king sits exposed in the centre with lines opening against him.","A queen offer and a bishop drive the king to ruin, led by your heavy pieces.","Queen takes on d7, starting a forced mate."],"hr":["Crni kralj stoji izložen u sredini dok se linije protiv njega otvaraju.","Žrtva dame i lovac tjeraju kralja u propast, predvođeni teškim figurama.","Dama uzima na d7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.041' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Königsstellung lässt sich durch Opfer auf den Schutzfeldern aufbrechen.","Zwei Schwerfiguren werden geopfert, dann erledigt deine Dame den entblößten König.","Der Turm schlägt auf g7 und startet ein erzwungenes Matt."],"en":["Black''s king shelter can be blown open by sacrifices on its guarding squares.","Two heavy pieces are given up, then your queen finishes the bared king.","Rook takes on g7, beginning a forced mate."],"hr":["Crnu kraljevu zaštitu možeš razbiti žrtvama na poljima koja je čuvaju.","Dvije teške figure se žrtvuju, a zatim tvoja dama dokrajči ogoljenog kralja.","Top uzima na g7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.042' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird Schritt für Schritt aus seiner Deckung getrieben.","Ein Turmopfer öffnet die Tür, dann jagen Dame und Turm den König zum Matt.","Der Turm schlägt auf g7 und leitet ein erzwungenes Matt ein."],"en":["The black king is driven from its shelter step by step.","A rook sacrifice opens the door, then queen and rook hunt the king to mate.","Rook takes on g7, starting a forced mate."],"hr":["Crni kralj se korak po korak istjeruje iz svoje zaštite.","Žrtva topa otvara vrata, a zatim dama i top love kralja do mata.","Top uzima na g7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.043' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Bauerndeckung des schwarzen Königs lässt sich durch ein Läuferopfer beseitigen.","Nach dem Opfer auf dem Randfeld führt deine Dame den klassischen Mattangriff.","Der Läufer schlägt auf h7 und startet ein erzwungenes Matt."],"en":["The black king''s pawn cover can be removed by a bishop sacrifice.","After the offer on the edge square your queen leads the classic mating attack.","Bishop takes on h7, beginning a forced mate."],"hr":["Pješačku zaštitu crnog kralja možeš ukloniti žrtvom lovca.","Nakon žrtve na rubnom polju tvoja dama vodi klasični matni napad.","Lovac uzima na h7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.044' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König lässt sich durch ein Läuferopfer aus seinem Bunker zerren.","Springer und Dame greifen nach, dann fällt der König dem Mattangriff zum Opfer.","Der Läufer schlägt auf h7 und leitet ein erzwungenes Matt ein."],"en":["The black king can be dragged from his bunker by a bishop sacrifice.","Knight and queen pile in, then the king succumbs to the mating attack.","Bishop takes on h7, starting a forced mate."],"hr":["Crnog kralja možeš izvući iz njegova skloništa žrtvom lovca.","Skakač i dama se uključuju, a zatim kralj podliježe matnom napadu.","Lovac uzima na h7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.045' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch eine Serie von Opfern aus seiner Deckung gerissen.","Mehrere Figuren werden geopfert, bis Springer und Dame den König einkesseln.","Der Läufer schlägt auf h7 und startet ein erzwungenes Matt."],"en":["The black king is ripped from his cover by a series of sacrifices.","Several pieces are given up until knight and queen trap the king.","Bishop takes on h7, beginning a forced mate."],"hr":["Crni kralj se nizom žrtava istrgne iz svoje zaštite.","Više figura se žrtvuje dok skakač i dama ne zatvore kralja.","Lovac uzima na h7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.046' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird quer über das Brett ins offene Feld getrieben.","Ein Turmopfer eröffnet die Jagd, dann hetzen Dame und Turm den König zum Matt.","Der Turm schlägt auf a5 und leitet ein erzwungenes Matt ein."],"en":["The white king is hounded right across the board into the open.","A rook sacrifice opens the chase, then queen and rook drive the king to mate.","Rook takes on a5, starting a forced mate."],"hr":["Bijeli kralj se progoni preko cijele ploče na otvoreno.","Žrtva topa otvara lov, a zatim dama i top tjeraju kralja do mata.","Top uzima na a5 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.047' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung wird durch Opfer auf den Schutzfeldern aufgerissen.","Turm und Läufer werden hingegeben, dann setzt deine Dame an der Linie matt.","Der Turm schlägt auf g7 und startet ein erzwungenes Matt."],"en":["The white king''s shelter is torn open by sacrifices on its guarding squares.","Rook and bishop are surrendered, then your queen mates along the file.","Rook takes on g7, beginning a forced mate."],"hr":["Bijelu kraljevu zaštitu razbijaš žrtvama na poljima koja je čuvaju.","Top i lovac se žrtvuju, a zatim tvoja dama matira po liniji.","Top uzima na g7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.048' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Bauerndeckung des schwarzen Königs lässt sich mit einem Läuferopfer entfernen.","Nach dem Randopfer ziehen Dame, Läufer und Springer den Mattangriff zusammen.","Der Läufer schlägt auf h7 und leitet ein erzwungenes Matt ein."],"en":["The black king''s pawn cover can be removed with a bishop sacrifice.","After the edge offer queen, bishop and knight combine for the mating attack.","Bishop takes on h7, starting a forced mate."],"hr":["Pješačku zaštitu crnog kralja možeš ukloniti žrtvom lovca.","Nakon rubne žrtve dama, lovac i skakač spajaju snage u matnom napadu.","Lovac uzima na h7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.049' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch Opfer aus seiner zentralen Deckung gelockt.","Springer und Dame öffnen die Stellung, dann fällt der König dem Angriff zum Opfer.","Der Springer schlägt auf e6 und startet ein erzwungenes Matt."],"en":["The black king is lured out of his central cover by sacrifices.","Knight and queen open the position, then the king falls to the attack.","Knight takes on e6, beginning a forced mate."],"hr":["Crnog kralja izmamljuješ iz njegove središnje zaštite žrtvama.","Skakač i dama otvaraju poziciju, a zatim kralj pada pod napadom.","Skakač uzima na e6 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.050' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke gefangen und die Deckung wird Stück für Stück zerstört.","Springer und Turm werden geopfert, dann erzwingt deine Dame das Matt am Rand.","Der Springer schlägt auf g3 und leitet ein erzwungenes Matt ein."],"en":["The white king is trapped in the corner and its cover is dismantled piece by piece.","Knight and rook are sacrificed, then your queen forces mate on the edge.","Knight takes on g3, starting a forced mate."],"hr":["Bijeli kralj je zarobljen u kutu i njegova se zaštita ruši dio po dio.","Skakač i top se žrtvuju, a zatim tvoja dama prisiljava mat na rubu.","Skakač uzima na g3 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.051' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die offene Linie zum schwarzen König lädt zu einem zerstörerischen Opfer ein.","Ein Turmopfer öffnet die Linie, dann dringt der zweite Turm zum Matt durch.","Der Turm schlägt auf h8 und leitet ein erzwungenes Matt ein."],"en":["The open file to the black king invites a destructive sacrifice.","A rook sacrifice opens the file, then the second rook crashes through to mate.","Rook takes on h8, starting a forced mate."],"hr":["Otvorena linija prema crnom kralju poziva na razornu žrtvu.","Žrtva topa otvara liniju, a zatim drugi top prodire do mata.","Top uzima na h8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Auf der offenen Linie steht der schwarze König schutzlos der Wucht deiner Figuren gegenüber.","Ein Turmopfer reißt die Deckung weg, dann setzt deine Dame in der Ecke matt.","Der Turm schlägt auf h8 und leitet ein erzwungenes Matt ein."],"en":["On the open file the black king faces the force of your pieces unguarded.","A rook sacrifice removes the cover, then your queen mates in the corner.","Rook takes on h8, starting a forced mate."],"hr":["Na otvorenoj liniji crni kralj nezaštićen dočekuje snagu tvojih figura.","Žrtva topa uklanja zaštitu, a zatim tvoja dama matira u kutu.","Top uzima na h8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Bauerndeckung des schwarzen Königs lässt sich durch ein Opfer wegräumen.","Nach dem Turmopfer dringt deine Dame über die offene Linie zum Matt vor.","Der Turm schlägt auf h6 und leitet ein erzwungenes Matt ein."],"en":["The black king''s pawn cover can be cleared away by a sacrifice.","After the rook offer your queen breaks through the open file to mate.","Rook takes on h6, starting a forced mate."],"hr":["Pješačku zaštitu crnog kralja možeš ukloniti žrtvom.","Nakon žrtve topa tvoja dama prodire otvorenom linijom do mata.","Top uzima na h6 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und ein verlockendes Opfer öffnet die Linie.","Nach dem Damenopfer fährt ein Turm auf der freien Linie zum Matt herab.","Die Dame schlägt auf h8 und leitet ein erzwungenes Matt ein."],"en":["The black king clings to the edge and a tempting sacrifice opens the file.","After the queen offer a rook sweeps down the open file to mate.","Queen takes on h8, starting a forced mate."],"hr":["Crni kralj se drži ruba, a primamljiva žrtva otvara liniju.","Nakon žrtve dame top juri otvorenom linijom do mata.","Dama uzima na h8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König findet auf der offenen Linie und am Rand kein sicheres Feld.","Ein Turm dringt mit Damenunterstützung über die Linie zum entscheidenden Schlag durch.","Der Turm schlägt auf h7 und leitet ein erzwungenes Matt ein."],"en":["The black king finds no safe square on the open file or the edge.","A rook crashes through the file with queen support for the decisive blow.","Rook takes on h7, starting a forced mate."],"hr":["Crni kralj ne nalazi sigurno polje ni na otvorenoj liniji ni na rubu.","Top uz potporu dame prodire po liniji do odlučujućeg udarca.","Top uzima na h7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die offene Linie zum schwarzen König wird durch ein Vorbereitungsopfer freigelegt.","Nach dem Damenopfer übernehmen deine Türme die Linie und setzen matt.","Die Dame schlägt auf g6 und leitet ein erzwungenes Matt ein."],"en":["The open file to the black king is cleared by a preparatory sacrifice.","After the queen offer your rooks seize the file and deliver mate.","Queen takes on g6, starting a forced mate."],"hr":["Otvorenu liniju prema crnom kralju otvara pripremna žrtva.","Nakon žrtve dame tvoji topovi preuzimaju liniju i daju mat.","Dama uzima na g6 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die offene Linie zum schwarzen König lädt zu einem Eröffnungsopfer ein.","Ein Turmopfer reißt die Linie auf, dann führt die Dame den Mattstoß.","Der Turm schlägt auf h8 und leitet ein erzwungenes Matt ein."],"en":["The open file to the black king invites an opening sacrifice.","A rook sacrifice tears the file open, then the queen delivers the mating thrust.","Rook takes on h8, starting a forced mate."],"hr":["Otvorena linija prema crnom kralju poziva na uvodnu žrtvu.","Žrtva topa otvara liniju, a zatim dama izvodi matni udarac.","Top uzima na h8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird durch ein Damenopfer aus seiner Deckung gezogen.","Nach dem Opfer rückt ein Turm auf der Linie zum entscheidenden Matt vor.","Die Dame schlägt auf h2 und leitet ein erzwungenes Matt ein."],"en":["The white king is pulled from his cover by a queen sacrifice.","After the offer a rook advances down the file for the decisive mate.","Queen takes on h2, starting a forced mate."],"hr":["Bijelog kralja izvlačiš iz njegove zaštite žrtvom dame.","Nakon žrtve top napreduje po liniji do odlučujućeg mata.","Dama uzima na h2 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König lässt sich durch ein Turmopfer auf das offene Feld zwingen.","Nach dem Opfer dringt deine Dame über die Linie zum Matt vor.","Der Turm schlägt auf h2 und leitet ein erzwungenes Matt ein."],"en":["The white king can be forced into the open by a rook sacrifice.","After the offer your queen breaks through the file to mate.","Rook takes on h2, starting a forced mate."],"hr":["Bijelog kralja možeš žrtvom topa prisiliti na otvoreno.","Nakon žrtve tvoja dama prodire po liniji do mata.","Top uzima na h2 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Deckung des schwarzen Königs am Rand wird durch Opfer abgetragen.","Türme werden auf der Linie geopfert, dann setzt deine Dame matt.","Der Turm schlägt auf h7 und leitet ein erzwungenes Matt ein."],"en":["The black king''s cover on the edge is stripped away by sacrifices.","Rooks are given up on the file, then your queen delivers mate.","Rook takes on h7, starting a forced mate."],"hr":["Zaštita crnog kralja na rubu skida se žrtvama.","Topovi se žrtvuju po liniji, a zatim tvoja dama daje mat.","Top uzima na h7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die offene Linie zum schwarzen König lädt zu einem doppelten Turmopfer ein.","Nach den Opfern auf der Linie liefert ein Springer den letzten Stoß.","Der Turm schlägt auf h8 und leitet ein erzwungenes Matt ein."],"en":["The open file to the black king invites a double rook sacrifice.","After the offers on the file a knight delivers the final blow.","Rook takes on h8, starting a forced mate."],"hr":["Otvorena linija prema crnom kralju poziva na dvostruku žrtvu topa.","Nakon žrtava po liniji skakač zadaje posljednji udarac.","Top uzima na h8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die offene Linie zum schwarzen König erlaubt einen zerstörerischen Einbruch.","Ein Turmopfer reißt die Linie auf, dann setzt deine Dame am Rand matt.","Der Turm schlägt auf h8 und leitet ein erzwungenes Matt ein."],"en":["The open file to the black king allows a destructive breakthrough.","A rook sacrifice tears the file open, then your queen mates on the edge.","Rook takes on h8, starting a forced mate."],"hr":["Otvorena linija prema crnom kralju omogućuje razoran proboj.","Žrtva topa otvara liniju, a zatim tvoja dama matira na rubu.","Top uzima na h8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird auf der offenen Linie zur Zielscheibe deiner Türme.","Türme verdoppeln auf der Linie und brechen mit Opfer zum Matt durch.","Der Turm schlägt auf h8 und leitet ein erzwungenes Matt ein."],"en":["The white king becomes the target of your rooks on the open file.","Rooks double on the file and break through with a sacrifice to mate.","Rook takes on h8, starting a forced mate."],"hr":["Bijeli kralj postaje meta tvojih topova na otvorenoj liniji.","Topovi se udvostručuju po liniji i žrtvom probijaju do mata.","Top uzima na h8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Linie zum schwarzen König öffnet sich durch ein verlockendes Turmopfer.","Nach dem Opfer treiben Dame und der zweite Turm den König zum Matt.","Der Turm schlägt auf h7 und leitet ein erzwungenes Matt ein."],"en":["The file to the black king opens with a tempting rook sacrifice.","After the offer queen and the second rook drive the king to mate.","Rook takes on h7, starting a forced mate."],"hr":["Linija prema crnom kralju otvara se primamljivom žrtvom topa.","Nakon žrtve dama i drugi top tjeraju kralja do mata.","Top uzima na h7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird durch ein Damenopfer aus seiner Deckung gerissen.","Nach dem Opfer dringt ein Turm über die Linie zum entscheidenden Matt vor.","Die Dame schlägt auf h3 und leitet ein erzwungenes Matt ein."],"en":["The white king is torn from his cover by a queen sacrifice.","After the offer a rook breaks through the file for the decisive mate.","Queen takes on h3, starting a forced mate."],"hr":["Bijelog kralja istrgneš iz njegove zaštite žrtvom dame.","Nakon žrtve top prodire po liniji do odlučujućeg mata.","Dama uzima na h3 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird durch ein Turmopfer in die Ecke gezwungen.","Nach dem Opfer treiben Dame und Läufer den König zum Matt am Rand.","Der Turm schlägt auf a1 und leitet ein erzwungenes Matt ein."],"en":["The white king is forced into the corner by a rook sacrifice.","After the offer queen and bishop drive the king to mate on the edge.","Rook takes on a1, starting a forced mate."],"hr":["Bijeli kralj se žrtvom topa prisiljava u kut.","Nakon žrtve dama i lovac tjeraju kralja do mata na rubu.","Top uzima na a1 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Deckung des schwarzen Königs am Rand lässt sich durch Opfer auflösen.","Ein Springer und ein Turm werden hingegeben, dann setzt deine Dame matt.","Der Springer schlägt auf h7 und leitet ein erzwungenes Matt ein."],"en":["The black king''s cover on the edge can be dissolved by sacrifices.","A knight and a rook are surrendered, then your queen delivers mate.","Knight takes on h7, starting a forced mate."],"hr":["Zaštitu crnog kralja na rubu možeš razbiti žrtvama.","Skakač i top se žrtvuju, a zatim tvoja dama daje mat.","Skakač uzima na h7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt hinter seiner Bauernkette fest, und ein Opfer reißt die Deckung auf.","Ein Turmopfer auf der Randlinie lockt den König weg, dann setzt die Dame matt.","Turm schlägt auf h8 – Beginn eines erzwungenen Matts."],"en":["The black king is hemmed in behind his pawns, and a sacrifice tears open his cover.","A rook sacrifice on the edge file drags the king away, then the queen mates.","Rook takes on h8 — the start of a forced mate."],"hr":["Crni kralj je zatočen iza svojih pješaka, a žrtva razbija zaklon.","Žrtva topa na rubnoj liniji odvlači kralja, a zatim dama daje mat.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand wird Stein für Stein freigelegt und von schweren Figuren verfolgt.","Ein Damenopfer auf der Randlinie eröffnet die Jagd, Türme treiben den König ins Matt.","Dame schlägt auf h7 – der Auftakt zu erzwungenem Matt."],"en":["The cornered king is stripped bare and hunted down by the heavy pieces.","A queen sacrifice on the edge file opens the chase, and the rooks force mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Kralj u kutu ostaje bez zaklona i progone ga teške figure.","Žrtva dame na rubnoj liniji otvara lov, a topovi tjeraju u mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird über offene Linien gezogen, sein Läufer ist überlastet.","Ein Turmopfer beseitigt den Verteidiger, dann jagen Dame und Läufer den König.","Turm schlägt auf h8 – Beginn eines erzwungenen Matts."],"en":["The black king is dragged across open lines while his bishop is overloaded.","A rook sacrifice removes the defender, then queen and bishop hunt the king.","Rook takes on h8 — the start of a forced mate."],"hr":["Crni kralj se izvlači po otvorenim linijama, a lovac mu je preopterećen.","Žrtva topa uklanja branitelja, a zatim dama i lovac progone kralja.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand ist nach einem Bauernsturm fast schutzlos.","Ein Damenopfer auf der Randlinie zieht den Verteidiger heran, dann schlägt der Turm zu.","Dame schlägt auf h7 – der Beginn eines erzwungenen Matts."],"en":["The king on the edge is nearly defenceless after a pawn storm.","A queen sacrifice on the edge file draws a defender, then the rook strikes.","Queen takes on h7 — the start of a forced mate."],"hr":["Kralj na rubu gotovo je bez zaštite nakon pješačke oluje.","Žrtva dame na rubnoj liniji privlači branitelja, a zatim top udara.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der eingeschlossene König wird über die Randlinie ins Freie und ins Verderben gelockt.","Ein Turmopfer öffnet die Linie, der zweite Turm vollendet die Jagd.","Turm schlägt auf h8 – Auftakt zu erzwungenem Matt."],"en":["The boxed-in king is lured out along the edge file to his doom.","A rook sacrifice opens the file and the second rook finishes the hunt.","Rook takes on h8 — the start of a forced mate."],"hr":["Zatvoreni kralj se po rubnoj liniji izvlači u propast.","Žrtva topa otvara liniju, a drugi top dovršava lov.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.024' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König in der Ecke ist eingeengt, ein zweites Opfer entscheidet.","Ein Damenopfer lockt den König heraus, dann setzt der zweite Turm matt.","Dame schlägt auf h8 – Beginn eines erzwungenen Matts."],"en":["The king in the corner is cramped, and a second sacrifice decides.","A queen sacrifice lures the king out, then the second rook mates.","Queen takes on h8 — the start of a forced mate."],"hr":["Kralj u kutu je stiješnjen, a druga žrtva odlučuje.","Žrtva dame izvlači kralja, a zatim drugi top daje mat.","Dama uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.025' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steckt in der Ecke, seine Grundreihe ist tödlich schwach.","Ein Damenopfer reißt den deckenden König weg, dann entscheidet eine ferne Figur.","Dame schlägt auf h1 – der Auftakt zu erzwungenem Matt."],"en":["The white king is stuck in the corner with a fatally weak back rank.","A queen sacrifice tears away the guarding king, then a distant piece decides.","Queen takes on h1 — the start of a forced mate."],"hr":["Bijeli kralj je zaglavljen u kutu s kobno slabim zadnjim redom.","Žrtva dame odvlači kralja branitelja, a zatim udaljena figura odlučuje.","Dama uzima na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.026' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter dünner Deckung gefangen, eine Figur lenkt ab.","Ein Turm lenkt den feindlichen Läufer ab, dann bricht die Dame durch.","Turm nach h3 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped behind thin cover while a piece is deflected.","A rook deflects the enemy bishop, then the queen crashes through.","Rook to h3 — the start of a forced mate."],"hr":["Crni kralj je zarobljen iza tanke zaštite dok se figura odvlači.","Top odvlači protivničkog lovca, a zatim dama probija.","Top na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.027' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke eingemauert, ein Opfer öffnet die Linie.","Eine Dame opfert sich, um die Randlinie für den Turm zu öffnen.","Dame schlägt auf g7 – der Beginn eines erzwungenen Matts."],"en":["The black king is walled into the corner, and a sacrifice opens the lane.","A queen sacrifice clears the way so the rook can deliver mate.","Queen takes on g7 — the start of a forced mate."],"hr":["Crni kralj je uzidan u kut, a žrtva otvara liniju.","Žrtva dame raščišćava put da top da mat.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.028' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand wird durch ein Doppelopfer entblößt und gejagt.","Erst opfert die Dame, dann der Turm, schließlich gibt der Springer den Todesstoß.","Dame schlägt auf h8 – Auftakt zu erzwungenem Matt."],"en":["The king on the edge is laid bare and hunted by a double sacrifice.","Queen then rook are given up, and finally the knight strikes the blow.","Queen takes on h8 — the start of a forced mate."],"hr":["Kralj na rubu biva ogoljen i progonjen dvostrukom žrtvom.","Najprije dama, pa top, a na kraju skakač zadaje udarac.","Dama uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.029' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird über die Randlinie ins Freie gezwungen.","Ein Turmopfer und die nachrückende Dame jagen den König unaufhaltsam.","Turm schlägt auf h8 – der Beginn eines erzwungenen Matts."],"en":["The black king is forced out into the open along the edge file.","A rook sacrifice and the trailing queen hunt the king relentlessly.","Rook takes on h8 — the start of a forced mate."],"hr":["Crni kralj se po rubnoj liniji tjera na otvoreno.","Žrtva topa i dama koja slijedi neumoljivo progone kralja.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.030' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird auf der Randlinie aufgerollt und festgenagelt.","Ein Turmopfer öffnet die Linie, Dame und Bauer treiben den König ins Matt.","Turm schlägt auf h8 – Auftakt zu erzwungenem Matt."],"en":["The black king is rolled up and pinned down on the edge file.","A rook sacrifice opens the file; queen and pawn force the king into mate.","Rook takes on h8 — the start of a forced mate."],"hr":["Crni kralj biva razvaljen i prikovan na rubnoj liniji.","Žrtva topa otvara liniju; dama i pješak tjeraju kralja u mat.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.031' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand ist eingeklemmt, seine Deckung wird systematisch zerlegt.","Ein Turmopfer reißt eine Linie auf, dann setzen Turm und Läufer matt.","Turm schlägt auf h7 – der Beginn eines erzwungenen Matts."],"en":["The cornered king is jammed in as his cover is taken apart piece by piece.","A rook sacrifice rips open a file, then rook and bishop combine to mate.","Rook takes on h7 — the start of a forced mate."],"hr":["Kralj u kutu je stiješnjen dok mu se zaklon razbija dio po dio.","Žrtva topa otvara liniju, a zatim top i lovac daju mat.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.032' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht ungeschützt am Rand und wird über offene Linien gefangen.","Ein Turm lockt den König heran, dann schließen die schweren Figuren das Netz.","Turm nach h1 – Auftakt zu erzwungenem Matt."],"en":["The black king stands exposed on the edge, caught along the open lines.","A rook draws the king forward, then the heavy pieces close the net.","Rook to h1 — the start of a forced mate."],"hr":["Crni kralj stoji nezaštićen na rubu, uhvaćen po otvorenim linijama.","Top privlači kralja, a zatim teške figure zatvaraju mrežu.","Top na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.033' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König in der Ecke ist tödlich eingeengt, eine Figur lenkt ihn ab.","Ein Turm lockt den König in die Ecke, dann setzen Springer und Dame matt.","Turm schlägt auf h2 – der Beginn eines erzwungenen Matts."],"en":["The white king in the corner is fatally cramped while a piece deflects him.","A rook lures the king into the corner, then knight and queen deliver mate.","Rook takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj u kutu je kobno stiješnjen dok ga figura odvlači.","Top mami kralja u kut, a zatim skakač i dama daju mat.","Top uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.034' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird Schritt für Schritt zur Seite getrieben.","Ein Turmopfer und die zupackende Dame jagen den König ins Matt.","Turm schlägt auf h7 – Auftakt zu erzwungenem Matt."],"en":["The black king on the edge is driven sideways step by step.","A rook sacrifice and the lunging queen chase the king into mate.","Rook takes on h7 — the start of a forced mate."],"hr":["Crni kralj na rubu se korak po korak tjera u stranu.","Žrtva topa i dama koja navaljuje tjeraju kralja u mat.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.035' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König in der Ecke ist eingeschlossen, sein Verteidiger wird abgelenkt.","Ein Läuferopfer öffnet die Linie, dann holen Turm und König-Verfolgung das Matt.","Läufer schlägt auf h2 – der Beginn eines erzwungenen Matts."],"en":["The white king is shut in the corner while his defender is pulled away.","A bishop sacrifice opens the lane, then the rook joins to seal the mate.","Bishop takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj je zatvoren u kutu dok mu se branitelj odvlači.","Žrtva lovca otvara liniju, a zatim se top pridružuje za mat.","Lovac uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.036' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist auf engem Raum gefangen, ein Doppelopfer reißt alles auf.","Erst opfert die Dame, dann der Turm, ehe die Leichtfiguren das Matt vollenden.","Dame schlägt auf h2 – Auftakt zu erzwungenem Matt."],"en":["The white king is trapped in a tight space as a double sacrifice tears it open.","Queen then rook are given up before the minor pieces finish the mate.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj je zarobljen u tijesnom prostoru dok dvostruka žrtva sve otvara.","Najprije dama, pa top, prije nego lake figure dovrše mat.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.037' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist ungedeckt, ein stiller Bauernzug stellt das tödliche Netz.","Ein vorrückender Bauer droht entscheidend, dann fängt die Dame den König.","Bauer nach f3 – der Beginn eines erzwungenen Matts."],"en":["The white king is bare, and a quiet pawn move sets the killing net.","An advancing pawn creates a decisive threat, then the queen snares the king.","Pawn to f3 — the start of a forced mate."],"hr":["Bijeli kralj je nezaštićen, a tih potez pješaka postavlja smrtonosnu mrežu.","Pješak koji napreduje stvara odlučujuću prijetnju, a zatim dama hvata kralja.","Pješak na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.038' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird über die Randlinie aus seiner Stellung gezerrt.","Ein Turm dringt über die offene Linie ein und treibt den König ins Matt.","Turm nach h3 – Auftakt zu erzwungenem Matt."],"en":["The black king is dragged out of position along the edge file.","A rook breaks in down the open file and herds the king into mate.","Rook to h3 — the start of a forced mate."],"hr":["Crni kralj se po rubnoj liniji izvlači iz svoje pozicije.","Top prodire po otvorenoj liniji i tjera kralja u mat.","Top na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.039' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch wiederholte Opfer entblößt und gejagt.","Ein Damenopfer eröffnet die Jagd, dann übernehmen die Türme das Matt.","Dame schlägt auf h8 – der Beginn eines erzwungenen Matts."],"en":["The black king on the edge is stripped and hunted by repeated sacrifices.","A queen sacrifice opens the chase, then the rooks take over the mate.","Queen takes on h8 — the start of a forced mate."],"hr":["Crni kralj na rubu biva ogoljen i progonjen uzastopnim žrtvama.","Žrtva dame otvara lov, a zatim topovi preuzimaju mat.","Dama uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.040' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch eine Kette von Opfern aufgerieben.","Ein Damenopfer reißt die Deckung auf, dann jagen die Türme den König.","Dame schlägt auf g6 – Auftakt zu erzwungenem Matt."],"en":["The black king on the edge is worn down by a chain of sacrifices.","A queen sacrifice rips open the cover, then the rooks hunt the king.","Queen takes on g6 — the start of a forced mate."],"hr":["Crni kralj na rubu biva izmoren nizom žrtava.","Žrtva dame razbija zaklon, a zatim topovi progone kralja.","Dama uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.041' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch leise Drohungen und Opfer eingekreist.","Ein stiller Damenzug bereitet das Opfer vor, das den König freilegt.","Dame nach h5 – der Beginn eines erzwungenen Matts."],"en":["The black king is encircled by quiet threats and a sacrifice.","A quiet queen move prepares the sacrifice that bares the king.","Queen to h5 — the start of a forced mate."],"hr":["Crni kralj biva opkoljen tihim prijetnjama i žrtvom.","Tih potez dame priprema žrtvu koja ogoljuje kralja.","Dama na h5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.042' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch eine Vorbereitung und ein Opfer gefangen.","Ein Springeropfer beseitigt einen Verteidiger, dann öffnet das Turmopfer die Linie.","Springer schlägt auf e4 – Auftakt zu erzwungenem Matt."],"en":["The black king on the edge is caught by a preparation and a sacrifice.","A knight sacrifice removes a defender, then a rook sacrifice opens the line.","Knight takes on e4 — the start of a forced mate."],"hr":["Crni kralj na rubu biva uhvaćen pripremom i žrtvom.","Žrtva skakača uklanja branitelja, a zatim žrtva topa otvara liniju.","Skakač uzima na e4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.043' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird über die Randlinie aus seiner Festung gerissen.","Ein Doppelturmopfer öffnet die Linie, dann setzt die Dame das Netz.","Dame schlägt auf h8 – der Beginn eines erzwungenen Matts."],"en":["The black king is torn out of his fortress along the edge file.","A double rook sacrifice opens the file, then the queen sets the net.","Queen takes on h8 — the start of a forced mate."],"hr":["Crni kralj se po rubnoj liniji izvlači iz svoje tvrđave.","Dvostruka žrtva topa otvara liniju, a zatim dama postavlja mrežu.","Dama uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.044' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand ist hinter durchbrochener Deckung verloren.","Ein Damenopfer öffnet die Linie, dann marschiert der Bauer entscheidend vor.","Dame schlägt auf g6 – Auftakt zu erzwungenem Matt."],"en":["The black king on the edge is lost behind broken cover.","A queen sacrifice opens the file, then the pawn marches in decisively.","Queen takes on g6 — the start of a forced mate."],"hr":["Crni kralj na rubu je izgubljen iza probijenog zaklona.","Žrtva dame otvara liniju, a zatim pješak odlučujuće napreduje.","Dama uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.045' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird über die Randlinie aus der Deckung gelockt und gejagt.","Ein Turmopfer öffnet die Linie, dann treiben Dame und Springer den König.","Turm schlägt auf h8 – der Beginn eines erzwungenen Matts."],"en":["The black king is lured out of cover along the edge file and hunted.","A rook sacrifice opens the file, then queen and knight drive the king.","Rook takes on h8 — the start of a forced mate."],"hr":["Crni kralj se po rubnoj liniji mami iz zaklona i progoni.","Žrtva topa otvara liniju, a zatim dama i skakač tjeraju kralja.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.046' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch Opfer entblößt und die Linie aufgerissen.","Ein Turmopfer beseitigt die Deckung, dann setzt der zweite Turm nach.","Turm schlägt auf h7 – Auftakt zu erzwungenem Matt."],"en":["The black king on the edge is bared by a sacrifice that rips the file open.","A rook sacrifice removes the cover, then the second rook follows up.","Rook takes on h7 — the start of a forced mate."],"hr":["Crni kralj na rubu biva ogoljen žrtvom koja otvara liniju.","Žrtva topa uklanja zaklon, a zatim drugi top nastavlja.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.047' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke ist eingeschnürt, ein Läuferzug fixiert ihn.","Ein Läufer nagelt den König fest, dann reißt ein Turmopfer die Linie auf.","Läufer schlägt auf f8 – der Beginn eines erzwungenen Matts."],"en":["The black king in the corner is laced in, fixed by a bishop move.","A bishop pins the king in place, then a rook sacrifice opens the line.","Bishop takes on f8 — the start of a forced mate."],"hr":["Crni kralj u kutu je sapet, učvršćen potezom lovca.","Lovac prikiva kralja, a zatim žrtva topa otvara liniju.","Lovac uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.048' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch eine lange Opferserie zermürbt.","Ein Turmopfer eröffnet den Angriff, dann übernehmen Dame und Bauer die Jagd.","Turm schlägt auf h7 – Auftakt zu erzwungenem Matt."],"en":["The black king on the edge is ground down by a long series of sacrifices.","A rook sacrifice opens the attack, then queen and pawn take up the chase.","Rook takes on h7 — the start of a forced mate."],"hr":["Crni kralj na rubu biva smrvljen dugim nizom žrtava.","Žrtva topa otvara napad, a zatim dama i pješak preuzimaju lov.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.049' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung ist entlang der offenen Linie bedrohlich entblößt, und ein Opfer reißt die letzte Deckung weg.","Eine Dame opfert sich, dann übernimmt der zweite schwere Stein, und am Ende setzt ein Läufer den entscheidenden Schlag.","Dame nach h1 – Beginn eines erzwungenen Matts."],"en":["The white king is dangerously exposed along the open file, and a sacrifice strips away the last cover.","A queen sacrifices herself, the heavy pieces crash through, and a bishop delivers the final blow.","Queen to h1 — the start of a forced mate."],"hr":["Bijeli kralj je opasno izložen duž otvorene linije, a žrtva uklanja posljednju zaštitu.","Dama se žrtvuje, teške figure probijaju, a lovac zadaje konačni udarac.","Dama na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.050' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand, und seine Verteidiger lassen sich nacheinander beseitigen.","Erst lockt ein Opfer den König heraus, dann arbeiten Turm und Springer zusammen, bis ein neuer Turm das Netz schließt.","Dame schlägt auf f8 – Auftakt eines erzwungenen Matts."],"en":["The black king is pinned to the edge and his defenders can be peeled away one by one.","A sacrifice lures the king out, then rook and knight cooperate before a fresh rook seals the net.","Queen takes on f8 — the start of a forced mate."],"hr":["Crni kralj je prikovan uz rub, a njegovi branitelji se redom uklanjaju.","Žrtva izvlači kralja, zatim top i skakač surađuju prije nego novi top zatvori mrežu.","Dama uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.051' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung ist morsch, und ein Damenopfer öffnet sie endgültig.","Die Dame opfert sich, um den König herauszuzerren, dann erledigt der Turm den Rest.","Dame schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king''s shelter is rotten, and a queen sacrifice tears it open for good.","The queen offers herself to drag the king out, then a rook finishes the job.","Queen takes on h2 — the start of a forced mate."],"hr":["Zaklon bijelog kralja je truo, a žrtva dame ga konačno otvara.","Dama se žrtvuje da izvuče kralja, a zatim top dovršava posao.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist am Rand erstickt, und ein Opfer zieht ihn ins Verderben.","Die Dame opfert sich, um den König herauszuholen, dann fällt der zweite schwere Stein ein.","Dame schlägt auf h2 – Auftakt eines erzwungenen Matts."],"en":["The white king is smothered on the edge, and a sacrifice drags him to his doom.","A queen sacrifice pulls the king out, then the other heavy piece pours in.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj je ugušen uz rub, a žrtva ga vuče u propast.","Žrtva dame izvlači kralja, a zatim druga teška figura nadire.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt fest, und ein Damenopfer lenkt seinen letzten Verteidiger ab.","Die Dame opfert sich, um eine Figur wegzulocken, dann springt ein Pferd zum tödlichen Schach ein.","Dame schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["The black king is stuck fast, and a queen sacrifice deflects his last defender.","The queen offers herself to pull a piece away, then a knight leaps in for the killing check.","Queen takes on f7 — the start of a forced mate."],"hr":["Crni kralj je čvrsto zaglavljen, a žrtva dame odvlači njegovog posljednjeg branitelja.","Dama se žrtvuje da odvuče figuru, a zatim skakač uskače za smrtonosni šah.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke eingeklemmt, und ein Damenopfer bereitet das Netz vor.","Die Dame opfert sich, um eine Figur abzulenken, dann besiegelt ein vorgeschobener Bauer das Matt.","Dame schlägt auf g7 – Auftakt eines erzwungenen Matts."],"en":["The black king is jammed in the corner, and a queen sacrifice prepares the net.","The queen sacrifices herself to deflect a piece, then an advanced pawn seals the mate.","Queen takes on g7 — the start of a forced mate."],"hr":["Crni kralj je stiješnjen u kutu, a žrtva dame priprema mrežu.","Dama se žrtvuje da odvuče figuru, a zatim napredni pješak zapečaćuje mat.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist langrochiert und unzureichend gedeckt, sodass ein Opfer die Linie öffnet.","Ein Damenopfer reißt einen Bauern weg, dann fällt der Turm auf der freien Linie ein.","Dame schlägt auf c6 – Beginn eines erzwungenen Matts."],"en":["The black king has castled long with thin cover, so a sacrifice rips open a file.","A queen sacrifice removes a pawn, then a rook crashes in down the open file.","Queen takes on c6 — the start of a forced mate."],"hr":["Crni kralj je dugo rokirao uz slabu zaštitu, pa žrtva otvara liniju.","Žrtva dame uklanja pješaka, a zatim top upada po otvorenoj liniji.","Dama uzima na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand ist zum Greifen nah, und ein Opfer öffnet seinen Bauernschild.","Die Dame opfert sich, um einen Bauern wegzulocken, dann gibt der vorgerückte Freibauer das Schach.","Dame schlägt auf g6 – Auftakt eines erzwungenen Matts."],"en":["The exposed black king is within reach, and a sacrifice cracks his pawn shield.","The queen offers herself to pull a pawn away, then the advanced passer delivers the check.","Queen takes on g6 — the start of a forced mate."],"hr":["Izloženi crni kralj je nadohvat, a žrtva razbija njegov pješački štit.","Dama se žrtvuje da odvuče pješaka, a zatim napredni slobodnjak daje šah.","Dama uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand ist eng eingesperrt, und ein Opfer beseitigt seinen Verteidiger.","Ein Damenopfer lenkt einen Läufer ab, dann setzt der Turm auf der g-Linie matt.","Dame schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge is boxed in, and a sacrifice removes his defender.","A queen sacrifice deflects a bishop, then a rook mates down the open file.","Queen takes on f8 — the start of a forced mate."],"hr":["Crni kralj uz rub je stiješnjen, a žrtva uklanja njegovog branitelja.","Žrtva dame odvlači lovca, a zatim top matira po otvorenoj liniji.","Dama uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Grundreihe ist verwundbar, und ein Damenopfer öffnet sie.","Die Dame opfert sich, um den König herauszuzerren, dann liefert der Turm das Matt der Grundreihe.","Dame schlägt auf f1 – Auftakt eines erzwungenen Matts."],"en":["The white back rank is vulnerable, and a queen sacrifice prises it open.","The queen offers herself to drag the king out, then a rook delivers the back-rank mate.","Queen takes on f1 — the start of a forced mate."],"hr":["Bijeli zadnji red je ranjiv, a žrtva dame ga otvara.","Dama se žrtvuje da izvuče kralja, a zatim top daje mat po zadnjem redu.","Dama uzima na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist enttarnt, und ein Damenopfer räumt die Diagonale frei.","Die Dame opfert sich, um eine Figur abzulenken, dann gibt ein Bauer auf der Diagonale das tödliche Schach.","Dame schlägt auf e5 – Beginn eines erzwungenen Matts."],"en":["The black king is exposed, and a queen sacrifice clears the diagonal.","The queen sacrifices herself to deflect a piece, then a pawn delivers the deadly check along the diagonal.","Queen takes on e5 — the start of a forced mate."],"hr":["Crni kralj je izložen, a žrtva dame oslobađa dijagonalu.","Dama se žrtvuje da odvuče figuru, a zatim pješak daje smrtonosni šah po dijagonali.","Dama uzima na e5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König am Rand ist gefährdet, und ein Damenopfer zieht seinen Hüter weg.","Die Dame opfert sich, um den König festzunageln, dann setzt der Läufer auf der langen Diagonale matt.","Dame schlägt auf f2 – Auftakt eines erzwungenen Matts."],"en":["The white king on the edge is in danger, and a queen sacrifice drags his guard away.","The queen offers herself to pin the king down, then a bishop mates on the long diagonal.","Queen takes on f2 — the start of a forced mate."],"hr":["Bijeli kralj uz rub je u opasnosti, a žrtva dame odvlači njegovog čuvara.","Dama se žrtvuje da prikuje kralja, a zatim lovac matira po dugoj dijagonali.","Dama uzima na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf seiner Reihe gefangen, und ein Opfer beseitigt den letzten Schutz.","Ein Läuferopfer lenkt einen Verteidiger ab, dann fällt der Turm mit Schach auf der Reihe ein.","Läufer schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped on his rank, and a sacrifice removes the last guard.","A bishop sacrifice deflects a defender, then a rook invades with check along the rank.","Bishop takes on f8 — the start of a forced mate."],"hr":["Crni kralj je zarobljen na svom redu, a žrtva uklanja posljednju zaštitu.","Žrtva lovca odvlači branitelja, a zatim top upada sa šahom po redu.","Lovac uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung ist brüchig, und ein Damenopfer öffnet die entscheidende Linie.","Die Dame opfert sich, um den König herauszulocken, dann dringt der Turm tödlich ein.","Dame schlägt auf e3 – Auftakt eines erzwungenen Matts."],"en":["The white king''s position is brittle, and a queen sacrifice opens the decisive line.","The queen offers herself to lure the king out, then a rook penetrates with lethal effect.","Queen takes on e3 — the start of a forced mate."],"hr":["Položaj bijelog kralja je krhak, a žrtva dame otvara odlučujuću liniju.","Dama se žrtvuje da izvuče kralja, a zatim top smrtonosno prodire.","Dama uzima na e3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand ist eng umstellt, und ein Damenopfer öffnet das Tor.","Die Dame opfert sich, um einen Bauern wegzulocken, dann setzt der Läufer das Netz endgültig.","Dame schlägt auf g5 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge is hemmed in, and a queen sacrifice opens the gate.","The queen sacrifices herself to pull a pawn away, then a bishop completes the net.","Queen takes on g5 — the start of a forced mate."],"hr":["Crni kralj uz rub je stiješnjen, a žrtva dame otvara vrata.","Dama se žrtvuje da odvuče pješaka, a zatim lovac dovršava mrežu.","Dama uzima na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt unsicher in der Mitte, und ein Damenopfer reißt die Diagonale auf.","Die Dame opfert sich, um einen Bauern abzulenken, dann setzt der Läufer auf der Diagonale matt.","Dame schlägt auf e6 – Auftakt eines erzwungenen Matts."],"en":["The black king sits insecurely in the centre, and a queen sacrifice tears open the diagonal.","The queen offers herself to deflect a pawn, then a bishop delivers mate along the diagonal.","Queen takes on e6 — the start of a forced mate."],"hr":["Crni kralj nesigurno stoji u sredini, a žrtva dame otvara dijagonalu.","Dama se žrtvuje da odvuče pješaka, a zatim lovac matira po dijagonali.","Dama uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Grundreihe ist tödlich schwach und sofort einzuschlagen.","Eine Dame stürzt auf die letzte Reihe und nutzt die Schwäche der Grundreihe aus.","Dame schlägt auf c1 – matt."],"en":["The white back rank is fatally weak and ready to be struck at once.","A queen crashes onto the back rank, exploiting the trapped king.","Queen takes on c1 — mate."],"hr":["Bijeli zadnji red je smrtonosno slab i odmah ranjiv.","Dama se obrušava na zadnji red, iskorištavajući zarobljenog kralja.","Dama uzima na c1 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:012.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist langrochiert und dürftig gedeckt, sodass ein Opfer die Diagonale öffnet.","Ein Damenopfer reißt einen Bauern weg, dann setzt der Läufer auf der freigelegten Diagonale matt.","Dame schlägt auf c6 – Beginn eines erzwungenen Matts."],"en":["The black king has castled long with thin cover, so a sacrifice opens the diagonal.","A queen sacrifice removes a pawn, then a bishop mates on the cleared diagonal.","Queen takes on c6 — the start of a forced mate."],"hr":["Crni kralj je dugo rokirao uz slabu zaštitu, pa žrtva otvara dijagonalu.","Žrtva dame uklanja pješaka, a zatim lovac matira po oslobođenoj dijagonali.","Dama uzima na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
