UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung lässt sich durch ein Damenopfer aufbrechen.","Ein Damenopfer lenkt den König ab, dann setzt ein Springer mit einer Gabel das Netz.","Dame schlägt auf c3 – Auftakt eines erzwungenen Matts."],"en":["The white king''s position can be cracked open by a queen sacrifice.","A queen sacrifice deflects the king, then a knight forks his way into the net.","Queen takes on c3 — the start of a forced mate."],"hr":["Položaj bijelog kralja se može razbiti žrtvom dame.","Žrtva dame odvlači kralja, a zatim skakač viljuškom zatvara mrežu.","Dama uzima na c3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke, und seine Verteidiger lassen sich nacheinander entfernen.","Eine Dame fesselt die Stellung, dann werden die Verteidiger abgetauscht, bis ein Turm einfällt.","Dame nach g8 – Beginn eines erzwungenen Matts."],"en":["The black king clings to the corner, and his defenders can be peeled off one by one.","A queen pins the position, then the defenders are traded off until a rook crashes in.","Queen to g8 — the start of a forced mate."],"hr":["Crni kralj se drži kuta, a njegovi branitelji se redom uklanjaju.","Dama prikiva položaj, branitelji se zamjenjuju, a zatim top upada.","Dama na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Grundreihe ist morsch, und eine Folge von Opfern legt sie offen.","Erst lenkt ein Opfer einen Turm ab, dann zwingt ein zweiter Turm den König heraus, bevor der Turm matt setzt.","Dame schlägt auf d2 – Auftakt eines erzwungenen Matts."],"en":["The white back rank is rotten, and a string of sacrifices lays it bare.","A sacrifice deflects a rook, then a second rook forces the king out before the rook mates.","Queen takes on d2 — the start of a forced mate."],"hr":["Bijeli zadnji red je truo, a niz žrtava ga ogoljuje.","Žrtva odvlači topa, drugi top izvlači kralja, a zatim top matira.","Dama uzima na d2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung ist morsch, und eine Lawine von Opfern bricht sie auf.","Mehrere Opfer reißen die Bauern weg, dann sticht ein Springer mit einer Gabel zum Matt.","Dame schlägt auf b2 – Beginn eines erzwungenen Matts."],"en":["The white king''s shelter is rotten, and a cascade of sacrifices breaks it open.","A run of sacrifices removes the pawns, then a knight forks his way to mate.","Queen takes on b2 — the start of a forced mate."],"hr":["Zaklon bijelog kralja je truo, a niz žrtava ga razbija.","Niz žrtava uklanja pješake, a zatim skakač viljuškom dolazi do mata.","Dama uzima na b2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.024' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand ist eng umstellt, und ein Damenopfer öffnet seine Deckung.","Die Dame opfert sich, um einen Bauern wegzulocken, dann fällt der Turm tödlich auf der Reihe ein.","Dame schlägt auf h7 – Auftakt eines erzwungenen Matts."],"en":["The black king on the edge is hemmed in, and a queen sacrifice opens his cover.","The queen sacrifices herself to pull a pawn away, then a rook swings in for the kill.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj uz rub je stiješnjen, a žrtva dame otvara njegovu zaštitu.","Dama se žrtvuje da odvuče pješaka, a zatim top smrtonosno upada.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.025' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung ist verwundbar, und ein Damenopfer reißt sie auf.","Ein Damenopfer zerrt den König heraus, dann jagen Turm und Springer ihn ins Matt.","Dame schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king''s position is vulnerable, and a queen sacrifice tears it open.","A queen sacrifice drags the king out, then rook and knight hunt him to mate.","Queen takes on h2 — the start of a forced mate."],"hr":["Položaj bijelog kralja je ranjiv, a žrtva dame ga razbija.","Žrtva dame izvlači kralja, a zatim top i skakač ga gone do mata.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.026' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand ist eingeengt, und ein Damenopfer öffnet das Tor.","Ein Damenopfer reißt einen Bauern weg, dann jagen Dame und Läufer den König ins Matt.","Dame schlägt auf h7 – Auftakt eines erzwungenen Matts."],"en":["The black king on the edge is cramped, and a queen sacrifice opens the gate.","A queen sacrifice removes a pawn, then queen and bishop chase the king to mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj uz rub je stiješnjen, a žrtva dame otvara vrata.","Žrtva dame uklanja pješaka, a zatim dama i lovac gone kralja do mata.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.027' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung lässt sich durch fortgesetzte Opfer aufbrechen.","Ein Damenopfer zerrt den König heraus, dann gibt ein Läufer das tödliche Schach.","Dame schlägt auf f2 – Beginn eines erzwungenen Matts."],"en":["The white king''s position can be cracked open by a run of sacrifices.","A queen sacrifice drags the king out, then a bishop delivers the deadly check.","Queen takes on f2 — the start of a forced mate."],"hr":["Položaj bijelog kralja se može razbiti nizom žrtava.","Žrtva dame izvlači kralja, a zatim lovac daje smrtonosni šah.","Dama uzima na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.028' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand ist gefährdet, und ein Damenopfer reißt seinen Schild weg.","Die Dame opfert sich, um einen Bauern abzulenken, dann jagen die Türme den König ins Matt.","Dame schlägt auf f7 – Auftakt eines erzwungenen Matts."],"en":["The black king on the edge is in danger, and a queen sacrifice rips away his shield.","The queen sacrifices herself to deflect a pawn, then the rooks hunt the king to mate.","Queen takes on f7 — the start of a forced mate."],"hr":["Crni kralj uz rub je u opasnosti, a žrtva dame odnosi njegov štit.","Dama se žrtvuje da odvuče pješaka, a zatim topovi gone kralja do mata.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.029' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand ist eng eingesperrt, und ein Damenopfer öffnet seine Deckung.","Die Dame opfert sich, um einen Bauern wegzulocken, dann setzt der Turm auf der h-Linie matt.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge is boxed in, and a queen sacrifice opens his cover.","The queen sacrifices herself to pull a pawn away, then a rook mates down the open file.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj uz rub je stiješnjen, a žrtva dame otvara njegovu zaštitu.","Dama se žrtvuje da odvuče pješaka, a zatim top matira po otvorenoj liniji.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.030' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klammert sich am Rand fest, doch seine Deckung lässt sich wegräumen.","Ein Turm erobert die offene Linie zum König, nachdem ein Bauernopfer den Weg freilegt.","Dame nimmt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king clings to the edge, but his cover can be torn away.","A rook seizes the open file to the king once a pawn sacrifice clears the path.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj se drži ruba, ali se njegov zaklon može ukloniti.","Top osvaja otvorenu liniju prema kralju nakon što žrtva pješaka raščisti put.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.031' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist auf dem Königsflügel verwundbar, sein Schutzwall wackelt.","Deine Dame dringt in die Königsstellung ein und erzwingt das Matt.","Dame nach h4 – Auftakt zum erzwungenen Matt."],"en":["The white king is vulnerable on the kingside, his shelter shaky.","Your queen invades the king''s quarters and forces the mate.","Queen to h4 — the start of a forced mate."],"hr":["Bijeli kralj je ranjiv na kraljevu krilu, zaklon mu je krhak.","Tvoja dama prodire u kraljev tabor i prisiljava mat.","Dama na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.032' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die letzte Reihe des schwarzen Königs ist tödlich entblößt.","Ein Turmtausch öffnet die Linie, dann setzt ein Bauer den König matt.","Dame nach e8 – Beginn eines erzwungenen Matts."],"en":["The black king''s back rank is fatally exposed.","A rook trade opens the file, then a pawn mates the cornered king.","Queen to e8 — the start of a forced mate."],"hr":["Zadnja linija crnog kralja je kobno otkrivena.","Zamjena topova otvara liniju, a zatim pješak matira kralja.","Dama na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.033' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird auf den Eckenraum gedrängt und findet kein Entkommen.","Ein Damenopfer lockt eine Figur ab, dann liefert dein Turm das Matt.","Dame nimmt auf f1 – Auftakt zum erzwungenen Matt."],"en":["The white king is squeezed toward the corner with no flight.","A queen sacrifice lures a piece away, then your rook delivers mate.","Queen takes on f1 — the start of a forced mate."],"hr":["Bijeli kralj je stisnut prema kutu bez bijega.","Žrtva dame odvlači figuru, a zatim tvoj top daje mat.","Dama uzima na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.034' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König am Rand ist von eigenen Figuren eingeengt.","Ein Damenopfer reißt die Deckung weg, dann setzt der zweite Turm matt.","Dame nach c3 – Beginn eines erzwungenen Matts."],"en":["The white king on the edge is hemmed in by his own pieces.","A queen sacrifice tears away a defender, then the other rook mates.","Queen to c3 — the start of a forced mate."],"hr":["Bijeli kralj na rubu je sputan vlastitim figurama.","Žrtva dame uklanja branitelja, a zatim drugi top matira.","Dama na c3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.035' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die letzte Reihe des schwarzen Königs ist verwundbar.","Nach einem Turmtausch auf der letzten Reihe gibt ein Springer das Erstickungsmatt.","Dame nach e8 – Auftakt zum erzwungenen Matt."],"en":["The black king''s back rank is the weak point.","After a rook trade on the back rank, a knight delivers a smothered mate.","Queen to e8 — the start of a forced mate."],"hr":["Zadnja linija crnog kralja je slaba točka.","Nakon zamjene topova na zadnjoj liniji, skakač daje ugušeni mat.","Dama na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.036' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus seiner Deckung gelockt.","Ein Damenopfer öffnet die Bauernkette, dann jagt der Turm den König zu Tode.","Dame nimmt auf h6 – Beginn eines erzwungenen Matts."],"en":["The black king is dragged out of cover by a sacrifice.","A queen sacrifice cracks the pawn shield, then the rook hunts the king down.","Queen takes on h6 — the start of a forced mate."],"hr":["Crni kralj je izvučen iz zaklona žrtvom.","Žrtva dame razbija pješački štit, a zatim top lovi kralja.","Dama uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.037' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
