UPDATE BookPuzzles SET HintsJson='{"de":["Die letzte Reihe des schwarzen Königs lässt sich tödlich ausnutzen.","Ein Damenopfer und Turmtausch öffnen die Linie, dann setzt ein Bauer matt.","Dame nach e8 – Beginn eines erzwungenen Matts."],"en":["The black king''s back rank can be fatally exploited.","A queen sacrifice and rook trade open the file, then a pawn mates.","Queen to e8 — the start of a forced mate."],"hr":["Zadnja linija crnog kralja može se kobno iskoristiti.","Žrtva dame i zamjena topova otvaraju liniju, a zatim pješak matira.","Dama na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.039' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
