UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König am Rand wird durch Opfer ins Mattnetz getrieben.","Ein Springer und ein Turm öffnen die Königsstellung, dann setzt der Turm matt.","Springer nimmt auf f1 – Auftakt zum erzwungenen Matt."],"en":["The white king on the edge is driven into a mating net by sacrifices.","A knight and a rook open the king''s shelter, then the rook mates.","Knight takes on f1 — the start of a forced mate."],"hr":["Bijeli kralj na rubu žrtvama je natjeran u matnu mrežu.","Skakač i top otvaraju kraljev zaklon, a zatim top matira.","Skakač uzima na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.057' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch wiederholte Opfer aus der Ecke gejagt.","Dame und Läufer treiben den König, bis der Läufer das Matt gibt.","Dame nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is chased from the corner by repeated sacrifices.","Queen and bishop drive the king until the bishop delivers mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj je opetovanim žrtvama protjeran iz kuta.","Dama i lovac gone kralja dok lovac ne da mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.058' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch Opfer aus der Rochadestellung gerissen.","Ein Damenopfer und ein Läuferschlag treiben den König, dann setzt ein Springer matt.","Dame nimmt auf f7 – Beginn eines erzwungenen Matts."],"en":["The black king is torn from his castled position by sacrifices.","A queen sacrifice and a bishop strike drive the king, then a knight mates.","Queen takes on f7 — the start of a forced mate."],"hr":["Crni kralj je žrtvama istrgnut iz rokirane pozicije.","Žrtva dame i udar lovca gone kralja, a zatim skakač matira.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.059' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch wiederholte Opfer ins Mattnetz getrieben.","Dame und Türme jagen den König über das Brett bis zum erzwungenen Matt.","Dame nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is hounded into a mating net by repeated sacrifices.","Queen and rooks chase the king across the board to a forced mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj je opetovanim žrtvama natjeran u matnu mrežu.","Dama i topovi gone kralja preko ploče do prisilnog mata.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.060' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König hat kaum Luft und eine Damenopferung reißt seine Deckung auf.","Erst ein Damenopfer am König, dann gibt der Läufer den letzten Stoß.","Dame schlägt auf g2 – Beginn eines erzwungenen Matts."],"en":["The white king has almost no air and a queen sacrifice tears open his cover.","First a queen sacrifice near the king, then the bishop strikes the final blow.","Queen takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj jedva diše, a žrtva dame razbija njegovu zaštitu.","Najprije žrtva dame uz kralja, a zatim lovac zadaje konačni udarac.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.061' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Grundreihe ist verwundbar und der König wird hineingedrängt.","Türme und ein Läufer arbeiten zusammen, um den König in die Ecke zu treiben.","Dame schlägt auf e1 – Beginn eines erzwungenen Matts."],"en":["The white back rank is vulnerable and the king gets driven into it.","Rooks and a bishop combine to herd the king into the corner.","Queen takes on e1 — the start of a forced mate."],"hr":["Bijela zadnja linija je ranjiva i kralj biva utjeran u nju.","Topovi i lovac udružuju se da kralja stjeraju u kut.","Dama uzima na e1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.062' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und ein Opfer öffnet die Linien.","Erst weg mit dem Verteidiger, dann setzen die Türme matt.","Dame schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king is glued to the edge and a sacrifice opens the lines.","First remove the defender, then the rooks finish the mate.","Queen takes on g7 — the start of a forced mate."],"hr":["Crni kralj je prilijepljen uz rub, a žrtva otvara linije.","Najprije ukloni branitelja, a zatim topovi matiraju.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.063' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand eingeengt und die Verteidiger sind überlastet.","Ein Springersprung leitet die Mattführung mit Dame und Turm ein.","Springer nach g6 – Beginn eines erzwungenen Matts."],"en":["The black king is hemmed in on the edge and the defenders are overloaded.","A knight leap launches the mating attack with queen and rook.","Knight to g6 — the start of a forced mate."],"hr":["Crni kralj je stiješnjen uz rub, a branitelji su preopterećeni.","Skok konja pokreće matni napad damom i topom.","Konj na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.064' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt am Rand und ein Ablenkungsopfer entscheidet.","Erst den Verteidiger weglocken, dann setzt der Turm in der Ecke matt.","Dame schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["The black king is on the edge and a deflecting sacrifice decides.","First lure away the defender, then the rook mates in the corner.","Queen takes on f7 — the start of a forced mate."],"hr":["Crni kralj je uz rub, a odvlačeća žrtva odlučuje.","Najprije odvuci branitelja, a zatim top matira u kutu.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.065' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
