UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke gedrängt und die Linien werden geöffnet.","Läufer und zwei Türme jagen den König gnadenlos.","Läufer schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king is forced into the corner and the lines are pried open.","A bishop and two rooks hunt the king relentlessly.","Bishop takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj je stjeran u kut, a linije se otvaraju.","Lovac i dva topa nemilosrdno love kralja.","Lovac uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.067' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Königsstellung ist dünn und ein Damenangriff bricht durch.","Erst die Dame zum König, dann öffnet ein Opfer den Weg für das Turmmatt.","Dame nach h5 – Beginn eines erzwungenen Matts."],"en":["Black''s king position is thin and a queen thrust breaks through.","First the queen swings over, then a sacrifice clears the path for a rook mate.","Queen to h5 — the start of a forced mate."],"hr":["Crni kralj je slabo zaštićen, a napad dame probija.","Najprije dama prelazi, a zatim žrtva otvara put za mat topom.","Dama na h5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.068' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
