UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung ist löchrig und ein Damenopfer reißt sie auf.","Nach dem Damenopfer setzt ein Turm an der Königslinie matt.","Dame schlägt auf h4 – Beginn eines erzwungenen Matts."],"en":["The white king''s shelter is full of holes and a queen sacrifice rips it apart.","After the queen sacrifice a rook mates along the king''s file.","Queen takes on h4 — the start of a forced mate."],"hr":["Zaklon bijelog kralja je rupičast, a žrtva dame ga razbija.","Nakon žrtve dame top matira po kraljevoj liniji.","Dama uzima na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.071' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
