UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Rochadestellung ist angeschlagen und der König klebt am Rand.","Erst die Dame zum König, dann setzt sie auf der offenen Linie matt.","Dame nach h5 – Beginn eines erzwungenen Matts."],"en":["Black''s castled position is battered and the king clings to the edge.","First the queen swings over, then she mates along the open line.","Queen to h5 — the start of a forced mate."],"hr":["Crna rokada je oslabljena, a kralj se drži uz rub.","Najprije dama prelazi, a zatim matira po otvorenoj liniji.","Dama na h5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.074' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
