UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke gefangen und ein Opfer öffnet alles.","Nach den Opfern setzt ein Springer dem eingeengten König matt.","Dame schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king is trapped in the corner and a sacrifice opens everything.","After the sacrifices a knight mates the boxed-in king.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj je zarobljen u kutu, a žrtva otvara sve.","Nakon žrtava konj matira stiješnjenog kralja.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.088' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Königsstellung ist morsch und ein Opfer reißt sie auf.","Ein Damenopfer und ein Springeropfer ebnen den Weg für das Turmmatt.","Dame nach h5 – Beginn eines erzwungenen Matts."],"en":["Black''s king position is rotten and a sacrifice tears it open.","A queen sacrifice and a knight sacrifice pave the way for the rook mate.","Queen to h5 — the start of a forced mate."],"hr":["Crni kralj je trošno zaštićen, a žrtva ga razbija.","Žrtva dame i žrtva konja otvaraju put za mat topom.","Dama na h5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.089' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus der Deckung gezogen.","Ein Damenopfer entblößt den König, dann jagen ihn Läufer und Springer.","Dame schlägt auf h6 – Beginn eines erzwungenen Matts."],"en":["The black king is pulled out of cover by a sacrifice.","A queen sacrifice bares the king, then bishop and knight hunt him.","Queen takes on h6 — the start of a forced mate."],"hr":["Crni kralj biva izvučen iz zaklona žrtvom.","Žrtva dame ogoljuje kralja, a zatim ga jure lovac i konj.","Dama uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.090' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke und seine Bauernkette lässt ihm keine Luft.","Mit einem Damenopfer öffnest du die Linie für deine Türme, die dann zuschlagen.","Dame schlägt auf g8 – es folgt ein erzwungenes Matt."],"en":["The black king is wedged in the corner and his own pawns leave him no air.","A queen sacrifice clears the way for your rooks to finish the job.","Queen takes on g8 — starting a forced mate."],"hr":["Crni kralj je stiješnjen u kutu, a vlastiti pješaci ne daju mu zraka.","Žrtva dame otvara liniju tvojim topovima da dovrše posao.","Dama uzima na g8 — slijedi prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:012.091' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf dem Königsflügel entblößt und seine Felder schwinden.","Dein Springer und die Dame jagen den König ins Verderben.","Dame schlägt auf h6 – Beginn eines erzwungenen Matts."],"en":["The black king stands exposed on the kingside with shrinking squares.","Your knight and queen herd the king toward his doom.","Queen takes on h6 — beginning a forced mate."],"hr":["Crni kralj je razgolićen na kraljevu krilu, a polja mu nestaju.","Tvoj skakač i dama tjeraju kralja u propast.","Dama uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.092' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird Schritt für Schritt aus seiner Deckung getrieben.","Mit einem Damenopfer und dem Läufer treibst du den König ins offene Feld.","Dame nach e8 – Auftakt zu einem erzwungenen Matt."],"en":["The black king is to be driven step by step out of his shelter.","A queen sacrifice plus the bishop chase the king into the open.","Queen to e8 — the start of a forced mate."],"hr":["Crnog kralja korak po korak izgone iz zaklona.","Žrtva dame i lovac tjeraju kralja na otvoreno.","Dama na e8 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:012.093' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Matt scheitert nur daran, dass eine Linie noch verstellt ist.","Opfere, um die Linie zu öffnen, dann setzt der Turm matt.","Dame schlägt auf e8 – Auftakt zu einem erzwungenen Matt."],"en":["A mate is blocked only because a line is still obstructed.","Sacrifice to open the line, then a rook delivers mate.","Queen takes on e8 — beginning a forced mate."],"hr":["Mat ne uspijeva samo zato što je jedna linija još zatvorena.","Žrtvuj da otvoriš liniju, a onda top daje mat.","Dama uzima na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt in der Ecke und braucht nur die richtige Linie zum Ziel.","Ein Turmopfer reißt eine Linie auf, über die deine Dame matt setzt.","Turm schlägt auf h3 – Beginn eines erzwungenen Matts."],"en":["The black king sits in the corner and only the right file is needed.","A rook sacrifice rips open the line for your queen to mate.","Rook takes on h3 — beginning a forced mate."],"hr":["Crni kralj je u kutu i treba samo prava linija do cilja.","Žrtva topa otvara liniju kojom tvoja dama daje mat.","Top uzima na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Königsflügel verwundbar, sobald eine Linie aufgeht.","Opfere den Läufer, um die Linie für deine Dame freizumachen.","Läufer schlägt auf d5 – Auftakt zu einem erzwungenen Matt."],"en":["The black king is vulnerable on the kingside once a line opens.","Sacrifice the bishop to clear the path for your queen.","Bishop takes on d5 — the start of a forced mate."],"hr":["Crni kralj je ranjiv na kraljevu krilu čim se linija otvori.","Žrtvuj lovca da oslobodiš put svojoj dami.","Lovac uzima na d5 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:013.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist hinter seinen eigenen Steinen eingemauert und schwach.","Ein einziger Läuferzug stellt das tödliche Schach.","Läufer nach d3 – matt."],"en":["The white king is walled in behind his own men and helpless.","A single bishop move delivers the deadly check.","Bishop to d3 — mate."],"hr":["Bijeli kralj je zazidan iza vlastitih figura i bespomoćan.","Jedan jedini potez lovca daje smrtonosni šah.","Lovac na d3 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:013.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist am Rand entblößt, sobald seine Deckung fällt.","Ein Turmopfer lockt den Wächter weg, dann schlägt die Dame zu.","Turm schlägt auf g2 – Beginn eines erzwungenen Matts."],"en":["The white king is bared on the edge once his guard is removed.","A rook sacrifice lures away the defender, then the queen strikes.","Rook takes on g2 — beginning a forced mate."],"hr":["Bijeli kralj je razgolićen na rubu čim mu padne čuvar.","Žrtva topa odvlači branitelja, a onda dama udara.","Top uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
