UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Königsflügel anfällig, wenn seine Deckung fällt.","Opfere den Springer, um die Stellung aufzubrechen, dann jagen Dame und Bauer den König.","Springer schlägt auf g5 – Beginn eines erzwungenen Matts."],"en":["The black king is vulnerable on the kingside once his cover collapses.","Sacrifice the knight to crack the position, then queen and pawn hunt the king.","Knight takes on g5 — beginning a forced mate."],"hr":["Crni kralj je ranjiv na kraljevu krilu čim mu padne zaklon.","Žrtvuj skakača da razbiješ poziciju, pa dama i pješak love kralja.","Skakač uzima na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.026' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist am Rand entblößt und sein Wächter ist überlastet.","Opfere mit Tempo, dann setzt der Turm über die Linie matt.","Dame schlägt auf h4 – Auftakt zu einem erzwungenen Matt."],"en":["The white king is bared on the edge with an overloaded guard.","Sacrifice with tempo, then a rook mates down the line.","Queen takes on h4 — the start of a forced mate."],"hr":["Bijeli kralj je razgolićen na rubu, a čuvar mu je preopterećen.","Žrtvuj s tempom, pa top daje mat po liniji.","Dama uzima na h4 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:013.027' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist am Königsflügel verwundbar, sobald ein Bauer weicht.","Opfere den Springer mit Tempo, dann setzt der Läufer matt.","Springer schlägt auf g4 – Beginn eines erzwungenen Matts."],"en":["The white king is vulnerable on the kingside once a pawn steps aside.","Sacrifice the knight with tempo, then the bishop delivers mate.","Knight takes on g4 — beginning a forced mate."],"hr":["Bijeli kralj je ranjiv na kraljevu krilu čim se pješak makne.","Žrtvuj skakača s tempom, pa lovac daje mat.","Skakač uzima na g4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.028' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird Schritt für Schritt aus seiner Deckung gezerrt.","Opfere mit Tempo, dann jagen deine Dame und der Turm den König.","Turm schlägt auf h3 – Auftakt zu einem erzwungenen Matt."],"en":["The white king is dragged step by step out of his shelter.","Sacrifice with tempo, then your queen and rook hunt the king.","Rook takes on h3 — the start of a forced mate."],"hr":["Bijeli kralj se korak po korak izvlači iz zaklona.","Žrtvuj s tempom, pa tvoja dama i top love kralja.","Top uzima na h3 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:013.029' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König hinter seinem Bauernschild lässt sich durch ein Opfer entblößen.","Ein Springeropfer reißt die Königsstellung auf, dann setzt die Dame mit Hilfe des Läufers matt.","Springer nach g6 – Beginn eines erzwungenen Matts."],"en":["The king behind his pawn shield can be stripped bare by a sacrifice.","A knight sacrifice tears open the king''s cover, then the queen mates with the bishop''s help.","Knight to g6 — the start of a forced mate."],"hr":["Kralj iza svog pješačkog štita može se ogoliti žrtvom.","Žrtva skakača razbija kraljev zaklon, a zatim dama matira uz pomoć lovca.","Skakač na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.030' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht windig, und ein Bauernopfer öffnet die Tür.","Ein Bauernopfer lockt, dann jagt die Dame den König und ein Turm beendet alles.","Bauer nach f4 – Beginn eines erzwungenen Matts."],"en":["The white king sits exposed, and a pawn sacrifice opens the door.","A pawn lure clears the way, then the queen hunts the king and a rook finishes.","Pawn to f4 — the start of a forced mate."],"hr":["Bijeli kralj stoji izložen, a žrtva pješaka otvara vrata.","Pješak privlači, zatim dama goni kralja, a top sve dovršava.","Pješak na f4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.031' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird von einem Damenopfer aufgerissen.","Ein Damenopfer öffnet die Linie, dann gibt der Turm das Matt.","Dame nach h5 – Beginn eines erzwungenen Matts."],"en":["The cornered black king is pried open by a queen sacrifice.","A queen sacrifice opens the line, then the rook delivers mate.","Queen to h5 — the start of a forced mate."],"hr":["Skrajnjeni crni kralj otvara se žrtvom dame.","Žrtva dame otvara liniju, zatim top daje mat.","Dama na h5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.032' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König mitten im Brett ist die Zielscheibe; zuerst muss ein Verteidiger weg.","Ein Bauer lenkt den Springer ab, dann dringt der Turm tödlich ein.","Bauer nach g5 – Beginn eines erzwungenen Matts."],"en":["The white king stuck in the centre is the target; first a defender must go.","A pawn deflects the knight, then the rook crashes in fatally.","Pawn to g5 — the start of a forced mate."],"hr":["Bijeli kralj zaglavljen u sredini je meta; najprije branitelj mora pasti.","Pješak odvlači skakača, zatim top kobno prodire.","Pješak na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.033' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird in die Ecke gedrängt und dort eingenetzt.","Ein Läuferopfer und ein Springeropfer reißen den König auf, dann setzt der Läufer matt.","Läufer nimmt auf e3 – Beginn eines erzwungenen Matts."],"en":["The white king is forced into the corner and netted there.","A bishop sacrifice and a knight sacrifice strip the king, then the bishop mates.","Bishop takes on e3 — the start of a forced mate."],"hr":["Bijeli kralj je natjeran u kut i ondje uhvaćen u mrežu.","Žrtva lovca i žrtva skakača ogole kralja, zatim lovac matira.","Lovac uzima na e3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.034' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die siebte Reihe und der König am Rand sind die Schwäche.","Ein Turmopfer lenkt einen Verteidiger ab, dann bricht die Dame durch.","Turm nach e5 – Beginn eines erzwungenen Matts."],"en":["The seventh rank and the king on the edge are the weakness.","A rook sacrifice deflects a defender, then the queen breaks through.","Rook to e5 — the start of a forced mate."],"hr":["Sedmi red i kralj na rubu su slabost.","Žrtva topa odvlači branitelja, zatim dama probija.","Top na e5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.035' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke leidet an der schwachen Grundreihe.","Ein Damenopfer und ein Turmopfer reißen die Deckung weg, dann setzt die Dame matt.","Dame nach e8 – Beginn eines erzwungenen Matts."],"en":["The black king in the corner suffers from a weak back rank.","A queen sacrifice and a rook sacrifice strip the cover, then the queen mates.","Queen to e8 — the start of a forced mate."],"hr":["Crni kralj u kutu pati od slabog zadnjeg reda.","Žrtva dame i žrtva topa skidaju zaštitu, zatim dama matira.","Dama na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.036' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König im Freien wird Schritt für Schritt eingekreist.","Ein Turm öffnet die Stellung, dann treiben Läufer und Dame den König ins Matt.","Turm nach d5 – Beginn eines erzwungenen Matts."],"en":["The black king out in the open is hemmed in step by step.","A rook opens the position, then bishop and queen drive the king to mate.","Rook to d5 — the start of a forced mate."],"hr":["Crni kralj na otvorenom postupno se opkoljava.","Top otvara poziciju, zatim lovac i dama tjeraju kralja u mat.","Top na d5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.037' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch ein Ablenkungsopfer entblößt.","Ein Turmopfer zieht den Läufer weg, dann liefern Turm und Bauer das Matt.","Turm nimmt auf h8 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge is exposed by a deflection sacrifice.","A rook sacrifice pulls the bishop away, then rook and pawn deliver mate.","Rook takes on h8 — the start of a forced mate."],"hr":["Crni kralj na rubu otkriva se žrtvom odvlačenja.","Žrtva topa odvlači lovca, zatim top i pješak daju mat.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.038' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke ist von Schwerfiguren belagert.","Ein Läuferopfer und ein Damenopfer öffnen die Linie, dann setzt der Turm matt.","Läufer nimmt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king in the corner is besieged by heavy pieces.","A bishop sacrifice and a queen sacrifice open the line, then the rook mates.","Bishop takes on g7 — the start of a forced mate."],"hr":["Crni kralj u kutu opkoljen je teškim figurama.","Žrtva lovca i žrtva dame otvaraju liniju, zatim top matira.","Lovac uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.039' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
