UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke leidet an der schwachen Grundreihe.","Ein Damenopfer und ein Springeropfer reißen die Deckung weg, dann setzt der Turm matt.","Dame nimmt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king in the corner suffers from a weak back rank.","A queen sacrifice and a knight sacrifice strip the cover, then the rook mates.","Queen takes on g7 — the start of a forced mate."],"hr":["Crni kralj u kutu pati od slabog zadnjeg reda.","Žrtva dame i žrtva skakača skidaju zaštitu, zatim top matira.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.045' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch eine Reihe von Opfern aus der Deckung gezerrt.","Ein Damenopfer und ein Turmopfer treiben den König heraus, dann setzt der Springer matt.","Dame nimmt auf a7 – Beginn eines erzwungenen Matts."],"en":["The black king is dragged out of cover by a chain of sacrifices.","A queen sacrifice and a rook sacrifice flush out the king, then the knight mates.","Queen takes on a7 — the start of a forced mate."],"hr":["Crni kralj se nizom žrtava izvlači iz zaklona.","Žrtva dame i žrtva topa istjeruju kralja, zatim skakač matira.","Dama uzima na a7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.046' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke ist von schweren Figuren umstellt.","Ein Springer schließt ein, dann öffnen Turm- und Damenopfer den Weg zum Matt.","Springer nimmt auf e7 – Beginn eines erzwungenen Matts."],"en":["The black king in the corner is surrounded by heavy pieces.","A knight seals the king in, then rook and queen sacrifices clear the path to mate.","Knight takes on e7 — the start of a forced mate."],"hr":["Crni kralj u kutu okružen je teškim figurama.","Skakač ga zatvara, zatim žrtve topa i dame otvaraju put do mata.","Skakač uzima na e7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.047' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird mit Tempogewinn ins Netz getrieben.","Ein Läuferopfer und ein Turmopfer schnüren das Netz zu, dann setzt die Dame matt.","Läufer nach g4 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge is driven into a net with gain of tempo.","A bishop sacrifice and a rook sacrifice tighten the net, then the queen mates.","Bishop to g4 — the start of a forced mate."],"hr":["Crni kralj na rubu se s dobitkom tempa tjera u mrežu.","Žrtva lovca i žrtva topa stežu mrežu, zatim dama matira.","Lovac na g4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.048' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König hinter geöffneten Bauern wird systematisch gejagt.","Ein Damenopfer und ein Turmopfer reißen die Stellung auf, dann setzt der Läufer matt.","Dame nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king behind broken pawns is systematically hunted.","A queen sacrifice and a rook sacrifice tear open the position, then the bishop mates.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj iza razbijenih pješaka sustavno se progoni.","Žrtva dame i žrtva topa otvaraju poziciju, zatim lovac matira.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.049' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch zwei Opfer entblößt.","Ein Springeropfer und ein Damenopfer reißen die Deckung weg, dann setzt der Turm matt.","Springer nimmt auf g6 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge is stripped by two sacrifices.","A knight sacrifice and a queen sacrifice tear off the cover, then the rook mates.","Knight takes on g6 — the start of a forced mate."],"hr":["Crni kralj na rubu se ogoli dvjema žrtvama.","Žrtva skakača i žrtva dame skidaju zaštitu, zatim top matira.","Skakač uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.050' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in einer langen Treibjagd über das Brett gehetzt.","Eine Damenopfer-Idee und ein Turmvorstoß netzen den König, dann setzt der Bauer matt.","Dame nimmt auf c5 – Beginn eines erzwungenen Matts."],"en":["The black king is chased across the board in a long hunt.","A queen offer and a rook thrust net the king, then the pawn mates.","Queen takes on c5 — the start of a forced mate."],"hr":["Crni kralj se u dugom lovu tjera preko ploče.","Ponuda dame i prodor topa hvataju kralja, zatim pješak matira.","Dama uzima na c5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:013.051' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Grundreihe ist die Schwäche, sobald ein Verteidiger weicht.","Ein Damenopfer lenkt den Turm ab, dann dringt die Dame zum Matt ein.","Dame nimmt auf g1 – Beginn eines erzwungenen Matts."],"en":["The white back rank is the weakness once a defender steps aside.","A queen sacrifice deflects the rook, then the queen penetrates to mate.","Queen takes on g1 — the start of a forced mate."],"hr":["Bijeli zadnji red je slabost čim branitelj ustukne.","Žrtva dame odvlači topa, zatim dama prodire u mat.","Dama uzima na g1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch eigene Figuren erstickt.","Ein Damenopfer zwingt eine Blockade, dann setzt der Springer das erstickte Matt.","Dame nimmt auf g8 – Beginn eines erzwungenen Matts."],"en":["The black king is smothered by his own pieces.","A queen sacrifice forces a block, then the knight gives the smothered mate.","Queen takes on g8 — the start of a forced mate."],"hr":["Crni kralj je ugušen vlastitim figurama.","Žrtva dame prisiljava blokadu, zatim skakač daje ugušeni mat.","Dama uzima na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus seiner Deckung gezogen.","Ein Damenopfer lockt einen Verteidiger weg, dann setzt der Springer matt.","Dame nimmt auf f7 – Beginn eines erzwungenen Matts."],"en":["The black king is drawn from cover by a sacrifice.","A queen sacrifice lures a defender away, then the knight mates.","Queen takes on f7 — the start of a forced mate."],"hr":["Crni kralj se žrtvom izvlači iz zaklona.","Žrtva dame odvlači branitelja, zatim skakač matira.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
