UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird von eigenen Steinen eingeengt.","Ein Turmopfer lenkt den Turm ab, dann setzt der Springer matt.","Turm nimmt auf a8 – Beginn eines erzwungenen Matts."],"en":["The black king on the edge is cramped by his own men.","A rook sacrifice deflects the rook, then the knight mates.","Rook takes on a8 — the start of a forced mate."],"hr":["Crni kralj na rubu sputan je vlastitim figurama.","Žrtva topa odvlači topa, zatim skakač matira.","Top uzima na a8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Grundreihe wird verwundbar, sobald ein Verteidiger fällt.","Ein Damenopfer lenkt den Turm ab, dann setzt der Springer matt.","Dame nimmt auf g1 – Beginn eines erzwungenen Matts."],"en":["The white back rank turns vulnerable once a defender is removed.","A queen sacrifice deflects the rook, then the knight mates.","Queen takes on g1 — the start of a forced mate."],"hr":["Bijeli zadnji red postaje ranjiv čim branitelj padne.","Žrtva dame odvlači topa, zatim skakač matira.","Dama uzima na g1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke wird durch ein Opfer entblößt.","Ein Damenopfer lenkt einen Verteidiger ab, dann setzt der Springer matt.","Dame nimmt auf a7 – Beginn eines erzwungenen Matts."],"en":["The black king in the corner is laid bare by a sacrifice.","A queen sacrifice deflects a defender, then the knight mates.","Queen takes on a7 — the start of a forced mate."],"hr":["Crni kralj u kutu ogoli se žrtvom.","Žrtva dame odvlači branitelja, zatim skakač matira.","Dama uzima na a7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt eingeklemmt in der Ecke und seine eigenen Figuren rauben ihm jedes Fluchtfeld.","Ein Springeropfer reißt die Deckung auf, dann setzt der zweite Springer den ersticken Schlusspunkt.","Dame schlägt auf g8 – Beginn eines erzwungenen Matts."],"en":["The black king is wedged in the corner and his own pieces strip away every escape.","A knight sacrifice tears open the cover, then the second knight delivers the smothered finish.","Queen takes on g8 — starting a forced mate."],"hr":["Crni kralj je stiješnjen u kutu, a vlastite mu figure oduzimaju svako polje za bijeg.","Žrtva skakača otvara zaštitu, a drugi skakač zadaje ugušeni mat.","Dama uzima na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt am Rand und ein abgezogenes Schach wird ihm zum Verhängnis.","Ein Bauernopfer lockt eine Figur weg, dann gibt der Läufer das tödliche Abzugsschach.","Bauer schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king is pinned to the edge and a discovered check proves fatal.","A pawn sacrifice lures a piece away, then the bishop gives the killing discovered check.","Pawn takes on h2 — starting a forced mate."],"hr":["Bijeli kralj je prikovan uz rub, a otkriveni šah postaje koban.","Žrtva pješaka odvlači figuru, a lovac zatim daje smrtonosni otkriveni šah.","Pješak uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König erstickt in der Ecke an seinen eigenen Figuren.","Ein Damenopfer öffnet die Tür, dann liefert der Springer das Erstickungsmatt.","Dame schlägt auf g8 – Beginn eines erzwungenen Matts."],"en":["The black king suffocates in the corner among his own pieces.","A queen sacrifice opens the door, then the knight delivers the smothered mate.","Queen takes on g8 — starting a forced mate."],"hr":["Crni kralj se guši u kutu okružen vlastitim figurama.","Žrtva dame otvara vrata, a skakač zadaje ugušeni mat.","Dama uzima na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König irrt am Rand umher und die Dame jagt ihn ins Netz.","Ein Turmvorstoß und ein Bauernzug treiben den König, dann setzt die Dame über die freie Linie matt.","Turm nach a7 – Beginn eines erzwungenen Matts."],"en":["The black king wanders on the edge and the queen hunts it into a net.","A rook advance and a pawn push drive the king, then the queen mates along the open line.","Rook to a7 — starting a forced mate."],"hr":["Crni kralj luta uz rub, a dama ga goni u mrežu.","Napredovanje topa i potez pješaka tjeraju kralja, a dama zatim matira po otvorenoj liniji.","Top na a7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seiner eigenen Bauernkette in der Ecke gefangen.","Erst ein Damenopfer, dann ein Läuferopfer brechen die Deckung, ehe der weit vorgerückte Bauer mattsetzt.","Dame schlägt auf g8 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped in the corner behind his own pawn shield.","First a queen sacrifice, then a bishop sacrifice rip the cover before the advanced pawn mates.","Queen takes on g8 — starting a forced mate."],"hr":["Crni kralj je zarobljen u kutu iza vlastitog pješačkog zaklona.","Najprije žrtva dame, zatim žrtva lovca razbijaju zaštitu prije nego daleko napredovali pješak matira.","Dama uzima na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht in der Ecke und ein Abzugsschach beendet die Partie.","Ein Damenopfer lockt eine Figur, dann gibt der Springer das entscheidende Abzugsschach.","Dame schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king sits in the corner and a discovered check ends the game.","A queen sacrifice lures a defender, then the knight gives the decisive discovered check.","Queen takes on h2 — starting a forced mate."],"hr":["Bijeli kralj je u kutu, a otkriveni šah završava partiju.","Žrtva dame odvlači branitelja, a skakač zatim daje odlučujući otkriveni šah.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in der Ecke von seinen eigenen Figuren erstickt.","Ein Springer- und ein Damenopfer räumen das Feld, ehe der Springer das Erstickungsmatt gibt.","Springer schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king is smothered in the corner by his own pieces.","A knight and a queen sacrifice clear the way before the knight gives the smothered mate.","Knight takes on f8 — starting a forced mate."],"hr":["Crni kralj je ugušen u kutu vlastitim figurama.","Žrtva skakača i dame čiste put prije nego skakač zadaje ugušeni mat.","Skakač uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König versteckt sich in der Ecke, doch ein erstickendes Netz schließt sich.","Ein Springeropfer und ein Damenopfer öffnen die Lage, dann setzt der Springer erstickt matt.","Springer schlägt auf f3 – Beginn eines erzwungenen Matts."],"en":["The white king hides in the corner, but a smothering net closes in.","A knight sacrifice and a queen sacrifice open things up, then the knight delivers smothered mate.","Knight takes on f3 — starting a forced mate."],"hr":["Bijeli kralj se skriva u kutu, ali se mreža guši oko njega.","Žrtva skakača i žrtva dame otvaraju poziciju, a skakač zatim zadaje ugušeni mat.","Skakač uzima na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in der Ecke von den eigenen Steinen eingeschnürt.","Ein Damen- und ein Springermanöver bereiten das Erstickungsmatt durch den Springer vor.","Dame schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king is bound in the corner by his own men.","A queen and knight manoeuvre prepare the smothered mate by the knight.","Queen takes on g7 — starting a forced mate."],"hr":["Crni kralj je svezan u kutu vlastitim figurama.","Manevar dame i skakača pripremaju ugušeni mat skakačem.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steckt fest und ein Springer schnürt das Mattnetz zu.","Ein Damenopfer und Abtausche räumen das Feld, ehe der Springer den König erstickt mattsetzt.","Dame schlägt auf e7 – Beginn eines erzwungenen Matts."],"en":["The black king is stuck and a knight seals the mating net.","A queen sacrifice and exchanges clear the way before the knight smothers the king.","Queen takes on e7 — starting a forced mate."],"hr":["Crni kralj je zaglavljen, a skakač zatvara matnu mrežu.","Žrtva dame i razmjene čiste put prije nego skakač uguši kralja.","Dama uzima na e7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und ein vorrückender Bauer verschließt ihm alles.","Ein Turm- und ein Bauernopfer öffnen die Linie, dann setzt der Turm matt.","Turm schlägt auf e7 – Beginn eines erzwungenen Matts."],"en":["The black king clings to the edge and an advancing pawn shuts everything down.","A rook and a pawn sacrifice open the line, then the rook mates.","Rook takes on e7 — starting a forced mate."],"hr":["Crni kralj se drži uz rub, a napredujući pješak mu sve zatvara.","Žrtva topa i pješaka otvaraju liniju, a top zatim matira.","Top uzima na e7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in die Ecke gedrängt und ein Springer webt das Mattnetz.","Springermanöver und ein Damenopfer bringen den König zur Strecke, dann liefert der Springer das Erstickungsmatt.","Springer schlägt auf c7 – Beginn eines erzwungenen Matts."],"en":["The black king is forced into the corner and a knight weaves the mating net.","Knight manoeuvres and a queen sacrifice corner the king, then the knight gives the smothered mate.","Knight takes on c7 — starting a forced mate."],"hr":["Crni kralj je stjeran u kut, a skakač plete matnu mrežu.","Manevri skakača i žrtva dame stjeraju kralja, a skakač zatim zadaje ugušeni mat.","Skakač uzima na c7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in der Ecke von seinen eigenen Figuren erstickt.","Springeropfer und ein Damenopfer öffnen die Verteidigung, ehe der Springer erstickt mattsetzt.","Springer schlägt auf g6 – Beginn eines erzwungenen Matts."],"en":["The black king is smothered in the corner by his own pieces.","Knight sacrifices and a queen sacrifice peel open the defence before the knight mates.","Knight takes on g6 — starting a forced mate."],"hr":["Crni kralj je ugušen u kutu vlastitim figurama.","Žrtve skakača i žrtva dame razbijaju obranu prije nego skakač zadaje ugušeni mat.","Skakač uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in die Ecke getrieben und kein Feld bleibt ihm.","Ein Damenopfer und ein Springervorstoß schließen das Netz, ehe der Springer mattsetzt.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is driven to the corner with no square left.","A queen sacrifice and a knight thrust close the net before the knight mates.","Queen takes on h7 — starting a forced mate."],"hr":["Crni kralj je stjeran u kut i nema mu preostalog polja.","Žrtva dame i prodor skakača zatvaraju mrežu prije nego skakač matira.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.024' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König hat noch nicht rochiert und wird im Zentrum eingefangen.","Ein Damenopfer treibt den König, dann jagt ihn der Springer ins Erstickungsmatt.","Dame schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king has not castled and gets caught in the centre.","A queen sacrifice drives the king, then the knight hunts it into a smothered mate.","Queen takes on f8 — starting a forced mate."],"hr":["Crni kralj nije rokirao i biva uhvaćen u centru.","Žrtva dame tjera kralja, a skakač ga zatim goni u ugušeni mat.","Dama uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.025' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in der Ecke von den eigenen Steinen erdrückt.","Mehrere Springersprünge und ein Damenopfer enden im Erstickungsmatt durch den Springer.","Dame schlägt auf e6 – Beginn eines erzwungenen Matts."],"en":["The black king is crushed in the corner by his own men.","A sequence of knight hops and a queen sacrifice end in a smothered mate by the knight.","Queen takes on e6 — starting a forced mate."],"hr":["Crni kralj je pritisnut u kutu vlastitim figurama.","Niz skokova skakača i žrtva dame završavaju ugušenim matom skakača.","Dama uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.026' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König erstickt in der Ecke an seinen eigenen Figuren.","Springermanöver und ein Damenopfer öffnen die Lage, ehe der Springer erstickt mattsetzt.","Läufer schlägt auf f5 – Beginn eines erzwungenen Matts."],"en":["The black king suffocates in the corner among his own pieces.","Knight manoeuvres and a queen sacrifice open things up before the knight delivers smothered mate.","Bishop takes on f5 — starting a forced mate."],"hr":["Crni kralj se guši u kutu okružen vlastitim figurama.","Manevri skakača i žrtva dame otvaraju poziciju prije nego skakač zadaje ugušeni mat.","Lovac uzima na f5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:014.027' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird aus seiner Deckung gezerrt und durch die Reihen gejagt.","Ein Damenopfer lockt den König heraus, dann treiben Springer und Turm ihn ins Matt.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is dragged from cover and chased across the ranks.","A queen sacrifice lures the king out, then knight and rook drive it into mate.","Queen takes on h7 — starting a forced mate."],"hr":["Crni kralj biva izvučen iz zaklona i tjeran preko redova.","Žrtva dame izvlači kralja, a skakač i top ga zatim tjeraju u mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke und ein Abzugsschach erledigt ihn.","Ein Damenopfer zerrt den König heraus, dann öffnet der Springer den Weg für das Turmmatt.","Dame schlägt auf h8 – Beginn eines erzwungenen Matts."],"en":["The black king clings to the corner and a discovered check finishes it.","A queen sacrifice drags the king out, then the knight clears the path for the rook to mate.","Queen takes on h8 — starting a forced mate."],"hr":["Crni kralj se drži u kutu, a otkriveni šah ga dokrajčuje.","Žrtva dame izvlači kralja, a skakač zatim otvara put topu za mat.","Dama uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.003' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht am Rand und ein Doppelschach wird ihm zum Verhängnis.","Ein Damenopfer lockt eine Figur weg, dann gibt der Bauer das tödliche Abzugsschach.","Dame schlägt auf g5 – Beginn eines erzwungenen Matts."],"en":["The black king stands on the edge and a discovered check proves fatal.","A queen sacrifice lures a piece away, then the pawn gives the killing discovered check.","Queen takes on g5 — starting a forced mate."],"hr":["Crni kralj stoji uz rub, a otkriveni šah postaje koban.","Žrtva dame odvlači figuru, a pješak zatim daje smrtonosni otkriveni šah.","Dama uzima na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand eingesperrt und ein Doppelschach gibt den Ausschlag.","Ein Läufer öffnet mit Doppelschach die Linie, dann setzt der Turm matt.","Läufer nach g8 – Beginn eines erzwungenen Matts."],"en":["The black king is boxed in on the edge and a double check tips the scale.","A bishop opens with double check, then the rook mates.","Bishop to g8 — starting a forced mate."],"hr":["Crni kralj je zatvoren uz rub, a dvostruki šah presuđuje.","Lovac otvara dvostrukim šahom, a top zatim matira.","Lovac na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Abzugsschach aus der Deckung getrieben.","Die Dame zieht weg und gibt mit dem Läufer Abzugsschach, dann folgt das Matt.","Dame nach e7 – Beginn eines erzwungenen Matts."],"en":["The black king is driven from cover by a discovered check.","The queen steps aside to unveil a bishop check, then mate follows.","Queen to e7 — starting a forced mate."],"hr":["Crni kralj biva istjeran iz zaklona otkrivenim šahom.","Dama se odmiče i otkriva šah lovcem, a zatim slijedi mat.","Dama na e7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht offen und ein Abzugsschach zieht das Netz zu.","Der Springer zieht mit Abzugsschach weg, dann setzt die Dame matt.","Springer schlägt auf f5 – Beginn eines erzwungenen Matts."],"en":["The black king stands exposed and a discovered check draws the net tight.","The knight moves with discovered check, then the queen mates.","Knight takes on f5 — starting a forced mate."],"hr":["Crni kralj stoji izložen, a otkriveni šah zateže mrežu.","Skakač se odmiče otkrivenim šahom, a dama zatim matira.","Skakač uzima na f5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht hinter dünner Deckung und ein Opfer reißt sie ein.","Ein Damenopfer lenkt den König ab, dann setzt der Turm matt.","Dame schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king sits behind a thin shield that a sacrifice tears away.","A queen sacrifice deflects the king, then the rook mates.","Queen takes on g7 — starting a forced mate."],"hr":["Crni kralj je iza tankog zaklona koji žrtva razbija.","Žrtva dame odvlači kralja, a top zatim matira.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus seiner Deckung gelockt.","Ein Turmopfer zerrt den König heraus, dann gibt der Läufer das Matt.","Turm schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king is lured from his shelter by a sacrifice.","A rook sacrifice drags the king out, then the bishop delivers mate.","Rook takes on f8 — starting a forced mate."],"hr":["Crni kralj biva izmamljen iz zaklona žrtvom.","Žrtva topa izvlači kralja, a lovac zatim daje mat.","Top uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch eine Opferfolge in der Ecke gestellt.","Ein Damenopfer und ein Bauernvorstoß bahnen den Weg, dann setzt der Läufer matt.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is cornered through a chain of sacrifices.","A queen sacrifice and a pawn push pave the way, then the bishop mates.","Queen takes on h7 — starting a forced mate."],"hr":["Crni kralj biva stjeran u kut nizom žrtava.","Žrtva dame i prodor pješaka utiru put, a lovac zatim matira.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke kaum gedeckt und ein Opfer öffnet ihn.","Ein Läuferopfer lockt eine Figur weg, dann gibt die Dame das Matt.","Läufer schlägt auf g8 – Beginn eines erzwungenen Matts."],"en":["The black king is barely covered in the corner and a sacrifice opens it.","A bishop sacrifice lures a piece away, then the queen delivers mate.","Bishop takes on g8 — starting a forced mate."],"hr":["Crni kralj je jedva pokriven u kutu, a žrtva ga otvara.","Žrtva lovca odvlači figuru, a dama zatim daje mat.","Lovac uzima na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht offen und ein Springer schnürt das Netz zu.","Der Springer zieht mit Abzugsschach weg und springt dann zum Matt ein.","Springer schlägt auf c5 – Beginn eines erzwungenen Matts."],"en":["The black king stands exposed and a knight seals the net.","The knight moves with discovered check and then leaps in for mate.","Knight takes on c5 — starting a forced mate."],"hr":["Crni kralj stoji izložen, a skakač zatvara mrežu.","Skakač se odmiče otkrivenim šahom, a zatim uskače za mat.","Skakač uzima na c5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus der Deckung gezogen.","Ein Läuferopfer lenkt den König ab, dann setzt die Dame matt.","Läufer schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king is pulled out of cover by a sacrifice.","A bishop sacrifice deflects the king, then the queen mates.","Bishop takes on g7 — starting a forced mate."],"hr":["Crni kralj biva izvučen iz zaklona žrtvom.","Žrtva lovca odvlači kralja, a dama zatim matira.","Lovac uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht offen und ein Springer schließt das Mattnetz.","Der Springer schlägt mit Schach und springt dann ins entscheidende Matt.","Springer schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["The black king stands exposed and a knight closes the mating net.","The knight captures with check and then leaps in for the decisive mate.","Knight takes on f7 — starting a forced mate."],"hr":["Crni kralj stoji izložen, a skakač zatvara matnu mrežu.","Skakač uzima sa šahom, a zatim uskače za odlučujući mat.","Skakač uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der gegnerische König ist am Rand eingeengt und ein Lockopfer reißt seinen letzten Schutz weg.","Eine Dame opfert sich, damit der Läufer das Mattnetz schließt.","Dame nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["The enemy king is hemmed in on the edge and a sacrifice tears away his last cover.","A queen sacrifices herself so the bishop can spring the mating net.","Queen takes on h7 — starting a forced mate."],"hr":["Protivnički kralj je stiješnjen na rubu, a žrtva mu otkida posljednju zaštitu.","Dama se žrtvuje da bi lovac zatvorio matnu mrežu.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König ist hinter eigenen Steinen gefangen und eine Ablenkung legt ihn frei.","Ein Damenopfer öffnet die Diagonale für den tödlichen Läufer.","Dame nimmt auf f7 – Auftakt zum erzwungenen Matt."],"en":["The king is trapped behind his own men and a deflection lays him bare.","A queen sacrifice clears the diagonal for the lethal bishop.","Queen takes on f7 — beginning a forced mate."],"hr":["Kralj je zarobljen iza vlastitih figura, a odvlačenje ga ogoljuje.","Žrtva dame otvara dijagonalu smrtonosnom lovcu.","Dama uzima na f7 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand wird durch ein Opfer in ein Springermattnetz gezwungen.","Eine Dame opfert sich, damit ein Springer das tödliche Schach gibt.","Dame nach h6 – Auftakt zum erzwungenen Matt."],"en":["A sacrifice forces the cornered king into a knight''s mating net.","A queen offers herself so a knight can deliver the killing check.","Queen to h6 — starting a forced mate."],"hr":["Žrtva tjera stiješnjenog kralja u skakačevu matnu mrežu.","Dama se žrtvuje da bi skakač dao smrtonosni šah.","Dama na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König wird durch ein Opfer freigelegt und am Rand erstickt.","Ein Damenopfer holt den König heraus, dann gibt ein Turm das Schach.","Dame nimmt auf g7 – Beginn eines erzwungenen Matts."],"en":["A sacrifice strips the king''s shelter and smothers him on the edge.","A queen sacrifice drags the king out, then a rook delivers the check.","Queen takes on g7 — starting a forced mate."],"hr":["Žrtva otkriva kralja i guši ga na rubu.","Žrtva dame izvlači kralja, a zatim top daje šah.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König in der Mitte wird durch Turmschachs ins offene Feld getrieben.","Zwei Türme arbeiten zusammen und der Läufer schneidet den Fluchtweg ab.","Turm nimmt auf c6 – Auftakt zum erzwungenen Matt."],"en":["Rook checks drive the centralised king into the open.","The two rooks cooperate while the bishop cuts off escape.","Rook takes on c6 — beginning a forced mate."],"hr":["Šahovi topom tjeraju kralja iz sredine na otvoreno.","Dva topa surađuju dok lovac presijeca bijeg.","Top uzima na c6 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt in der Ecke und ein Opfer öffnet die Mattlinie.","Erst opfert sich der Läufer, dann setzt die Dame mit Bauernhilfe matt.","Läufer nach h2 – Beginn eines erzwungenen Matts."],"en":["The white king clings to the corner and a sacrifice opens the mating line.","A bishop sacrifices first, then the queen mates with a pawn''s help.","Bishop to h2 — starting a forced mate."],"hr":["Bijeli kralj je priljepljen u kutu, a žrtva otvara matnu liniju.","Prvo se žrtvuje lovac, a zatim dama mati uz pomoć pješaka.","Lovac na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand wird durch einen vorgerückten Bauern erstickt.","Ein Turm jagt den König und der weit vorgeschobene Bauer schneidet alles ab.","Turm nimmt auf g7 – Auftakt zum erzwungenen Matt."],"en":["The king on the edge is smothered by an advanced pawn.","A rook hunts the king while the far-advanced pawn seals the cage.","Rook takes on g7 — beginning a forced mate."],"hr":["Kralj na rubu je ugušen napredovanim pješakom.","Top progoni kralja dok daleko napredovani pješak zatvara kavez.","Top uzima na g7 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König wird durch Opfer aus der Deckung gerissen und am Rand gestellt.","Eine Dame und ein Springer opfern sich, damit ein Turm mattsetzt.","Dame nimmt auf h8 – Beginn eines erzwungenen Matts."],"en":["Sacrifices rip the king from his shelter and pin him to the edge.","A queen and a knight give themselves up so a rook can mate.","Queen takes on h8 — starting a forced mate."],"hr":["Žrtve izvlače kralja iz zaklona i pribijaju ga uz rub.","Dama i skakač se žrtvuju da bi top matirao.","Dama uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
