UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist hinter seinen eigenen Bauern eingemauert und kann den Springer-Attacken nicht entkommen.","Ein Springer tanzt um den eingeengten König herum, bis der Turm das letzte Wort hat.","Springer nach g4 – leitet das erzwungene Matt ein."],"en":["The white king is boxed in behind his own pawns and cannot escape the knight''s dance.","A knight hops around the cramped king until the rook finishes the job.","Knight to g4 — beginning a forced mate."],"hr":["Bijeli kralj je zazidan iza vlastitih pješaka i ne može pobjeći skakačevom plesu.","Skakač skače oko stiješnjenog kralja dok top ne dovrši posao.","Skakač na g4 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.076' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und seine Verteidiger sind hoffnungslos überlastet.","Ein Turmopfer reißt die Stellung auf, danach gibt die Dame das letzte Schach.","Turm schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king clings to the edge while his defenders are hopelessly overloaded.","A rook sacrifice tears the position open, then the queen delivers the final blow.","Rook takes on g7 — starting a forced mate."],"hr":["Crni kralj se drži ruba dok su mu branitelji beznadno preopterećeni.","Žrtva topa razbija poziciju, a zatim dama daje konačni udarac.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.077' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht im Freien und ein Springervorstoß raubt ihm die letzten Felder.","Ein Springer springt mitten ins Zentrum und der Läufer setzt den Schlusspunkt.","Springer nach e5 – leitet das erzwungene Matt ein."],"en":["The black king stands in the open and a knight thrust strips away its last squares.","A knight leaps into the centre and the bishop delivers the finishing check.","Knight to e5 — beginning a forced mate."],"hr":["Crni kralj stoji na otvorenom, a skok skakača mu oduzima posljednja polja.","Skakač skače u središte, a lovac zadaje završni šah.","Skakač na e5 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.078' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird zum Rand gejagt, wo ihm die Felder ausgehen.","Springer und Turm treiben den König gemeinsam in das Mattnetz.","Springer nach h6 – Beginn einer erzwungenen Mattjagd."],"en":["The black king is hunted to the edge, where it runs out of squares.","The knight and rook drive the king together into the mating net.","Knight to h6 — starting a forced king hunt to mate."],"hr":["Crni kralj je natjeran na rub, gdje mu ponestaje polja.","Skakač i top zajedno tjeraju kralja u matnu mrežu.","Skakač na h6 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.079' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Königsstellung ist durch einen weit vorgeschobenen Bauern aufgerissen.","Ein Damenopfer öffnet die Linie und Turm samt Springer jagen den König nieder.","Dame schlägt auf h7 – leitet das erzwungene Matt ein."],"en":["Black''s king cover is torn open by a far-advanced pawn.","A queen sacrifice opens the file and rook plus knight run the king down.","Queen takes on h7 — beginning a forced mate."],"hr":["Zaklon crnog kralja razbijen je daleko napredovanim pješakom.","Žrtva dame otvara liniju, a top i skakač obaraju kralja.","Dama uzima na h7 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.080' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist nur dünn gedeckt und seine Verteidiger lassen sich ablenken.","Ein Damenopfer auf dem Schwachpunkt ebnet Springer und Springer den Weg.","Dame schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["The black king is thinly guarded and its defenders can be deflected.","A queen sacrifice on the weak point clears the way for the knights.","Queen takes on f7 — starting a forced mate."],"hr":["Crni kralj je slabo čuvan, a njegovi se branitelji mogu odvući.","Žrtva dame na slaboj točki otvara put skakačima.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.081' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Rochadestellung ist durch einen Bauern bis ans Brett gesprengt.","Ein Damenopfer reißt die Linie auf, dann übernehmen die Springer die Jagd.","Dame schlägt auf h7 – leitet das erzwungene Matt ein."],"en":["Black''s castled position is blasted open by a pawn right up against the king.","A queen sacrifice rips open the file, then the knights take over the hunt.","Queen takes on h7 — beginning a forced mate."],"hr":["Rošada crnog kralja razbijena je pješakom tik uz kralja.","Žrtva dame otvara liniju, a zatim skakači preuzimaju lov.","Dama uzima na h7 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.082' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird ins Freie gelockt und gnadenlos verfolgt.","Ein Damenopfer startet die Jagd, die der Turm dann vollendet.","Dame schlägt auf g8 – Beginn einer erzwungenen Mattjagd."],"en":["The black king is lured into the open and relentlessly pursued.","A queen sacrifice begins the hunt that the rook then completes.","Queen takes on g8 — starting a forced king hunt to mate."],"hr":["Crni kralj je namamljen na otvoreno i nemilosrdno progonjen.","Žrtva dame započinje lov koji top zatim dovršava.","Dama uzima na g8 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.083' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt in der Ecke und seine Grundreihe ist tödlich schwach.","Ein Turmopfer lockt den König heran, dann gibt der Läufer das Matt.","Turm schlägt auf b2 – leitet das erzwungene Matt ein."],"en":["The white king is stuck in the corner with a fatal back-rank weakness.","A rook sacrifice draws the king in, then the bishop delivers mate.","Rook takes on b2 — beginning a forced mate."],"hr":["Bijeli kralj je zaglavljen u kutu sa smrtonosno slabom zadnjom linijom.","Žrtva topa privlači kralja, a zatim lovac daje mat.","Top uzima na b2 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.084' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist entblößt und wird quer über das Brett getrieben.","Ein Springervorstoß eröffnet die Jagd, die Dame und Turm vollenden.","Springer nach g5 – Beginn einer erzwungenen Mattjagd."],"en":["The black king is exposed and chased across the whole board.","A knight thrust opens the hunt that the queen and rook complete.","Knight to g5 — starting a forced king hunt to mate."],"hr":["Crni kralj je izložen i progonjen preko cijele ploče.","Skok skakača otvara lov koji dama i top dovršavaju.","Skakač na g5 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.085' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist eingeengt und auf der Grundreihe verwundbar.","Ein Turmopfer öffnet die Stellung, dann setzt das leichte Material den König matt.","Turm schlägt auf g2 – leitet das erzwungene Matt ein."],"en":["The white king is cramped and vulnerable on its first rank.","A rook sacrifice opens the position, then the minor pieces close in for mate.","Rook takes on g2 — beginning a forced mate."],"hr":["Bijeli kralj je stiješnjen i ranjiv na prvoj liniji.","Žrtva topa otvara poziciju, a zatim laki figurni materijal zatvara matnu mrežu.","Top uzima na g2 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.086' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist eingeengt und kann den Läufern und dem Turm nicht entkommen.","Ein Läufervorstoß engt den König ein, dann liefern Turm und Läufer das Matt.","Läufer nach e3 – leitet das erzwungene Matt ein."],"en":["The white king is hemmed in and cannot escape the bishops and rook.","A bishop thrust pins the king down, then rook and bishop seal the mate.","Bishop to e3 — beginning a forced mate."],"hr":["Bijeli kralj je sabijen i ne može pobjeći lovcima i topu.","Skok lovca prikiva kralja, a zatim top i lovac zatvaraju mat.","Lovac na e3 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.087' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist offen und seine wenigen Verteidiger werden weggelenkt.","Ein Turmopfer lockt den König heraus, dann jagen Dame und Läufer ihn nieder.","Turm schlägt auf g2 – Beginn einer erzwungenen Mattjagd."],"en":["The white king is open and its few defenders are dragged away.","A rook sacrifice pulls the king out, then queen and bishop run it down.","Rook takes on g2 — starting a forced king hunt to mate."],"hr":["Bijeli kralj je otvoren, a njegovi malobrojni branitelji se odvlače.","Žrtva topa izvlači kralja, a zatim dama i lovac ga obaraju.","Top uzima na g2 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.088' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Königsstellung ist von weißen Figuren umzingelt.","Ein Turmopfer reißt die Deckung weg, dann setzen Läufer und Dame nach.","Turm schlägt auf g7 – leitet das erzwungene Matt ein."],"en":["Black''s king position is surrounded by White''s pieces.","A rook sacrifice tears away the cover, then bishop and queen follow up.","Rook takes on g7 — beginning a forced mate."],"hr":["Pozicija crnog kralja okružena je bijelim figurama.","Žrtva topa otrgne zaklon, a zatim lovac i dama nastavljaju napad.","Top uzima na g7 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.089' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke gefangen und seine Verteidiger reichen nicht.","Ein Damenopfer öffnet die Linie, dann häufen Türme und Läufer den Druck zum Matt.","Dame schlägt auf h2 – leitet das erzwungene Matt ein."],"en":["The white king is trapped in the corner and its defence falls short.","A queen sacrifice opens the file, then rooks and bishop pile on for mate.","Queen takes on h2 — beginning a forced mate."],"hr":["Bijeli kralj je zarobljen u kutu, a obrana mu nije dovoljna.","Žrtva dame otvara liniju, a zatim topovi i lovac gomilaju pritisak do mata.","Dama uzima na h2 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.090' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist durch einen keilenden Bauern eingeklemmt und kann nicht atmen.","Ein Damenopfer lockt den König heraus, dann liefern die Türme das Matt.","Dame schlägt auf h7 – leitet das erzwungene Matt ein."],"en":["The black king is jammed in by a wedging pawn and cannot breathe.","A queen sacrifice draws the king out, then the rooks deliver mate.","Queen takes on h7 — beginning a forced mate."],"hr":["Crni kralj je zaglavljen ukliještenim pješakom i ne može disati.","Žrtva dame izvlači kralja, a zatim topovi daju mat.","Dama uzima na h7 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.091' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist entblößt und seine Grundreihe wartet auf den Schlag.","Ein Damenopfer reißt die Königsstellung auf, dann setzen Turm und Springer nach.","Dame schlägt auf g2 – leitet das erzwungene Matt ein."],"en":["The white king is exposed and its back rank is waiting for the blow.","A queen sacrifice rips open the king''s shelter, then rook and knight follow up.","Queen takes on g2 — beginning a forced mate."],"hr":["Bijeli kralj je izložen, a njegova zadnja linija čeka udarac.","Žrtva dame razbija kraljev zaklon, a zatim top i skakač nastavljaju.","Dama uzima na g2 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.092' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist nur dünn gedeckt und seine Verteidiger lassen sich ablenken.","Ein Damenopfer lenkt den Verteidiger ab, dann übernehmen die Türme die Arbeit.","Dame nach f6 – leitet das erzwungene Matt ein."],"en":["The black king is thinly defended and its guards can be deflected.","A queen sacrifice deflects the defender, then the rooks take over.","Queen to f6 — beginning a forced mate."],"hr":["Crni kralj je slabo branjen, a čuvari mu se mogu odvući.","Žrtva dame odvlači branitelja, a zatim topovi preuzimaju posao.","Dama na f6 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.093' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist hinter dünner Deckung in der Ecke verwundbar.","Ein Bauernopfer öffnet die Linie, dann setzen Springer und Türme den König matt.","Bauer schlägt auf h2 – leitet das erzwungene Matt ein."],"en":["The white king is vulnerable behind thin cover in the corner.","A pawn sacrifice opens the line, then knight and rooks mate the king.","Pawn takes on h2 — beginning a forced mate."],"hr":["Bijeli kralj je ranjiv iza tankog zaklona u kutu.","Žrtva pješaka otvara liniju, a zatim skakač i topovi matiraju kralja.","Pješak uzima na h2 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.094' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König muss quer über das Brett gehetzt werden, bis das Netz zuschnappt.","Turm, Springer und Läufer treiben den flüchtenden König gemeinsam in die Falle.","Turm nach e8 – Beginn einer erzwungenen Mattjagd."],"en":["The black king must be chased across the board until the net snaps shut.","Rook, knight and bishop together drive the fleeing king into a trap.","Rook to e8 — starting a forced king hunt to mate."],"hr":["Crni kralj se mora progoniti preko cijele ploče dok se mreža ne zatvori.","Top, skakač i lovac zajedno tjeraju kralja u bijegu u zamku.","Top na e8 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird ins Freie gelockt und über das Brett gejagt.","Ein Damenschach startet die Verfolgung, die der Läufer dann beendet.","Dame schlägt auf e8 – Beginn einer erzwungenen Mattjagd."],"en":["The black king is lured into the open and hunted across the board.","A queen check starts the chase that the bishop then ends.","Queen takes on e8 — starting a forced king hunt to mate."],"hr":["Crni kralj je namamljen na otvoreno i progonjen preko ploče.","Šah damom započinje potjeru koju lovac zatim okončava.","Dama uzima na e8 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird aus seiner Deckung gezerrt und immer weiter getrieben.","Ein Läufer- und Damenschach jagen den König, bis er kein Feld mehr hat.","Läufer schlägt auf c4 – Beginn einer erzwungenen Mattjagd."],"en":["The white king is dragged out of cover and driven ever further.","Bishop and queen checks hunt the king until it has no square left.","Bishop takes on c4 — starting a forced king hunt to mate."],"hr":["Bijeli kralj je izvučen iz zaklona i tjeran sve dalje.","Šahovi lovcem i damom progone kralja dok mu ne ostane nijedno polje.","Lovac uzima na c4 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht im Zentrum frei und wird unaufhaltsam verfolgt.","Ein Damenvorstoß beginnt die Jagd, die Springer und Läufer vollenden.","Dame schlägt auf d6 – Beginn einer erzwungenen Mattjagd."],"en":["The black king stands exposed in the centre and is relentlessly pursued.","A queen thrust opens the hunt that knight and bishop complete.","Queen takes on d6 — starting a forced king hunt to mate."],"hr":["Crni kralj stoji izložen u središtu i nemilosrdno se progoni.","Skok dame otvara lov koji skakač i lovac dovršavaju.","Dama uzima na d6 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König irrt im Zentrum umher und wird Schritt für Schritt eingekreist.","Ein Damenvorstoß und Figurenopfer treiben den König ins Mattnetz.","Dame nach d5 – Beginn einer erzwungenen Mattjagd."],"en":["The black king wanders in the centre and is encircled step by step.","A queen thrust and piece sacrifices herd the king into the mating net.","Queen to d5 — starting a forced king hunt to mate."],"hr":["Crni kralj luta u središtu i okružuje se korak po korak.","Skok dame i žrtve figura tjeraju kralja u matnu mrežu.","Dama na d5 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist ins Freie getrieben und kann nicht mehr zurück.","Ein stiller Springerzug knüpft das Netz, bevor die schweren Figuren zuschlagen.","Springer nach a4 – Beginn einer erzwungenen Mattjagd."],"en":["The black king has been driven into the open and cannot return.","A quiet knight move tightens the net before the heavier pieces strike.","Knight to a4 — starting a forced king hunt to mate."],"hr":["Crni kralj je istjeran na otvoreno i ne može se vratiti.","Tihi potez skakača zateže mrežu prije nego što teške figure udare.","Skakač na a4 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird aus seiner Deckung gezogen und über das Brett gehetzt.","Ein Damenopfer öffnet die Jagd, die Turm und Läufer beenden.","Dame schlägt auf h2 – Beginn einer erzwungenen Mattjagd."],"en":["The white king is pulled out of cover and chased across the board.","A queen sacrifice opens the hunt that rook and bishop finish.","Queen takes on h2 — starting a forced king hunt to mate."],"hr":["Bijeli kralj je izvučen iz zaklona i progonjen preko ploče.","Žrtva dame otvara lov koji top i lovac okončavaju.","Dama uzima na h2 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird aus seiner Stellung gerissen und unerbittlich verfolgt.","Ein Turmopfer lockt den König heraus, dann jagen Läufer und Dame ihn nieder.","Turm schlägt auf f7 – Beginn einer erzwungenen Mattjagd."],"en":["The black king is torn from its position and relentlessly pursued.","A rook sacrifice draws the king out, then bishop and queen run it down.","Rook takes on f7 — starting a forced king hunt to mate."],"hr":["Crni kralj je istrgnut iz svoje pozicije i neumoljivo progonjen.","Žrtva topa izvlači kralja, a zatim lovac i dama ga obaraju.","Top uzima na f7 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand gefangen und wird in die Ecke getrieben.","Ein stiller Läuferzug spannt das Netz, dann jagen Turm und Springer den König.","Läufer schlägt auf d5 – Beginn einer erzwungenen Mattjagd."],"en":["The black king is caught on the edge and herded into the corner.","A quiet bishop move sets the net, then rook and knight hunt the king.","Bishop takes on d5 — starting a forced king hunt to mate."],"hr":["Crni kralj je uhvaćen na rubu i tjeran u kut.","Tihi potez lovca postavlja mrežu, a zatim top i skakač progone kralja.","Lovac uzima na d5 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht ungeschützt in der Brettmitte und wird umzingelt.","Ein Turmopfer öffnet die Jagd, die Dame und Turm dann vollenden.","Turm schlägt auf e5 – Beginn einer erzwungenen Mattjagd."],"en":["The black king stands unguarded in mid-board and gets surrounded.","A rook sacrifice opens the hunt that queen and rook then complete.","Rook takes on e5 — starting a forced king hunt to mate."],"hr":["Crni kralj stoji nezaštićen na sredini ploče i biva okružen.","Žrtva topa otvara lov koji dama i top zatim dovršavaju.","Top uzima na e5 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Rochadestellung wird gesprengt und der König ins Freie getrieben.","Ein Damenopfer reißt die Deckung weg, dann jagen Turm und Springer den König.","Dame schlägt auf h7 – Beginn einer erzwungenen Mattjagd."],"en":["Black''s castled shelter is blasted open and the king driven into the open.","A queen sacrifice tears away the cover, then rook and knight hunt the king.","Queen takes on h7 — starting a forced king hunt to mate."],"hr":["Rošada crnog kralja je razbijena, a kralj istjeran na otvoreno.","Žrtva dame otrgne zaklon, a zatim top i skakač progone kralja.","Dama uzima na h7 — početak prisilnog lova na kralja do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wartet ungeschützt im Zentrum, während deine Dame und Türme ihn umzingeln.","Deine Dame öffnet das Treiben, doch am Ende setzt ein Turm dem flüchtenden König matt.","Dame nach b2 – der Beginn eines erzwungenen Matts."],"en":["The white king sits exposed in the centre while your queen and rooks close in.","Your queen begins the hunt, and in the end a rook delivers mate to the running king.","Queen to b2 — the start of a forced mate."],"hr":["Bijeli kralj stoji izložen u sredini dok ga tvoja dama i topovi opkoljavaju.","Tvoja dama započinje lov, a na kraju top daje mat kralju u bijegu.","Dama na b2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird aus seinem Versteck gezerrt und über das Brett gejagt.","Erst öffnet ein Bauer die Stellung, dann treiben Dame und Läufer den König ins Matt.","Bauer nach d3 – der Beginn eines erzwungenen Matts."],"en":["The white king is dragged out of hiding and chased across the board.","A pawn cracks the position open, then queen and bishop drive the king to mate.","Pawn to d3 — the start of a forced mate."],"hr":["Bijeli kralj biva izvučen iz skrovišta i protjeran preko ploče.","Pješak otvara poziciju, a zatim dama i lovac tjeraju kralja u mat.","Pješak na d3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird mit einem Damenopfer aus der Deckung gelockt und gejagt.","Nach dem Opfer auf der Springerlinie treiben Turm und Bauern den König ins Netz.","Dame nimmt auf h7 – der Beginn eines erzwungenen Matts."],"en":["A queen sacrifice tears the black king out of its shelter and sends it running.","After the sacrifice, your rook and pawns drive the exposed king into the net.","Queen takes on h7 — the start of a forced mate."],"hr":["Žrtva dame izvlači crnog kralja iz zaklona i šalje ga u bijeg.","Nakon žrtve top i pješaci tjeraju izloženog kralja u mrežu.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König erstickt in der eigenen Ecke zwischen seinen Figuren.","Ein Läuferopfer reißt die Deckung auf, dann liefern Springer und Bauer das Matt.","Läufer nimmt auf g2 – der Beginn eines erzwungenen Matts."],"en":["The white king is suffocating in its own corner among its pieces.","A bishop sacrifice rips open the cover, then a knight and pawn finish the job.","Bishop takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj se guši u vlastitom kutu među svojim figurama.","Žrtva lovca razbija zaklon, a zatim skakač i pješak dovršavaju mat.","Lovac uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht entblößt am Rand, sein Schutzwall ist weg.","Ein Damenopfer reißt den Bauernschild ab, dann treiben Turm und Figuren den König ins Matt.","Dame nimmt auf h7 – der Beginn eines erzwungenen Matts."],"en":["The black king is left bare on the edge with its shield gone.","A queen sacrifice strips the pawn cover, then rook and pieces force the king to mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj ostaje go na rubu, štit mu je nestao.","Žrtva dame skida pješački zaklon, a top i figure tjeraju kralja u mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird aus seiner Festung getrieben und über das Feld gejagt.","Erst opfert ein Turm sich, dann jagen Dame, Springer und Bauer den König ins Matt.","Turm nimmt auf g6 – der Beginn eines erzwungenen Matts."],"en":["The black king is pried out of its fortress and hunted across the board.","A rook offers itself first, then queen, knight and pawn run the king down to mate.","Rook takes on g6 — the start of a forced mate."],"hr":["Crni kralj biva izvučen iz tvrđave i protjeran preko ploče.","Top se prvo žrtvuje, a zatim dama, skakač i pješak love kralja u mat.","Top uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand gefangen, deine Dame führt die Attacke.","Die Dame stürzt sich auf den entblößten Königsflügel und das Matt ist erzwungen.","Dame nimmt auf h7 – der Beginn eines erzwungenen Matts."],"en":["The black king is trapped on the edge and your queen leads the charge.","The queen pounces on the bare kingside and the mate is forced from there.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj je zarobljen na rubu, a tvoja dama vodi napad.","Dama se obrušava na ogoljeli kraljev krak i mat je prisilan.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird in einer langen Jagd quer übers Brett getrieben.","Ein Läuferopfer öffnet das Tor, dann treiben Turm und Springer den König ins Matt.","Läufer nimmt auf d3 – der Beginn eines erzwungenen Matts."],"en":["The white king is run down in a long chase right across the board.","A bishop sacrifice opens the door, then rook and knight drive the king to mate.","Bishop takes on d3 — the start of a forced mate."],"hr":["Bijeli kralj biva protjeran u dugom lovu preko cijele ploče.","Žrtva lovca otvara vrata, a zatim top i skakač tjeraju kralja u mat.","Lovac uzima na d3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:016.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand und hat kaum Luft.","Deine Dame zieht den König heraus und setzt dann selbst matt.","Dame nach h4 – der Beginn eines erzwungenen Matts."],"en":["The black king is pinned to the edge with almost no air.","Your queen lures the king out and then delivers mate herself.","Queen to h4 — the start of a forced mate."],"hr":["Crni kralj je prikovan uz rub i jedva diše.","Tvoja dama izvlači kralja, a zatim sama daje mat.","Dama na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt eingemauert am Rand fest.","Deine Dame gibt das entscheidende Schach, ein Bauer riegelt das Fluchtfeld ab.","Dame nach h3 – der Beginn eines erzwungenen Matts."],"en":["The black king is walled in tight against the edge.","Your queen gives the key check while a pawn seals the escape.","Queen to h3 — the start of a forced mate."],"hr":["Crni kralj je čvrsto zazidan uz rub.","Tvoja dama daje ključni šah dok pješak zatvara polje za bijeg.","Dama na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König erstickt in der Ecke, gefangen von den eigenen Figuren.","Eine Dame stößt mitten hinein und gibt das erstickte Matt.","Dame nach d4 – matt."],"en":["The white king is smothered in the corner by its own pieces.","A queen plunges into the middle and delivers the smothered mate.","Queen to d4 — mate."],"hr":["Bijeli kralj je ugušen u kutu vlastitim figurama.","Dama upada u sredinu i daje ugušeni mat.","Dama na d4 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht entblößt in der Ecke und ein Zwischenschach öffnet alles.","Erst ein Springerschach, dann fällt die Dame mit dem tödlichen Schlag ein.","Springer nach g3 – der Beginn eines erzwungenen Matts."],"en":["The white king stands bare in the corner and an in-between check cracks it open.","First a knight check, then the queen crashes in with the decisive blow.","Knight to g3 — the start of a forced mate."],"hr":["Bijeli kralj stoji go u kutu, a međušah sve otvara.","Prvo šah skakačem, a zatim dama upada s odlučujućim udarcem.","Skakač na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Grundreihe des Weißen ist tödlich schwach.","Ein Turm dringt auf der Grundreihe ein und lässt sich nur kurz aufhalten.","Turm nach c1 – der Beginn eines erzwungenen Matts."],"en":["White''s back rank is fatally weak.","A rook invades on the back rank and can only be delayed for a moment.","Rook to c1 — the start of a forced mate."],"hr":["Bijela zadnja linija je smrtonosno slaba.","Top upada na zadnju liniju i može biti zaustavljen tek načas.","Top na c1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt in der Ecke, ein Ablenkungsopfer entscheidet.","Erst lockt ein Springer die Deckung weg, dann setzt die Dame matt.","Springer nach g4 – der Beginn eines erzwungenen Matts."],"en":["The white king is stuck in the corner and a deflection decides.","A knight first lures the defender away, then the queen delivers mate.","Knight to g4 — the start of a forced mate."],"hr":["Bijeli kralj je zaglavljen u kutu, a žrtva odvlačenja odlučuje.","Skakač prvo odvlači branitelja, a zatim dama daje mat.","Skakač na g4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird mit einem Opfer aus seinem Versteck gezogen.","Erst lockt das Opfer den König heraus, dann gibt ein Läufer das tödliche Schach.","Dame nimmt auf f7 – der Beginn eines erzwungenen Matts."],"en":["A sacrifice drags the black king out of its hiding place.","The sacrifice draws the king out, then a bishop gives the lethal check.","Queen takes on f7 — the start of a forced mate."],"hr":["Žrtva izvlači crnog kralja iz njegova skrovišta.","Žrtva izmamljuje kralja, a zatim lovac daje smrtonosni šah.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König erstickt in der Ecke zwischen seinen Figuren.","Ein Damenopfer räumt das Feld, dann gibt ein Springer das erstickte Matt.","Dame nimmt auf h7 – der Beginn eines erzwungenen Matts."],"en":["The black king is smothered in the corner among its pieces.","A queen sacrifice clears the way, then a knight gives the smothered mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj je ugušen u kutu među svojim figurama.","Žrtva dame čisti put, a zatim skakač daje ugušeni mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht am Rand mit kaum Platz zum Atmen.","Deine Dame schwenkt auf die andere Seite und schnürt den König ein.","Dame nach h1 – der Beginn eines erzwungenen Matts."],"en":["The black king sits on the edge with barely room to breathe.","Your queen swings across to the other wing and boxes the king in.","Queen to h1 — the start of a forced mate."],"hr":["Crni kralj je na rubu i jedva ima prostora za disanje.","Tvoja dama prelazi na drugo krilo i zatvara kralja.","Dama na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in seiner Stellung eingeklemmt, ein Opfer entscheidet.","Erst beseitigt das Opfer einen Verteidiger, dann gibt ein Springer das Schach.","Dame nimmt auf e8 – der Beginn eines erzwungenen Matts."],"en":["The black king is jammed in its position and a sacrifice decides.","The sacrifice first removes a defender, then a knight delivers the check.","Queen takes on e8 — the start of a forced mate."],"hr":["Crni kralj je stiješnjen u svojoj poziciji, a žrtva odlučuje.","Žrtva prvo uklanja branitelja, a zatim skakač daje šah.","Dama uzima na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist hinter eigenen Steinen eingeengt, eine Diagonale wird tödlich.","Erst öffnet ein Turmopfer die Linie, dann setzt ein Läufer matt.","Turm nimmt auf c3 – der Beginn eines erzwungenen Matts."],"en":["The white king is cramped behind its own men and a diagonal turns deadly.","A rook sacrifice opens the line first, then a bishop delivers mate.","Rook takes on c3 — the start of a forced mate."],"hr":["Bijeli kralj je stiješnjen iza vlastitih figura, a dijagonala postaje smrtonosna.","Žrtva topa prvo otvara liniju, a zatim lovac daje mat.","Top uzima na c3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt in der Ecke, eine Diagonale zielt direkt auf ihn.","Deine Dame fällt mit einem unparierbaren Schach in der Ecke ein.","Dame nach h3 – matt."],"en":["The white king clings to the corner with a diagonal aimed straight at it.","Your queen drops in with an unstoppable check by the corner.","Queen to h3 — mate."],"hr":["Bijeli kralj se drži u kutu, a dijagonala cilja ravno na njega.","Tvoja dama upada s neodbranjivim šahom kraj kuta.","Dama na h3 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht entblößt, ein Schach lenkt ihn auf das falsche Feld.","Erst treibt ein Damenschach den König, dann gibt ein Springer das Matt.","Dame nimmt auf h1 – der Beginn eines erzwungenen Matts."],"en":["The white king stands exposed and a check pushes it onto the wrong square.","A queen check drives the king first, then a knight delivers mate.","Queen takes on h1 — the start of a forced mate."],"hr":["Bijeli kralj stoji izložen, a šah ga gura na pogrešno polje.","Šah damom prvo tjera kralja, a zatim skakač daje mat.","Dama uzima na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird mit einem Opfer aus der Rochade gerissen.","Erst zieht ein Turmopfer den König heraus, dann setzt die Dame matt.","Turm nimmt auf h8 – der Beginn eines erzwungenen Matts."],"en":["A sacrifice tears the black king out of its castled shelter.","A rook sacrifice draws the king out first, then the queen delivers mate.","Rook takes on h8 — the start of a forced mate."],"hr":["Žrtva izvlači crnog kralja iz rošade.","Žrtva topa prvo izmamljuje kralja, a zatim dama daje mat.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Grundreihe des Weißen und ein Spießer auf den König entscheiden.","Erst lenkt ein Turmopfer den Verteidiger ab, dann fällt ein Turm tödlich ein.","Turm nimmt auf h2 – der Beginn eines erzwungenen Matts."],"en":["A pin against the white king and the back rank decide the day.","A rook sacrifice deflects the defender first, then a rook crashes in fatally.","Rook takes on h2 — the start of a forced mate."],"hr":["Vezivanje uz bijelog kralja i zadnja linija odlučuju.","Žrtva topa prvo odvlači branitelja, a zatim top smrtonosno upada.","Top uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in seiner Ecke vollkommen eingemauert.","Ein Läufer schwingt sich heran und gibt das entscheidende Schach.","Dame nimmt auf f8 – matt."],"en":["The black king is completely walled into its corner.","A bishop swings across and gives the decisive check.","Queen takes on f8 — mate."],"hr":["Crni kralj je potpuno zazidan u svom kutu.","Lovac dolazi i daje odlučujući šah.","Dama uzima na f8 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist weit vorgerückt und mitten im Brett gefangen.","Erst lockt ein Bauer den König heran, dann gibt die Dame das Schach.","Bauer nach g5 – der Beginn eines erzwungenen Matts."],"en":["The white king has wandered far up and is caught in the centre.","A pawn lures the king closer first, then the queen gives the check.","Pawn to g5 — the start of a forced mate."],"hr":["Bijeli kralj je daleko zalutao i zarobljen je u sredini.","Pješak prvo izmamljuje kralja, a zatim dama daje šah.","Pješak na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Grundreihe des Weißen ist hoffnungslos schwach.","Deine Dame schwenkt herüber und nutzt die ungedeckte Grundreihe aus.","Dame nach e4 – der Beginn eines erzwungenen Matts."],"en":["White''s back rank is hopelessly weak.","Your queen swings over and exploits the undefended last rank.","Queen to e4 — the start of a forced mate."],"hr":["Bijela zadnja linija je beznadno slaba.","Tvoja dama prelazi i iskorištava nebranjenu zadnju liniju.","Dama na e4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird mit einem Springerschach aus der Ecke getrieben.","Erst gibt ein Springer das Schach, dann setzt die Dame matt.","Springer nach f6 – der Beginn eines erzwungenen Matts."],"en":["A knight check drives the white king out of the corner.","A knight gives the check first, then the queen delivers mate.","Knight to f6 — the start of a forced mate."],"hr":["Šah skakačem tjera bijelog kralja iz kuta.","Skakač prvo daje šah, a zatim dama daje mat.","Skakač na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird über den Rand gejagt, Läufer und Dame im Verbund.","Erst treibt die Dame den König, dann gibt ein Läufer das entscheidende Schach.","Dame nach f8 – der Beginn eines erzwungenen Matts."],"en":["The black king is hunted along the edge by bishop and queen together.","The queen drives the king first, then a bishop gives the decisive check.","Queen to f8 — the start of a forced mate."],"hr":["Crni kralj biva protjeran uz rub, lovac i dama zajedno.","Dama prvo tjera kralja, a zatim lovac daje odlučujući šah.","Dama na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke gefangen, ein Opfer reißt die Deckung weg.","Erst opfert ein Turm sich, dann liefert die Dame das Matt.","Turm nimmt auf f8 – der Beginn eines erzwungenen Matts."],"en":["The black king is trapped in the corner and a sacrifice strips its cover.","A rook sacrifices itself first, then the queen delivers the mate.","Rook takes on f8 — the start of a forced mate."],"hr":["Crni kralj je zarobljen u kutu, a žrtva mu skida zaklon.","Top se prvo žrtvuje, a zatim dama daje mat.","Top uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.024' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist verwundbar, eine Ablenkung der Dame entscheidet.","Erst lockt ein Läufer die weiße Dame weg, dann fällt deine Dame tödlich ein.","Läufer nimmt auf d4 – der Beginn eines erzwungenen Matts."],"en":["The white king is vulnerable and deflecting the queen decides it.","A bishop first lures the white queen away, then your queen crashes in fatally.","Bishop takes on d4 — the start of a forced mate."],"hr":["Bijeli kralj je ranjiv, a odvlačenje dame odlučuje.","Lovac prvo odvlači bijelu damu, a zatim tvoja dama smrtonosno upada.","Lovac uzima na d4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.025' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist am Rand eingeklemmt und hat kaum Luft.","Deine schwere Figur stürmt heran und wickelt das Mattnetz um den König.","Dame nach f4 – Beginn eines erzwungenen Matts."],"en":["The black king is wedged against the edge with barely any air.","Your heavy piece charges in and weaves the mating net around the king.","Queen to f4 — starting a forced mate."],"hr":["Crni kralj je stiješnjen uz rub i jedva ima zraka.","Tvoja teška figura nahrupi i ispleti matnu mrežu oko kralja.","Dama na f4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.026' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt in der Ecke fest, und ein Opfer reißt die Deckung weg.","Ein Turmopfer zieht den König heraus, dann setzen Dame und Läufer nach.","Turm schlägt auf h7 – Auftakt eines erzwungenen Matts."],"en":["The black king is stuck in the corner, and a sacrifice tears away its cover.","A rook sacrifice drags the king out, then queen and bishop close in.","Rook takes on h7 — the start of a forced mate."],"hr":["Crni kralj je zaglavljen u kutu, a žrtva mu razdire zaklon.","Žrtva topa izvuče kralja, a zatim dama i lovac dolaze za njim.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.027' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt am Rand und kann der Schachserie nicht entkommen.","Deine Türme treiben den König mit wiederholten Opfern und Schachs vor sich her.","Turm nach a3 – Beginn eines erzwungenen Matts."],"en":["The white king clings to the edge and cannot escape the checks.","Your rooks herd the king along with repeated sacrifices and checks.","Rook to a3 — the start of a forced mate."],"hr":["Bijeli kralj se drži uz rub i ne može pobjeći od šahova.","Tvoji topovi tjeraju kralja ponovljenim žrtvama i šahovima.","Top na a3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.028' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die königliche Stellung von Schwarz ist zerschossen, und ein weiterer Schlag öffnet alles.","Ein Läuferopfer reißt die Bauerndeckung auf, dann jagt die Dame den König.","Läufer schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king''s shelter is shattered, and one more blow blows it open.","A bishop sacrifice rips away the pawn cover, then the queen hunts the king.","Bishop takes on h7 — the start of a forced mate."],"hr":["Zaklon crnog kralja je razbijen, a još jedan udarac sve otvara.","Žrtva lovca otrgne pješački zaklon, a zatim dama lovi kralja.","Lovac uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.029' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus seiner Deckung gelockt.","Ein Turmopfer beseitigt den Verteidiger, dann setzen Dame und Läufer nach.","Turm schlägt auf h8 – Auftakt eines erzwungenen Matts."],"en":["The black king is lured out of its shelter by a sacrifice.","A rook sacrifice removes the defender, then queen and bishop pursue.","Rook takes on h8 — starting a forced mate."],"hr":["Crni kralj se žrtvom izmami iz svog zaklona.","Žrtva topa uklanja branitelja, a zatim dama i lovac gone kralja.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.030' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist eingeengt, und ein Opfer öffnet die letzte Tür.","Ein Damenopfer lockt den König heraus, dann gibt der Springer das Matt.","Dame nach f3 – Beginn eines erzwungenen Matts."],"en":["The white king is hemmed in, and a sacrifice opens the final door.","A queen sacrifice draws the king out, then a knight delivers mate.","Queen to f3 — the start of a forced mate."],"hr":["Bijeli kralj je sabijen, a žrtva otvara posljednja vrata.","Žrtva dame izvuče kralja, a zatim skakač daje mat.","Dama na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.031' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht im Freien und lässt sich endgültig einfangen.","Ein Turmopfer öffnet die Linie, dann liefert die Dame den letzten Schlag.","Turm nach f5 – Auftakt eines erzwungenen Matts."],"en":["The black king is out in the open and gets caught for good.","A rook sacrifice opens the line, then the queen delivers the final blow.","Rook to f5 — starting a forced mate."],"hr":["Crni kralj je na otvorenom i biva konačno uhvaćen.","Žrtva topa otvara liniju, a zatim dama zadaje posljednji udarac.","Top na f5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.032' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist im Zentrum gestrandet und findet keine Ruhe.","Ein Turmopfer lockt den König heran, dann führen Dame und Läufer das Matt.","Turm schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king is stranded in the centre and finds no peace.","A rook sacrifice lures the king forward, then queen and bishop finish.","Rook takes on f8 — the start of a forced mate."],"hr":["Crni kralj je nasukan u centru i ne nalazi mira.","Žrtva topa primami kralja naprijed, a zatim dama i lovac dovršavaju.","Top uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.033' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt am Rand fest, und ein Schach treibt ihn ins Verderben.","Dame und Türme arbeiten zusammen, um den König einzukreisen.","Turm schlägt auf h8 – Beginn eines erzwungenen Matts."],"en":["The black king is stuck on the edge, and a check drives it to ruin.","Queen and rooks work together to corner the king.","Rook takes on h8 — the start of a forced mate."],"hr":["Crni kralj je zaglavljen uz rub, a šah ga tjera u propast.","Dama i topovi surađuju da bi sabili kralja u kut.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.034' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung hat eine entscheidende Schwäche an der Front.","Ein Springeropfer reißt die Deckung auf, dann fällt die Dame ein.","Springer nach f3 – Beginn eines erzwungenen Matts."],"en":["The white king''s position has a fatal weakness on its front.","A knight sacrifice rips open the cover, then the queen crashes in.","Knight to f3 — the start of a forced mate."],"hr":["Položaj bijelog kralja ima koban slab na prednjoj strani.","Žrtva skakača razdire zaklon, a zatim dama upada.","Skakač na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.035' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Verteidigung am Damenflügel ist gebunden und überlastet.","Ein Springeropfer beseitigt einen Verteidiger, dann gibt die Dame das Matt.","Springer nach d6 – Auftakt eines erzwungenen Matts."],"en":["Black''s defence on the queenside is tied down and overloaded.","A knight sacrifice removes a defender, then the queen delivers mate.","Knight to d6 — starting a forced mate."],"hr":["Crna obrana na daminom krilu je vezana i preopterećena.","Žrtva skakača uklanja branitelja, a zatim dama daje mat.","Skakač na d6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.036' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke gedrängt und schnappt nach Luft.","Eine Serie von Opfern räumt die Deckung weg, bis die Dame zuschlägt.","Turm schlägt auf g1 – Beginn eines erzwungenen Matts."],"en":["The white king is pinned into the corner and gasping for air.","A string of sacrifices clears the cover until the queen strikes.","Rook takes on g1 — the start of a forced mate."],"hr":["Bijeli kralj je sabijen u kut i hvata zrak.","Niz žrtava raščišćava zaklon dok dama ne udari.","Top uzima na g1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.037' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
