UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist in der Ecke umstellt, die Deckung wackelt.","Ein Damenopfer reißt die letzte Verteidigung weg, dann liefern die Türme das Matt.","Dame schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The black king is surrounded in the corner, its cover crumbling.","A queen sacrifice tears away the last defence, then the rooks deliver mate.","Queen takes on g7 — the start of a forced mate."],"hr":["Crni kralj je opkoljen u kutu, zaklon mu se ruši.","Žrtva dame otrgne posljednju obranu, a zatim topovi daju mat.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.040' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
