UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke eingeschnürt und kaum zu retten.","Ein Damenopfer öffnet die Tür, dann setzen Springer und Bauer das Netz zu.","Dame schlägt auf g2 – Beginn eines erzwungenen Matts."],"en":["The white king is laced tight into the corner and barely savable.","A queen sacrifice opens the door, then a knight and pawn seal the net.","Queen takes on g2 — the start of a forced mate."],"hr":["Bijeli kralj je čvrsto stegnut u kutu i jedva spasiv.","Žrtva dame otvara vrata, a zatim skakač i pješak zatvaraju mrežu.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.044' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
