UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König leidet an einer Schwäche auf der Grundreihe.","Ein Damenopfer räumt den Verteidiger weg, dann gibt der Turm das Matt.","Dame schlägt auf e2 – Beginn eines erzwungenen Matts."],"en":["The white king suffers from a back-rank weakness.","A queen sacrifice clears the defender away, then a rook delivers mate.","Queen takes on e2 — the start of a forced mate."],"hr":["Bijeli kralj pati od slabosti na zadnjoj liniji.","Žrtva dame uklanja branitelja, a zatim top daje mat.","Dama uzima na e2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.055' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Eine geopferte Figur reißt die schützenden Bauern vor dem König weg.","Erst zieht ein Läufer das Opfer ein, dann gibt deine Dame mit dem Läufer den entscheidenden Stoß.","Läufer schlägt auf f7 – Auftakt zu erzwungenem Matt."],"en":["A sacrifice tears away the pawns shielding the king.","After the bishop draws out the defence, your queen and bishop deliver the blow.","Bishop takes on f7 — the start of a forced mate."],"hr":["Žrtva razbija pješake koji štite kralja.","Nakon što lovac izvuče obranu, dama i lovac zadaju udarac.","Lovac uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.056' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der gegnerische König wird auf dem Rand entblößt und in ein Mattnetz getrieben.","Ein Bauernvorstoß öffnet die Stellung, dann jagen Dame und Turm den König.","Bauer nach f6 – Beginn eines erzwungenen Matts."],"en":["The enemy king gets stripped of cover and herded toward a mating net.","A pawn push opens lines, then queen and rook hunt the king.","Pawn to f6 — the start of a forced mate."],"hr":["Protivnički kralj ostaje bez zaštite i biva natjeran u matnu mrežu.","Potez pješaka otvara linije, a dama i top love kralja.","Pješak na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.057' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der König auf dem Rand wird durch ein Figurenopfer freigelegt.","Erst opfert ein Turm sich an der Königsstellung, dann schlagen Turm und Dame zu.","Turm schlägt auf h8 – Beginn eines erzwungenen Matts."],"en":["The king on the edge is exposed by a piece sacrifice.","A rook offers itself near the king, then rook and queen finish.","Rook takes on h8 — the start of a forced mate."],"hr":["Kralj na rubu biva razgolićen žrtvom figure.","Top se žrtvuje kod kralja, a zatim top i dama dovršavaju.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.058' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der eingeengte König am Rand wird durch ein Bauernopfer mattgesetzt.","Ein Bauernopfer lenkt ab, dann gibt deine Dame das tödliche Schach.","Bauer nach g5 – Auftakt zum erzwungenen Matt."],"en":["The cramped king on the edge falls to a pawn offer.","A pawn sacrifice deflects, then your queen gives the killing check.","Pawn to g5 — the start of a forced mate."],"hr":["Stiješnjeni kralj na rubu pada nakon žrtve pješaka.","Žrtva pješaka odvlači, a zatim dama daje smrtonosni šah.","Pješak na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.059' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der eingeklemmte König auf der Grundreihe ist die Schwäche.","Türme räumen die Verteidigung ab, dann liefert deine Dame das Matt.","Turm schlägt auf c8 – Beginn eines erzwungenen Matts."],"en":["The king boxed in on the back rank is the weakness.","Rooks clear away the defence, then your queen mates.","Rook takes on c8 — the start of a forced mate."],"hr":["Kralj stiješnjen na zadnjem redu je slabost.","Topovi uklanjaju obranu, a zatim dama matira.","Top uzima na c8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.060' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König am Rand kann den Schachs nicht entkommen.","Ein Turmopfer lockt den König, dann jagt deine Dame ihn ins Matt.","Turm schlägt auf h2 – Auftakt zum erzwungenen Matt."],"en":["The white king on the edge cannot escape the checks.","A rook sacrifice lures the king, then your queen drives it to mate.","Rook takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj na rubu ne može pobjeći šahovima.","Žrtva topa mami kralja, a zatim ga dama tjera u mat.","Top uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.061' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
