UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist auf der Grundreihe gefangen und schlecht geschützt.","Ein Damenopfer öffnet die Linie, dann reiten die Springer das Matt ein.","Dame schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king is trapped on his back row and poorly shielded.","A queen sacrifice opens the line, then the knights ride home.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj je zarobljen na zadnjoj liniji i slabo zaštićen.","Žrtva dame otvara liniju, a zatim skakači dovršavaju.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:017.090' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
