UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht entblößt da, und ein Opfer reißt seine Deckung endgültig auf.","Ein Damenopfer lockt einen Bauern weg, danach gibt ein Springer den tödlichen Sprung.","Die Dame schlägt auf e3 und startet das erzwungene Matt."],"en":["The white king stands exposed, and a sacrifice tears open the last of his cover.","A queen sacrifice drags a pawn away, then a knight delivers the fatal leap.","The queen takes on e3, starting a forced mate."],"hr":["Bijeli kralj stoji nezaštićen, a žrtva razbija posljednji zaklon.","Žrtva dame odvlači pješaka, a zatim skakač zadaje smrtonosni skok.","Dama uzima na e3 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.116' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König im Zentrum wird Schritt für Schritt eingekreist.","Springer und Dame jagen den König, bis der entscheidende Springersprung schließt.","Der Springer schlägt auf b6 und beginnt das erzwungene Matt."],"en":["The black king in the centre is hunted down step by step.","Knights and queen drive the king until a final knight leap seals it.","The knight takes on b6, beginning a forced mate."],"hr":["Crni kralj u sredini progoni se korak po korak.","Skakači i dama tjeraju kralja dok završni skok ne zatvori mrežu.","Skakač uzima na b6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.117' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Mitte und wird in ein Netz aus weißen Figuren getrieben.","Ein Läufer eröffnet mit einem Schlag, danach übernehmen Turm und Springer das Geschäft.","Der Läufer schlägt auf f4 und leitet das erzwungene Matt ein."],"en":["The black king is stuck in the middle and herded into a net of white pieces.","A bishop opens with a capture, then rook and knight finish the job.","The bishop takes on f4, launching a forced mate."],"hr":["Crni kralj zaglavljen je u sredini i tjera se u mrežu bijelih figura.","Lovac otvara uzimanjem, a zatim top i skakač dovršavaju posao.","Lovac uzima na f4 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.118' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird an den Rand gedrängt, wo ihm bald die Luft ausgeht.","Ein Springer und die schwere Artillerie treiben den König zum Mattnetz.","Der Springer zieht nach f6 und beginnt das erzwungene Matt."],"en":["The black king is forced to the edge where he soon runs out of air.","A knight and the heavy pieces drive the king into a mating net.","The knight goes to f6, beginning a forced mate."],"hr":["Crni kralj tjera se na rub gdje mu uskoro ponestaje zraka.","Skakač i teške figure tjeraju kralja u matnu mrežu.","Skakač ide na f6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.119' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch einen vorgeschobenen Bauern in die Enge getrieben.","Bauer und Dame schnüren den König ein, bis die Dame das letzte Schach gibt.","Der Bauer schlägt auf f7 und leitet das erzwungene Matt ein."],"en":["The black king is squeezed in by an advanced pawn.","A pawn and the queen box the king in until she delivers the last check.","The pawn takes on f7, launching a forced mate."],"hr":["Crnog kralja stišće napredovani pješak.","Pješak i dama zatvaraju kralja dok dama ne zada posljednji šah.","Pješak uzima na f7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.120' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König irrt im offenen Feld und findet keinen sicheren Hafen.","Ein Springer und die Dame koordinieren die Jagd bis zum letzten Schach.","Der Springer zieht nach e5 und beginnt das erzwungene Matt."],"en":["The black king wanders in the open and finds no safe harbour.","A knight and the queen coordinate the hunt to the final check.","The knight goes to e5, beginning a forced mate."],"hr":["Crni kralj luta na otvorenom i ne nalazi sigurnu luku.","Skakač i dama usklađuju lov sve do posljednjeg šaha.","Skakač ide na e5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.121' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist auf der Grundreihe und am Rand verwundbar; ein Opfer öffnet die Tür.","Ein Turmopfer reißt die Königsstellung auf, dann übernehmen Dame und Läufer.","Der Turm schlägt auf g7 und startet das erzwungene Matt."],"en":["The black king is vulnerable on the back rank and the edge; a sacrifice opens the door.","A rook sacrifice rips open the king''s shelter, then queen and bishop take over.","The rook takes on g7, starting a forced mate."],"hr":["Crni kralj ranjiv je na zadnjoj liniji i rubu; žrtva otvara vrata.","Žrtva topa razbija kraljev zaklon, a zatim dama i lovac preuzimaju.","Top uzima na g7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.122' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt am Rand und hat kaum Luft zum Atmen.","Die Dame allein jagt den König und gibt das ersehnte letzte Schach.","Die Dame zieht nach g5 und beginnt das erzwungene Matt."],"en":["The white king clings to the edge with barely any breathing room.","The queen alone hunts the king and lands the final check.","The queen goes to g5, beginning a forced mate."],"hr":["Bijeli kralj prilijepljen je uz rub i jedva ima zraka.","Dama sama lovi kralja i zadaje konačni šah.","Dama ide na g5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.123' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König auf der Grundreihe ist anfällig, sobald seine Deckung verschwindet.","Ein Springeropfer lenkt ab, dann dringen Dame und Turm bis zum Matt vor.","Der Springer zieht nach h3 und leitet das erzwungene Matt ein."],"en":["The white king on the back rank is fragile once his cover is removed.","A knight sacrifice deflects, then queen and rook break through to mate.","The knight goes to h3, launching a forced mate."],"hr":["Bijeli kralj na zadnjoj liniji krhak je čim mu nestane zaklon.","Žrtva skakača odvlači, a zatim dama i top probijaju do mata.","Skakač ide na h3 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.124' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König im Zentrum wird durch ein Ablenkungsopfer entscheidend geschwächt.","Ein Turmopfer und ein Läufer treiben den König, bis die Dame zuschlägt.","Der Turm schlägt auf e7 und beginnt das erzwungene Matt."],"en":["The black king in the centre is fatally weakened by a deflecting sacrifice.","A rook sacrifice and a bishop drive the king until the queen strikes.","The rook takes on e7, beginning a forced mate."],"hr":["Crnog kralja u sredini kobno slabi žrtva za odvlačenje.","Žrtva topa i lovac tjeraju kralja dok dama ne udari.","Top uzima na e7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.125' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch ein Opfer aufs offene Feld gezwungen.","Ein Damenopfer lockt einen Turm her, dann jagen Turm und Läufer den König.","Die Dame zieht nach f8 und startet das erzwungene Matt."],"en":["The black king on the edge is forced into the open by a sacrifice.","A queen sacrifice lures a rook, then rook and bishop chase the king down.","The queen goes to f8, starting a forced mate."],"hr":["Crnog kralja na rubu žrtva tjera na otvoreno.","Žrtva dame mami topa, a zatim top i lovac progone kralja.","Dama ide na f8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.126' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Grundreihe ist verwundbar, und ein Opfer beseitigt den letzten Verteidiger.","Ein Turmopfer räumt den Weg, dann übernehmen die schweren Figuren das Matt.","Der Turm schlägt auf e1 und beginnt das erzwungene Matt."],"en":["The white back rank is vulnerable, and a sacrifice removes the last defender.","A rook sacrifice clears the path, then the heavy pieces deliver mate.","The rook takes on e1, beginning a forced mate."],"hr":["Bijela zadnja linija je ranjiva, a žrtva uklanja posljednjeg branitelja.","Žrtva topa čisti put, a zatim teške figure zadaju mat.","Top uzima na e1 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.127' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch ein Damenopfer endgültig isoliert.","Ein Damenopfer reißt die Linie auf, dann walzen die Türme den König nieder.","Die Dame schlägt auf c8 und startet das erzwungene Matt."],"en":["The black king on the edge is isolated for good by a queen sacrifice.","A queen sacrifice opens the file, then the rooks roll the king down.","The queen takes on c8, starting a forced mate."],"hr":["Crnog kralja na rubu žrtva dame konačno izolira.","Žrtva dame otvara liniju, a zatim topovi gaze kralja.","Dama uzima na c8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.128' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König im Zentrum wird durch ein Opfer auf der b-Linie aufgesprengt.","Ein Turmopfer öffnet die Linie, dann dringt die schwere Artillerie zum König durch.","Der Turm schlägt auf b8 und beginnt das erzwungene Matt."],"en":["The black king in the centre is blown open by a sacrifice on the file.","A rook sacrifice opens the line, then the heavy pieces break through to the king.","The rook takes on b8, beginning a forced mate."],"hr":["Crnog kralja u sredini razbija žrtva na liniji.","Žrtva topa otvara liniju, a zatim teške figure probijaju do kralja.","Top uzima na b8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.129' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Anstatt das Abzugsschach zu spielen, übersieht man leicht ein direktes Mattnetz für den weißen König.","Ein ruhiges Springeropfer und die Schwerfiguren weben das Netz um den König.","Der Springer zieht nach b3 und beginnt das erzwungene Matt."],"en":["Instead of the discovered check, one easily overlooks a direct mating net on the white king.","A quiet knight sacrifice and the heavy pieces weave the net around the king.","The knight goes to b3, beginning a forced mate."],"hr":["Umjesto otkrivenog šaha, lako se previdi izravna matna mreža oko bijelog kralja.","Tiha žrtva skakača i teške figure pletu mrežu oko kralja.","Skakač ide na b3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.130' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König auf der Grundreihe ist an den Rand gefesselt und matttreif.","Ein Springeropfer treibt den König, dann setzen Springer und Dame nach.","Der Springer schlägt auf f7 und beginnt das erzwungene Matt."],"en":["The black king on the back rank is pinned to the edge and ripe for mate.","A knight sacrifice drives the king, then knight and queen press on.","The knight takes on f7, beginning a forced mate."],"hr":["Crni kralj na zadnjoj liniji prikovan je uz rub i zreo za mat.","Žrtva skakača tjera kralja, a zatim skakač i dama nastavljaju.","Skakač uzima na f7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.131' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand verliert durch ein Opfer seine letzten Helfer.","Ein Turmopfer lenkt ab, dann liefern Dame und Springer das Matt.","Der Turm schlägt auf e8 und beginnt das erzwungene Matt."],"en":["The black king on the edge loses his last helpers to a sacrifice.","A rook sacrifice deflects, then queen and knight deliver the mate.","The rook takes on e8, beginning a forced mate."],"hr":["Crni kralj na rubu gubi posljednje pomagače zbog žrtve.","Žrtva topa odvlači, a zatim dama i skakač zadaju mat.","Top uzima na e8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.132' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus seiner Deckung gelockt.","Ein Turmopfer öffnet die Reihe, dann jagen Dame und Läufer den König.","Der Turm schlägt auf c7 und startet das erzwungene Matt."],"en":["The black king is lured out of his cover by a sacrifice.","A rook sacrifice opens the rank, then queen and bishop chase the king.","The rook takes on c7, starting a forced mate."],"hr":["Crnog kralja žrtva izvlači iz zaklona.","Žrtva topa otvara liniju, a zatim dama i lovac progone kralja.","Top uzima na c7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.133' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König im Zentrum wird durch ein Damenopfer ins Verderben gezogen.","Ein Damenopfer und ein Springer treiben den König, bis der Turm zuschlägt.","Die Dame schlägt auf a8 und beginnt das erzwungene Matt."],"en":["The black king in the centre is dragged to ruin by a queen sacrifice.","A queen sacrifice and a knight drive the king until the rook strikes.","The queen takes on a8, beginning a forced mate."],"hr":["Crnog kralja u sredini žrtva dame vuče u propast.","Žrtva dame i skakač tjeraju kralja dok top ne udari.","Dama uzima na a8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.134' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch ein stilles Damenopfer hervorgelockt.","Ein Damenopfer zieht den König heraus, dann gibt der Läufer das letzte Schach.","Die Dame zieht nach g5 und beginnt das erzwungene Matt."],"en":["The black king on the edge is coaxed out by a quiet queen sacrifice.","A queen sacrifice draws the king out, then the bishop delivers the final check.","The queen goes to g5, beginning a forced mate."],"hr":["Crnog kralja na rubu mami tiha žrtva dame.","Žrtva dame izvlači kralja, a zatim lovac zadaje posljednji šah.","Dama ide na g5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.135' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus seiner Burg gerissen.","Ein Turmopfer öffnet den Weg, dann übernehmen Dame und Turm die Jagd.","Der Turm schlägt auf e7 und beginnt das erzwungene Matt."],"en":["The black king is torn out of his fortress by a sacrifice.","A rook sacrifice opens the way, then queen and rook take up the hunt.","The rook takes on e7, beginning a forced mate."],"hr":["Crnog kralja žrtva čupa iz njegove tvrđave.","Žrtva topa otvara put, a zatim dama i top preuzimaju lov.","Top uzima na e7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.136' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch ein Opfer hervorgezwungen.","Ein Turmopfer treibt den König, dann weben Dame und Türme das Mattnetz.","Der Turm schlägt auf h8 und beginnt das erzwungene Matt."],"en":["The black king on the edge is forced out by a sacrifice.","A rook sacrifice drives the king, then queen and rooks weave the mating net.","The rook takes on h8, beginning a forced mate."],"hr":["Crnog kralja na rubu žrtva tjera van.","Žrtva topa tjera kralja, a zatim dama i topovi pletu matnu mrežu.","Top uzima na h8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.137' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch eine Folge von Opfern systematisch entblößt.","Mehrere Opfer räumen die Verteidiger, dann dringt die Artillerie zum König durch.","Der Turm schlägt auf d7 und beginnt das erzwungene Matt."],"en":["The black king is systematically stripped bare by a chain of sacrifices.","Several sacrifices remove the defenders, then the heavy pieces break through.","The rook takes on d7, beginning a forced mate."],"hr":["Crnog kralja niz žrtava sustavno ogoljuje.","Nekoliko žrtava uklanja branitelje, a zatim teške figure probijaju.","Top uzima na d7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.138' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch eine Opferserie endgültig freigelegt.","Mehrere Opfer reißen die Bauernschilde weg, dann setzt der Springer das Matt.","Der Turm zieht nach g3 und beginnt das erzwungene Matt."],"en":["The black king is finally laid bare by a string of sacrifices.","Several sacrifices tear away the pawn shields, then the knight delivers mate.","The rook goes to g3, beginning a forced mate."],"hr":["Crnog kralja niz žrtava konačno otkriva.","Nekoliko žrtava uklanja pješačke štitove, a zatim skakač zadaje mat.","Top ide na g3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.139' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch eine Springerjagd in die Enge getrieben.","Ein Springer hetzt den König ins Eck, dann gibt die Dame das letzte Schach.","Der Springer zieht nach d7 und beginnt das erzwungene Matt."],"en":["The black king on the edge is driven into a corner by a knight chase.","A knight hounds the king into the corner, then the queen delivers the final check.","The knight goes to d7, beginning a forced mate."],"hr":["Crnog kralja na rubu lov skakačem tjera u kut.","Skakač goni kralja u kut, a zatim dama zadaje posljednji šah.","Skakač ide na d7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.140' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König am Rand wird durch ein Opfer aus der Reserve gelockt.","Ein Damenopfer und ein Springer treiben den König, dann übernimmt der Turm.","Die Dame schlägt auf g2 und beginnt das erzwungene Matt."],"en":["The white king on the edge is drawn out by a sacrifice.","A queen sacrifice and a knight drive the king, then the rook takes over.","The queen takes on g2, beginning a forced mate."],"hr":["Bijelog kralja na rubu žrtva izvlači van.","Žrtva dame i skakač tjeraju kralja, a zatim top preuzima.","Dama uzima na g2 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.141' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Königsstellung ist um den Rand herum löchrig und einsturzgefährdet.","Die Dame stürzt sich auf das schwache Feld vor dem König.","Die Dame schlägt auf h6 – matt."],"en":["The black king''s shelter is full of holes around the edge and ready to collapse.","The queen dives onto the weak square in front of the king.","The queen takes on h6 — mate."],"hr":["Zaklon crnog kralja pun je rupa uz rub i spreman za urušavanje.","Dama se obrušava na slabo polje ispred kralja.","Dama uzima na h6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:018.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Grundreihe ist tödlich schwach, sobald der Verteidiger weg ist.","Ein Damenopfer lenkt den König ab, dann setzt der Turm hinten matt.","Die Dame schlägt auf f8 und beginnt das erzwungene Matt."],"en":["The black back rank is fatally weak once the defender is gone.","A queen sacrifice deflects the king, then the rook mates from behind.","The queen takes on f8, beginning a forced mate."],"hr":["Crna zadnja linija kobno je slaba čim nestane branitelj.","Žrtva dame odvlači kralja, a zatim top matira sa stražnje strane.","Dama uzima na f8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:018.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Bauern eingeschnürt und kann nirgendwohin.","Ein Damenopfer beseitigt einen Verteidiger, dann liefert der Springer das Matt.","Die Dame schlägt auf f7 und beginnt das erzwungene Matt."],"en":["The black king is laced in behind his pawns with nowhere to go.","A queen sacrifice removes a defender, then the knight delivers the mate.","The queen takes on f7, beginning a forced mate."],"hr":["Crni kralj zatvoren je iza svojih pješaka i nema kamo.","Žrtva dame uklanja branitelja, a zatim skakač zadaje mat.","Dama uzima na f7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:018.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird durch ein Opfer auf die Grundreihe gezwungen.","Ein Damenopfer lockt den König, dann setzt der Turm auf der offenen Linie matt.","Die Dame schlägt auf h8 und beginnt das erzwungene Matt."],"en":["The black king on the edge is forced onto the back rank by a sacrifice.","A queen sacrifice lures the king, then the rook mates down the open file.","The queen takes on h8, beginning a forced mate."],"hr":["Crnog kralja na rubu žrtva tjera na zadnju liniju.","Žrtva dame mami kralja, a zatim top matira po otvorenoj liniji.","Dama uzima na h8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:018.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Grundreihe ist verwundbar, und ein Opfer reißt die Verteidigung auf.","Ein Turm opfert sich, damit deine Dame zum tödlichen Schach durchschlägt.","Turm schlägt auf e1 – Beginn eines erzwungenen Matts."],"en":["White''s back rank is fragile, and a sacrifice tears the defence open.","A rook sacrifices itself so your queen can crash through with mate.","Rook takes on e1 — the start of a forced mate."],"hr":["Bijela posljednja linija je ranjiva, a žrtva razbija obranu.","Top se žrtvuje kako bi tvoja dama probila do matne pozicije.","Top uzima na e1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.008' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der eingeengte schwarze König lässt sich durch ein Opfer aus der Deckung locken.","Ein Damenopfer öffnet die Linie, dann gibt deine Dame das Matt.","Dame nach f8 – Auftakt zum erzwungenen Matt."],"en":["The cramped black king can be lured out of cover by a sacrifice.","A queen sacrifice clears the way, then your queen delivers mate.","Queen to f8 — the start of a forced mate."],"hr":["Skučeni crni kralj može se žrtvom izmamiti iz zaklona.","Žrtva dame otvara liniju, a tvoja dama zatim daje mat.","Dama na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.009' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Bauern eingeklemmt; ein Bauernsturm reißt die Stellung auf.","Ein Bauernopfer öffnet die Linie für den entscheidenden Schlag der Schwerfiguren.","Bauer nach g6 – Beginn eines erzwungenen Matts."],"en":["The black king is boxed in behind its pawns; a pawn break smashes it open.","A pawn sacrifice opens the line for the heavy pieces to strike.","Pawn to g6 — the start of a forced mate."],"hr":["Crni kralj je zatvoren iza svojih pješaka; proboj pješakom razbija položaj.","Žrtva pješaka otvara liniju za odlučujući udar teških figura.","Pješak na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.010' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt an der Ecke, und ein Opfer öffnet das Netz.","Ein Bauernopfer zieht den Turm fort, dann setzt deine Dame matt.","Dame schlägt auf g3 – Beginn eines erzwungenen Matts."],"en":["The white king is glued to the corner, and a sacrifice springs the net.","A pawn sacrifice deflects the rook, then your queen mates.","Queen takes on g3 — the start of a forced mate."],"hr":["Bijeli kralj je prikovan uz kut, a žrtva otvara matnu mrežu.","Žrtva pješaka odvlači topa, a tvoja dama zatim mati.","Dama uzima na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.011' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König sitzt in der Ecke fest und kann ein Opfer nicht ablehnen.","Ein Bauernopfer öffnet die Linie, dann dringt dein Turm zum Matt ein.","Bauer schlägt auf h3 – Beginn eines erzwungenen Matts."],"en":["The white king is stuck in the corner and cannot decline the offer.","A pawn sacrifice opens the line, then your rook breaks in for mate.","Pawn takes on h3 — the start of a forced mate."],"hr":["Bijeli kralj je zaglavljen u kutu i ne može odbiti žrtvu.","Žrtva pješaka otvara liniju, a tvoj top zatim provaljuje do mata.","Pješak uzima na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.012' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist entblößt, und ein Damenopfer zieht den verbliebenen Verteidiger fort.","Deine Dame opfert sich, damit der Turm das tödliche Schach gibt.","Dame schlägt auf f2 – Beginn eines erzwungenen Matts."],"en":["The white king is exposed, and a queen sacrifice drags off the last guard.","Your queen sacrifices itself so the rook can deliver the killing check.","Queen takes on f2 — the start of a forced mate."],"hr":["Bijeli kralj je otkriven, a žrtva dame odvlači posljednjeg branitelja.","Tvoja dama se žrtvuje kako bi top dao smrtonosni šah.","Dama uzima na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.013' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an die Grundreihe gefesselt; ein Opfer öffnet die Linie.","Ein Damenopfer räumt das Feld, dann setzt dein Turm matt.","Dame schlägt auf h8 – Beginn eines erzwungenen Matts."],"en":["The black king is pinned to its back rank; a sacrifice opens the file.","A queen sacrifice clears the square, then your rook gives mate.","Queen takes on h8 — the start of a forced mate."],"hr":["Crni kralj je vezan uz posljednju liniju; žrtva otvara liniju.","Žrtva dame čisti polje, a tvoj top zatim daje mat.","Dama uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.014' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist eingemauert, und ein Damenopfer zerstört seine Deckung.","Deine Dame opfert sich, dann gibt ein Bauer das überraschende Matt.","Dame schlägt auf g3 – Beginn eines erzwungenen Matts."],"en":["The white king is walled in, and a queen sacrifice wrecks its cover.","Your queen sacrifices itself, then a pawn gives the surprising mate.","Queen takes on g3 — the start of a forced mate."],"hr":["Bijeli kralj je zazidan, a žrtva dame ruši njegov zaklon.","Tvoja dama se žrtvuje, a pješak zatim daje iznenađujući mat.","Dama uzima na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.015' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird an den Rand getrieben, wo ihn ein Springer einfängt.","Ein Turm treibt den König weg, dann gibt der Springer das Matt.","Turm nach d8 – Beginn eines erzwungenen Matts."],"en":["The black king is driven to the edge, where a knight snares it.","A rook chases the king, then the knight delivers mate.","Rook to d8 — the start of a forced mate."],"hr":["Crni kralj je potjeran na rub, gdje ga skakač hvata.","Top tjera kralja, a skakač zatim daje mat.","Top na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.016' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steckt in der Mitte; ein Opfer reißt seine Bauern weg.","Ein Damenopfer öffnet die Diagonale für deinen Läufer zum Matt.","Dame schlägt auf e6 – Beginn eines erzwungenen Matts."],"en":["The black king is stuck in the centre; a sacrifice strips its pawns.","A queen sacrifice opens the diagonal for your bishop to mate.","Queen takes on e6 — the start of a forced mate."],"hr":["Crni kralj je zaglavljen u sredini; žrtva mu odnosi pješake.","Žrtva dame otvara dijagonalu za matni udar tvoga lovca.","Dama uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.017' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke eingesperrt und hat kein Luftloch.","Ein Damenopfer lockt den König heran, dann setzt deine Dame matt.","Dame schlägt auf h3 – Beginn eines erzwungenen Matts."],"en":["The white king is locked in the corner with no luft.","A queen sacrifice lures the king, then your queen mates.","Queen takes on h3 — the start of a forced mate."],"hr":["Bijeli kralj je zatvoren u kutu bez zračnog otvora.","Žrtva dame primamljuje kralja, a tvoja dama zatim mati.","Dama uzima na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.018' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist an den Rand gepresst; ein Opfer öffnet die letzte Linie.","Ein Turmopfer reißt die Bauerndeckung weg, dann mattet dein anderer Turm.","Turm schlägt auf h3 – Beginn eines erzwungenen Matts."],"en":["The white king is pressed to the edge; a sacrifice opens the last line.","A rook sacrifice tears off the pawn shield, then your other rook mates.","Rook takes on h3 — the start of a forced mate."],"hr":["Bijeli kralj je pritisnut uz rub; žrtva otvara posljednju liniju.","Žrtva topa odnosi pješački zaklon, a drugi top zatim mati.","Top uzima na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.019' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Figuren gefangen; eine Opferserie reißt sie weg.","Dame und Turm opfern sich nacheinander, dann setzt dein Turm auf der Grundreihe matt.","Dame schlägt auf g8 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped behind its pieces; a chain of sacrifices clears them.","Queen and rook sacrifice in turn, then your rook mates on the back rank.","Queen takes on g8 — the start of a forced mate."],"hr":["Crni kralj je zarobljen iza svojih figura; niz žrtava ih uklanja.","Dama i top se žrtvuju jedno za drugim, a top zatim mati po posljednjoj liniji.","Dama uzima na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.020' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer ins offene Feld gezogen.","Ein Damenopfer lockt den König heraus, dann mattet dein Turm.","Dame schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["The black king is dragged into the open by a sacrifice.","A queen sacrifice draws the king out, then your rook mates.","Queen takes on f7 — the start of a forced mate."],"hr":["Crni kralj se žrtvom izvlači na otvoreno polje.","Žrtva dame izvlači kralja, a tvoj top zatim mati.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.021' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke fällt einer Springergabel zum Opfer.","Ein Turmopfer zieht den König in die Ecke, dann springt der Springer zum Matt.","Turm schlägt auf h8 – Beginn eines erzwungenen Matts."],"en":["The cornered black king falls to a knight''s leap.","A rook sacrifice pulls the king into the corner, then the knight mates.","Rook takes on h8 — the start of a forced mate."],"hr":["Crni kralj u kutu pada od skakačeva skoka.","Žrtva topa uvlači kralja u kut, a skakač zatim mati.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.022' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist eng eingeschnürt; eine Folge von Opfern bricht durch.","Erst ein Damenopfer, dann liefern Läufer und Springer das Matt.","Dame schlägt auf h3 – Beginn eines erzwungenen Matts."],"en":["The white king is tightly hemmed in; a series of sacrifices breaks through.","First a queen sacrifice, then bishop and knight deliver mate.","Queen takes on h3 — the start of a forced mate."],"hr":["Bijeli kralj je čvrsto stiješnjen; niz žrtava probija obranu.","Najprije žrtva dame, a zatim lovac i skakač daju mat.","Dama uzima na h3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.023' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen Bauern gefangen; ein Opfer reißt sie auf.","Ein Turmopfer räumt die Deckung, dann mattet dein anderer Turm.","Turm schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["The black king is trapped behind its pawns; a sacrifice rips them open.","A rook sacrifice clears the cover, then your other rook mates.","Rook takes on f7 — the start of a forced mate."],"hr":["Crni kralj je zarobljen iza svojih pješaka; žrtva ih razbija.","Žrtva topa uklanja zaklon, a drugi top zatim mati.","Top uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.024' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer von seiner letzten Deckung getrennt.","Ein Damenopfer öffnet die Linie, dann dringt dein Turm zum Matt ein.","Dame nach g5 – Beginn eines erzwungenen Matts."],"en":["The black king is cut off from its last shield by a sacrifice.","A queen sacrifice opens the file, then your rook breaks in for mate.","Queen to g5 — the start of a forced mate."],"hr":["Crni kralj se žrtvom odvaja od posljednjeg zaklona.","Žrtva dame otvara liniju, a tvoj top zatim provaljuje do mata.","Dama na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.025' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch eine Opferkette aus seinem Versteck gezerrt.","Erst ein Turmopfer, dann arbeiten Dame und Läufer das Matt aus.","Turm schlägt auf h6 – Beginn eines erzwungenen Matts."],"en":["The black king is hauled from its shelter by a chain of sacrifices.","First a rook sacrifice, then queen and bishop work out the mate.","Rook takes on h6 — the start of a forced mate."],"hr":["Crni kralj se nizom žrtava izvlači iz svoga zaklona.","Najprije žrtva topa, a zatim dama i lovac izrađuju mat.","Top uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.026' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke wird durch ein Opfer aufgedeckt.","Ein Damenopfer zieht den König heran, dann setzen Springer und Turm matt.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king in the corner is laid bare by a sacrifice.","A queen sacrifice draws the king out, then knight and rook mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj u kutu otkriva se žrtvom.","Žrtva dame privlači kralja, a skakač i top zatim mate.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.027' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke eingeschlossen; ein Opfer öffnet das Netz.","Ein Damenopfer lockt den König, dann liefern Turm und Läufer das Matt.","Dame schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king is shut in the corner; a sacrifice springs the net.","A queen sacrifice lures the king, then rook and bishop deliver mate.","Queen takes on h2 — the start of a forced mate."],"hr":["Bijeli kralj je zatvoren u kutu; žrtva otvara matnu mrežu.","Žrtva dame primamljuje kralja, a top i lovac zatim daju mat.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.028' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an den Rand gedrängt; ein Opfer reißt die letzte Reihe auf.","Erst ein Läuferopfer, dann mattet dein Turm auf der offenen Linie.","Läufer schlägt auf h6 – Beginn eines erzwungenen Matts."],"en":["The black king is pushed to the edge; a sacrifice tears open the last rank.","First a bishop sacrifice, then your rook mates down the open line.","Bishop takes on h6 — the start of a forced mate."],"hr":["Crni kralj je potisnut na rub; žrtva razbija posljednju liniju.","Najprije žrtva lovca, a zatim tvoj top mati po otvorenoj liniji.","Lovac uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.029' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in die Ecke eingeklemmt; ein Opfer öffnet die Linie.","Erst ein Turmopfer, dann mattet deine Dame auf der zweiten Reihe.","Turm schlägt auf h1 – Beginn eines erzwungenen Matts."],"en":["The white king is jammed into the corner; a sacrifice opens the line.","First a rook sacrifice, then your queen mates on the second rank.","Rook takes on h1 — the start of a forced mate."],"hr":["Bijeli kralj je stiješnjen u kut; žrtva otvara liniju.","Najprije žrtva topa, a zatim tvoja dama mati na drugoj liniji.","Top uzima na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.030' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer ins Freie gezogen.","Ein Damenopfer öffnet die Linie, dann jagen Turm und Läufer das Matt.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king is pulled into the open by a sacrifice.","A queen sacrifice opens the line, then rook and bishop hunt the mate.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj se žrtvom izvlači na otvoreno.","Žrtva dame otvara liniju, a top i lovac zatim love mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.031' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steckt in der Mitte; ein Opfer entblößt ihn völlig.","Ein Damenopfer zieht den König heraus, dann setzt dein Läufer matt.","Dame schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["The black king is stuck in the centre; a sacrifice strips it bare.","A queen sacrifice draws the king out, then your bishop mates.","Queen takes on f7 — the start of a forced mate."],"hr":["Crni kralj je zaglavljen u sredini; žrtva ga potpuno otkriva.","Žrtva dame izvlači kralja, a tvoj lovac zatim mati.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.032' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird in der Ecke ins Mattnetz getrieben.","Ein Turmopfer öffnet die Linie, dann jagt deine Dame den König matt.","Turm schlägt auf h8 – Beginn eines erzwungenen Matts."],"en":["The black king is herded into a mating net in the corner.","A rook sacrifice opens the line, then your queen drives the king to mate.","Rook takes on h8 — the start of a forced mate."],"hr":["Crni kralj se u kutu tjera u matnu mrežu.","Žrtva topa otvara liniju, a tvoja dama zatim tjera kralja u mat.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.033' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke wird durch eine Opferfolge aufgedeckt.","Dame und Turm opfern sich, dann mattet dein anderer Turm auf der offenen Linie.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king in the corner is exposed by a run of sacrifices.","Queen and rook sacrifice, then your other rook mates down the open line.","Queen takes on h7 — the start of a forced mate."],"hr":["Crni kralj u kutu otkriva se nizom žrtava.","Dama i top se žrtvuju, a drugi top zatim mati po otvorenoj liniji.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.034' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke wird durch ein Opfer aus der Deckung gerissen.","Ein Damenopfer und ein Turmschach treiben den König dem Läufermatt entgegen.","Dame schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["The cornered black king is torn from cover by a sacrifice.","A queen sacrifice and a rook check drive the king into a bishop mate.","Queen takes on g7 — the start of a forced mate."],"hr":["Crni kralj u kutu se žrtvom otrgne iz zaklona.","Žrtva dame i šah topom tjeraju kralja u mat lovcem.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.035' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an den Rand gefesselt; ein Opfer reißt die Deckung weg.","Ein Damenopfer öffnet die Linie, dann mattet dein Turm.","Dame schlägt auf f6 – Beginn eines erzwungenen Matts."],"en":["The black king is fixed to the edge; a sacrifice rips away its cover.","A queen sacrifice opens the file, then your rook mates.","Queen takes on f6 — the start of a forced mate."],"hr":["Crni kralj je prikovan uz rub; žrtva mu odnosi zaklon.","Žrtva dame otvara liniju, a tvoj top zatim mati.","Dama uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.036' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus seiner Deckung gelockt.","Erst ein Springeropfer, dann arbeiten König und Turm das Läufermatt aus.","Springer schlägt auf g6 – Beginn eines erzwungenen Matts."],"en":["The black king is lured from its cover by a sacrifice.","First a knight sacrifice, then king and rook engineer a mate on the diagonal.","Knight takes on g6 — the start of a forced mate."],"hr":["Crni kralj se žrtvom izmamljuje iz svoga zaklona.","Najprije žrtva skakača, a zatim kralj i top izrađuju mat po dijagonali.","Skakač uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.037' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung ist auf der Grundlinie und entlang der Diagonale tödlich entblößt; ein Opfer reißt die letzte Deckung weg.","Erst kassiert die Dame einen Verteidiger, dann gibt der Turm auf der Grundreihe das Matt.","Dame nimmt auf f2 – Beginn eines erzwungenen Matts."],"en":["White''s king is fatally exposed on the back rank once its last guard is torn away by a sacrifice.","First the queen removes a defender, then the rook delivers mate along the back rank.","Queen takes on f2 — starting a forced mate."],"hr":["Bijeli kralj je smrtonosno izložen na posljednjoj liniji čim žrtva ukloni posljednjeg branitelja.","Najprije dama uklanja branitelja, a zatim top daje mat po posljednjoj liniji.","Dama uzima na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.038' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König hängt am offenen H-Bereich, und ein Bauernopfer öffnet die Linie endgültig.","Ein Springer springt zum entscheidenden Schlag heran, während die Dame über die offene Linie zustößt.","Dame nimmt auf h7 – Auftakt eines erzwungenen Matts."],"en":["The black king clings to a draughty kingside that a sacrifice rips wide open.","A knight leaps in for the decisive blow while the queen strikes down the open file.","Queen takes on h7 — beginning a forced mate."],"hr":["Crni kralj se drži za promajno kraljevo krilo koje žrtva otvara naširoko.","Skakač uskače za odlučujući udarac dok dama udara po otvorenoj liniji.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.039' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Königsstellung lässt sich durch ein Damenopfer aufreißen und der dunkle Diagonalweg wird tödlich.","Ein Läufer auf der langen Diagonale und ein Turm auf der offenen Linie weben das Mattnetz.","Dame nimmt auf h8 – Beginn eines erzwungenen Matts."],"en":["A queen sacrifice tears open the black king and the dark diagonal turns lethal.","A bishop on the long diagonal and a rook on the open file weave the mating net.","Queen takes on h8 — beginning a forced mate."],"hr":["Žrtva dame otvara crnoga kralja, a tamna dijagonala postaje smrtonosna.","Lovac na velikoj dijagonali i top na otvorenoj liniji pletu matnu mrežu.","Dama uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.040' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter seinen eigenen Steinen eingesperrt; ein Opfer öffnet die letzte Reihe.","Erst lockt die Dame eine Figur weg, dann liefert der Turm das Matt auf der Grundreihe.","Dame nimmt auf f7 – Beginn eines erzwungenen Matts."],"en":["The black king is boxed in behind its own men, and a sacrifice cracks the back rank.","First the queen drags a piece away, then the rook delivers mate on the back rank.","Queen takes on f7 — beginning a forced mate."],"hr":["Crni kralj je zatvoren iza vlastitih figura, a žrtva otvara posljednju liniju.","Najprije dama odvlači figuru, a zatim top daje mat po posljednjoj liniji.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.041' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt in der Ecke und ein Turmopfer zwingt ihn ins Mattnetz.","Nach dem Turmopfer setzt der Springer aus dem Hinterhalt das Matt.","Turm nach f8 – Beginn eines erzwungenen Matts."],"en":["The black king is stuck in the corner and a rook sacrifice forces it into the mating net.","After the rook sacrifice a knight springs from ambush to mate.","Rook to f8 — beginning a forced mate."],"hr":["Crni kralj je zaglavljen u kutu, a žrtva topa ga gura u matnu mrežu.","Nakon žrtve topa skakač iz zasjede daje mat.","Top na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.042' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Königsstellung lebt von einem überlasteten Verteidiger, den ein Damenopfer beseitigt.","Erst opfert die Dame, dann zieht der Läufer auf der Diagonale zum Mattzug heran.","Dame nimmt auf c6 – Beginn eines erzwungenen Matts."],"en":["Black''s defence rests on an overloaded guard that a queen sacrifice eliminates.","First the queen sacrifices, then the bishop swings along the diagonal to mate.","Queen takes on c6 — beginning a forced mate."],"hr":["Crna obrana ovisi o preopterećenom braniocu kojeg žrtva dame uklanja.","Najprije dama žrtvuje, a zatim lovac kreće po dijagonali do mata.","Dama uzima na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.043' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird auf der ersten Reihe und der offenen Linie eingekreist; eine Serie von Opfern legt ihn frei.","Türme und der Läufer wirken zusammen, bis ein Turm auf der Grundreihe das Matt gibt.","Dame nimmt auf e1 – Beginn eines erzwungenen Matts."],"en":["The white king gets hunted down on the first rank and the open file as a string of sacrifices strips it bare.","Rooks and the bishop combine until a rook delivers mate on the back rank.","Queen takes on e1 — beginning a forced mate."],"hr":["Bijeli kralj biva opkoljen na prvoj liniji i otvorenoj koloni dok ga niz žrtava razgolićuje.","Topovi i lovac surađuju dok top ne da mat po posljednjoj liniji.","Dama uzima na e1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.044' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König sitzt in der Ecke fest, und ein Damenopfer reißt seine Deckung auf.","Die Dame schlägt ein, dann liefert ein Turm das Matt auf der Grundreihe.","Dame nach g5 – Beginn eines erzwungenen Matts."],"en":["The white king is trapped in the corner and a queen sacrifice rips its cover apart.","The queen crashes in, then a rook delivers mate on the back rank.","Queen to g5 — beginning a forced mate."],"hr":["Bijeli kralj je zarobljen u kutu, a žrtva dame razdire njegov zaklon.","Dama upada, a zatim top daje mat po posljednjoj liniji.","Dama na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.045' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Im offenen Endspiel wird der weiße König auf den Rand getrieben und vom Springer eingefangen.","Dame und Springer arbeiten zusammen, bis die Dame das Matt setzt.","Dame nimmt auf h1 – Beginn eines erzwungenen Matts."],"en":["In the open endgame the white king is driven to the edge and snared by the knight.","Queen and knight work together until the queen delivers mate.","Queen takes on h1 — beginning a forced mate."],"hr":["U otvorenoj završnici bijeli kralj biva potjeran na rub i uhvaćen skakačem.","Dama i skakač surađuju dok dama ne da mat.","Dama uzima na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.046' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht eingeengt zwischen den eigenen Bauern, und ein stiller Zug schnürt das Netz zu.","Ein Turm und der weit vorgerückte Freibauer halten den König fest, dann gibt ein bescheidener Zug das Matt.","Turm nach f6 – Beginn eines erzwungenen Matts."],"en":["The black king stands cramped among its own pawns, and a quiet move tightens the net.","A rook and the far-advanced passed pawn pin the king down, then a modest move mates.","Rook to f6 — beginning a forced mate."],"hr":["Crni kralj stoji stiješnjen među vlastitim pješacima, a tihi potez steže mrežu.","Top i daleko nadirući slobodnjak drže kralja, a zatim skroman potez daje mat.","Top na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.047' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Königsstellung wird durch ein Läuferopfer aufgebrochen, das die Diagonale öffnet.","Nach dem Opfer dringen Dame und ein Läufer gemeinsam zum Mattangriff vor.","Läufer nimmt auf e6 – Beginn eines erzwungenen Matts."],"en":["A bishop sacrifice prises open the black king and clears the diagonal.","After the sacrifice the queen and a bishop combine for the mating attack.","Bishop takes on e6 — beginning a forced mate."],"hr":["Žrtva lovca otvara crnoga kralja i raščišćava dijagonalu.","Nakon žrtve dama i lovac zajedno kreću u matni napad.","Lovac uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.048' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird mit einer Reihe von Opfern an den Rand gezerrt.","Springer und Türme zerschlagen die Deckung, bis ein Turm das Matt liefert.","Springer nimmt auf g3 – Beginn eines erzwungenen Matts."],"en":["The white king is dragged to the edge by a cascade of sacrifices.","A knight and rooks smash the cover until a rook delivers mate.","Knight takes on g3 — beginning a forced mate."],"hr":["Bijeli kralj biva odvučen na rub nizom žrtava.","Skakač i topovi razbijaju zaklon dok top ne da mat.","Skakač uzima na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.049' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König klebt am Rand, und ein Damenopfer öffnet die letzte Reihe.","Dame und Türme verbinden sich, bis ein Turm das Matt auf der Grundreihe gibt.","Dame nach h6 – Beginn eines erzwungenen Matts."],"en":["The black king is pinned to the edge, and a queen sacrifice opens the back rank.","Queen and rooks join forces until a rook delivers mate on the back rank.","Queen to h6 — beginning a forced mate."],"hr":["Crni kralj je prikovan uz rub, a žrtva dame otvara posljednju liniju.","Dama i topovi se udružuju dok top ne da mat po posljednjoj liniji.","Dama na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.050' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König hat sein Bauerndach verloren; ein Damenopfer lockt ihn ins Freie.","Nach dem Opfer wechselt die Dame die Spur und der Läufer setzt das Matt.","Dame nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king has lost its pawn shelter, and a queen sacrifice lures it into the open.","After the sacrifice the queen switches files and the bishop delivers mate.","Queen takes on h7 — beginning a forced mate."],"hr":["Crni kralj je izgubio pješački zaklon, a žrtva dame ga izvlači na otvoreno.","Nakon žrtve dama mijenja liniju, a lovac daje mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.051' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Turmopfer aus seiner Rochade gerissen.","Nach dem Opfer treiben Dame und ein Springer den König ins endgültige Mattnetz.","Turm nimmt auf h8 – Beginn eines erzwungenen Matts."],"en":["A rook sacrifice tears the black king out of its castled shelter.","After the sacrifice the queen and a knight herd the king into the final net.","Rook takes on h8 — beginning a forced mate."],"hr":["Žrtva topa izvlači crnoga kralja iz rokade.","Nakon žrtve dama i skakač tjeraju kralja u konačnu matnu mrežu.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.052' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist auf der Grundreihe eingesperrt; ein Damenopfer beseitigt seinen letzten Helfer.","Nach dem Opfer schwenkt ein Turm auf die offene Linie und gibt das Matt.","Dame nimmt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king is locked on the back rank, and a queen sacrifice removes its last helper.","After the sacrifice a rook swings onto the open file to deliver mate.","Queen takes on h2 — beginning a forced mate."],"hr":["Bijeli kralj je zaključan na posljednjoj liniji, a žrtva dame uklanja njegova posljednjeg pomagača.","Nakon žrtve top prelazi na otvorenu liniju i daje mat.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.053' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König lebt von dünner Bauerndeckung, die ein Springeropfer aufreißt.","Nach dem Opfer dringen Dame und ein Turm gemeinsam zum Matt vor.","Springer nimmt auf g5 – Beginn eines erzwungenen Matts."],"en":["The black king survives on thin pawn cover that a knight sacrifice tears open.","After the sacrifice the queen and a rook break through together to mate.","Knight takes on g5 — beginning a forced mate."],"hr":["Crni kralj preživljava na tankom pješačkom zaklonu koji žrtva skakača razdire.","Nakon žrtve dama i top zajedno probijaju do mata.","Skakač uzima na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.054' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Turmopfer aus der Rochade gezerrt.","Nach dem Opfer stoßen Dame und ein Bauer vor, bis die Dame das Matt setzt.","Turm nimmt auf h8 – Beginn eines erzwungenen Matts."],"en":["A rook sacrifice drags the black king out of its castled position.","After the sacrifice the queen and a pawn advance until the queen delivers mate.","Rook takes on h8 — beginning a forced mate."],"hr":["Žrtva topa izvlači crnoga kralja iz rokade.","Nakon žrtve dama i pješak nadiru dok dama ne da mat.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.055' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Damenopfer aus seinem Versteck geholt.","Nach dem Opfer schwenkt ein Turm zur offenen Linie, und der Läufer beendet die Jagd.","Dame nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["A queen sacrifice flushes the black king out of its shelter.","After the sacrifice a rook swings to the open file and the bishop ends the hunt.","Queen takes on h7 — beginning a forced mate."],"hr":["Žrtva dame izvlači crnoga kralja iz zaklona.","Nakon žrtve top prelazi na otvorenu liniju, a lovac završava lov.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.056' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steckt in der Ecke fest; ein Opfer treibt ihn ins Mattnetz.","Die Dame jagt den König, bis sie ihn mit Unterstützung des Turms stellt.","Dame nimmt auf c6 – Beginn eines erzwungenen Matts."],"en":["The black king is stuck in the corner and a sacrifice drives it into the mating net.","The queen chases the king until she pins it down with the rook''s support.","Queen takes on c6 — beginning a forced mate."],"hr":["Crni kralj je zaglavljen u kutu, a žrtva ga tjera u matnu mrežu.","Dama goni kralja dok ga uz pomoć topa ne svlada.","Dama uzima na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.057' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die weiße Königsstellung wird durch ein Damenopfer auf der langen Diagonale aufgerissen.","Nach dem Opfer jagen Läufer und Turm den blanken König, bis der Turm das Matt setzt.","Dame nimmt auf g2 – Beginn eines erzwungenen Matts."],"en":["A queen sacrifice on the long diagonal blows open the white king.","After the sacrifice a bishop and rook chase the bare king until the rook mates.","Queen takes on g2 — beginning a forced mate."],"hr":["Žrtva dame na velikoj dijagonali otvara bijeloga kralja.","Nakon žrtve lovac i top gone golog kralja dok top ne da mat.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.058' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König hat eine durchlöcherte Bauernkette; ein Damenopfer öffnet die offene Linie.","Nach dem Opfer verdoppeln sich die Türme zum tödlichen Druck auf der offenen Linie.","Dame nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king has holes in its pawn screen, and a queen sacrifice opens the file.","After the sacrifice the rooks double up for lethal pressure down the open file.","Queen takes on h7 — beginning a forced mate."],"hr":["Crni kralj ima rupe u pješačkom zaklonu, a žrtva dame otvara liniju.","Nakon žrtve topovi se udvostručuju za smrtonosan pritisak po otvorenoj liniji.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.059' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird auf der Grundreihe und am Rand mit Opfern eingekreist.","Nach den Opfern liefern Dame und Türme gemeinsam das Matt.","Turm nimmt auf a4 – Beginn eines erzwungenen Matts."],"en":["The white king is hemmed in on the back rank and the edge by sacrifices.","After the sacrifices the queen and rooks combine to deliver mate.","Rook takes on a4 — beginning a forced mate."],"hr":["Bijeli kralj je opkoljen na posljednjoj liniji i rubu žrtvama.","Nakon žrtava dama i topovi zajedno daju mat.","Top uzima na a4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.060' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König verliert durch ein Damenopfer sein Bauerndach.","Nach dem Opfer ziehen Dame und Türme zur Königsjagd auf den offenen Linien zusammen.","Dame nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["A queen sacrifice strips the black king of its pawn roof.","After the sacrifice the queen and rooks converge on the open lines to hunt the king.","Queen takes on h7 — beginning a forced mate."],"hr":["Žrtva dame skida crnome kralju pješački krov.","Nakon žrtve dama i topovi se sjedinjuju po otvorenim linijama u lovu na kralja.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.061' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Turmopfer aus seinem Eck gelockt.","Nach dem Opfer jagen Dame und Bauer den König über das Brett bis zum Matt.","Turm nimmt auf h8 – Beginn eines erzwungenen Matts."],"en":["A rook sacrifice lures the black king out of its corner.","After the sacrifice the queen and a pawn chase the king across the board to mate.","Rook takes on h8 — beginning a forced mate."],"hr":["Žrtva topa izvlači crnoga kralja iz njegova kuta.","Nakon žrtve dama i pješak gone kralja preko ploče do mata.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.062' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König irrt im offenen Brett umher und wird von Dame und Springer eingefangen.","Dame und Springer schnüren das Netz zu, bis die Dame das Matt setzt.","Dame nach d8 – Beginn eines erzwungenen Matts."],"en":["The black king wanders in the open and gets caught by the queen and knight.","The queen and knight tighten the net until the queen delivers mate.","Queen to d8 — beginning a forced mate."],"hr":["Crni kralj luta po otvorenoj ploči i biva uhvaćen damom i skakačem.","Dama i skakač stežu mrežu dok dama ne da mat.","Dama na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.063' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König hat dünne Bauerndeckung; ein Damenopfer öffnet die offene Linie.","Nach dem Opfer übernehmen die Türme die offene Linie und treiben den König ins Matt.","Dame nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["The black king has thin pawn cover, and a queen sacrifice opens the file.","After the sacrifice the rooks take over the open file and drive the king to mate.","Queen takes on h7 — beginning a forced mate."],"hr":["Crni kralj ima tanak pješački zaklon, a žrtva dame otvara liniju.","Nakon žrtve topovi preuzimaju otvorenu liniju i tjeraju kralja u mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.002' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird mit Turm und Läufern im Zentrum eingekesselt.","Die Türme und ein Läufer schnüren das Netz, bis ein Turm das Matt liefert.","Turm nach d8 – Beginn eines erzwungenen Matts."],"en":["The black king gets boxed in the centre by rook and bishops.","The rooks and a bishop tighten the net until a rook delivers mate.","Rook to d8 — beginning a forced mate."],"hr":["Crni kralj biva opkoljen topom i lovcima u sredini.","Topovi i lovac stežu mrežu dok top ne da mat.","Top na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.004' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König lebt von wackliger Deckung; ein Springeropfer reißt die Linie auf.","Nach dem Opfer dringen Türme und Dame zum entscheidenden Mattangriff vor.","Springer nimmt auf g5 – Beginn eines erzwungenen Matts."],"en":["The black king relies on shaky cover that a knight sacrifice rips open.","After the sacrifice the rooks and queen break through for the decisive mating attack.","Knight takes on g5 — beginning a forced mate."],"hr":["Crni kralj se oslanja na klimav zaklon koji žrtva skakača razdire.","Nakon žrtve topovi i dama probijaju do odlučujućeg matnog napada.","Skakač uzima na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.005' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Damenopfer aus seinem Bauerndach gerissen.","Nach dem Opfer arbeiten Türme und Dame zusammen, bis ein Turm das Matt gibt.","Dame nimmt auf h7 – Beginn eines erzwungenen Matts."],"en":["A queen sacrifice tears the black king out of its pawn roof.","After the sacrifice the rooks and queen combine until a rook delivers mate.","Queen takes on h7 — beginning a forced mate."],"hr":["Žrtva dame izvlači crnoga kralja iz pješačkog krova.","Nakon žrtve topovi i dama surađuju dok top ne da mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.006' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König sitzt eingeengt in der Ecke und seine Verteidiger sind überlastet.","Mit einem Damenopfer reißt du die Königsstellung auf und die schweren Figuren liefern das Matt.","Läufer schlägt auf f8 – Beginn eines erzwungenen Matts."],"en":["The black king is hemmed into the corner and its defenders are overworked.","A sacrifice tears open the king''s cover so your heavy pieces can mate.","Bishop takes on f8 — the start of a forced mate."],"hr":["Crni kralj je stiješnjen u kutu, a njegovi branitelji su preopterećeni.","Žrtvom razbijaš kraljev zaklon kako bi teške figure dale mat.","Lovac uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.007' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
