UPDATE BookPuzzles SET HintsJson='{"de":["Die Bauern vor dem schwarzen König werden weggeräumt, dann bricht das Mattnetz zusammen.","Mit einem Damenopfer öffnest du den König und schlägst mit den schweren Figuren zu.","Dame nach h6 – Beginn eines erzwungenen Matts."],"en":["The pawns shielding the black king are torn away and the net closes.","A queen sacrifice exposes the king before your heavy pieces finish him.","Queen to h6 — start of a forced mate."],"hr":["Pješaci koji štite crnog kralja se uklanjaju i mreža se zatvara.","Žrtva dame razgolićuje kralja prije nego ga teške figure dokrajče.","Dama na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.039' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist in der Ecke eingeschnürt und überlastete Verteidiger brechen weg.","Ein Turmopfer reißt die Stellung auf, dann setzt die Dame mit Springerhilfe matt.","Turm schlägt auf h2 – Beginn eines erzwungenen Matts."],"en":["The white king is boxed into the corner with his defenders overloaded.","A rook sacrifice rips things open and queen plus knight finish the job.","Rook takes on h2 — start of a forced mate."],"hr":["Bijeli kralj je stiješnjen u kutu, a branitelji preopterećeni.","Žrtva topa otvara položaj, a dama uz skakača dovršava posao.","Top uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.040' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist an den Rand gefesselt, sein Bauernschild wird abgetragen.","Ein Damenopfer öffnet die Linie, dann jagt der Turm den König zum Matt.","Dame schlägt auf g6 – Beginn eines erzwungenen Matts."],"en":["The black king is pinned to the edge and his pawn cover gets stripped.","A queen sacrifice opens the line so the rook can hunt the king down.","Queen takes on g6 — start of a forced mate."],"hr":["Crni kralj je prikovan uz rub, a pješačka zaštita mu se uklanja.","Žrtva dame otvara liniju da top može potjerati kralja do mata.","Dama uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.041' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist eingeengt, und seine Verteidiger sind heillos überlastet.","Mit Läufer und Dame webst du ein Netz, das der Turm zum Matt schließt.","Läufer nach e4 – Beginn eines erzwungenen Matts."],"en":["The black king is hemmed in and his defenders are hopelessly overloaded.","Bishop and queen weave a net that a rook finally closes for mate.","Bishop to e4 — start of a forced mate."],"hr":["Crni kralj je stiješnjen, a branitelji beznadno preopterećeni.","Lovac i dama pletu mrežu koju top na kraju zatvara za mat.","Lovac na e4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.042' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König klebt am Rand, und ein Verteidiger ist überlastet.","Ein Opfer lockt eine Figur weg, dann setzen die Türme matt.","Dame nach f1 – Beginn eines erzwungenen Matts."],"en":["The white king is stuck on the edge and a defender is overworked.","A sacrifice lures a piece away so your rooks can deliver mate.","Queen to f1 — start of a forced mate."],"hr":["Bijeli kralj je zaglavljen uz rub, a branitelj preopterećen.","Žrtva odvlači figuru kako bi topovi mogli dati mat.","Dama na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.043' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Die Bauern vor dem schwarzen König werden geräumt, ein durchgehender Bauer entscheidet.","Nach zwei Opfern auf der Königslinie macht ein vorrückender Bauer den Sack zu.","Dame schlägt auf f6 – Beginn eines erzwungenen Matts."],"en":["The pawns in front of the black king are cleared for a passed pawn to decide.","After two sacrifices near the king, an advancing pawn seals the mate.","Queen takes on f6 — start of a forced mate."],"hr":["Pješaci ispred crnog kralja se uklanjaju da prolazni pješak odluči.","Nakon dvije žrtve kraj kralja, napredujući pješak zapečaćuje mat.","Dama uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.044' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird aus seiner Deckung gelockt und über das Brett gejagt.","Mit Dame und Läufern treibst du den König, bis er endgültig stellt.","Dame schlägt auf g2 – Beginn eines erzwungenen Matts."],"en":["The white king is dragged from his cover and chased across the board.","Queen and bishops drive the king until he runs out of squares.","Queen takes on g2 — start of a forced mate."],"hr":["Bijeli kralj se izvlači iz zaklona i progoni preko ploče.","Dama i lovci tjeraju kralja dok mu ne ponestane polja.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.045' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König sitzt am Rand fest, und seine Figuren stehen ihm im Weg.","Dame und Läufer arbeiten zusammen und treiben den König ins Matt.","Dame nach f1 – Beginn eines erzwungenen Matts."],"en":["The white king is stuck on the edge with his own pieces in the way.","Queen and bishop work together to drive the king into mate.","Queen to f1 — start of a forced mate."],"hr":["Bijeli kralj je zaglavljen uz rub, a vlastite mu figure smetaju.","Dama i lovac surađuju i tjeraju kralja u mat.","Dama na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.046' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch Zugzwang und Schachserie ins Netz gedrängt.","Deine Dame manövriert, bis der Turm den entscheidenden Schlag setzen kann.","Dame nach h4 – Beginn eines erzwungenen Matts."],"en":["The black king is squeezed into a net by repeated checks and zugzwang.","Your queen manoeuvres until the rook can land the decisive blow.","Queen to h4 — start of a forced mate."],"hr":["Crni kralj se utjeruje u mrežu nizom šahova i cugcvanga.","Tvoja dama manevrira dok top ne zada odlučujući udarac.","Dama na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.047' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird aus seiner Stellung gezerrt und unaufhaltsam gejagt.","Ein Damenopfer öffnet den König, dann setzen Turm und Dame matt.","Dame nach g6 – Beginn eines erzwungenen Matts."],"en":["The white king is dragged out and chased without respite.","A queen sacrifice opens the king so rook and queen can mate.","Queen to g6 — start of a forced mate."],"hr":["Bijeli kralj se izvlači i progoni bez predaha.","Žrtva dame otvara kralja da top i dama daju mat.","Dama na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.048' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird durch ein Opfer entblößt und ins Mattnetz getrieben.","Nach dem Opfer übernehmen Dame, Springer und Läufer die Jagd.","Turm schlägt auf b2 – Beginn eines erzwungenen Matts."],"en":["A sacrifice strips the white king bare and forces him into a mating net.","After the sacrifice, queen, knight and bishop take over the hunt.","Rook takes on b2 — start of a forced mate."],"hr":["Žrtva ogoljuje bijelog kralja i tjera ga u matnu mrežu.","Nakon žrtve dama, skakač i lovac preuzimaju hajku.","Top uzima na b2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.049' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist hinter eigenen Figuren eingeschlossen und kann nicht atmen.","Mit einem Läuferopfer und einem freien Bauern zwingst du das Matt herbei.","Läufer schlägt auf f6 – Beginn eines erzwungenen Matts."],"en":["The black king is boxed in behind his own pieces with no air.","A bishop sacrifice and a passed pawn force the mate home.","Bishop takes on f6 — start of a forced mate."],"hr":["Crni kralj je zatvoren iza vlastitih figura bez zraka.","Žrtva lovca i prolazni pješak iznuđuju mat.","Lovac uzima na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.050' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus seinem Bauernschild gerissen.","Nach dem Opfer treiben Dame und Springer den König ins Matt.","Dame schlägt auf h7 – Beginn eines erzwungenen Matts."],"en":["A sacrifice tears the black king out of his pawn shelter.","Then queen and knight drive the exposed king into mate.","Queen takes on h7 — start of a forced mate."],"hr":["Žrtva izvlači crnog kralja iz pješačkog zaklona.","Zatim dama i skakač tjeraju izloženog kralja u mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.051' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist eingeengt, und eine Reihe von Opfern zerschlägt seine Deckung.","Dame und Turm dringen ein, dann gibt der Läufer den letzten Schlag.","Dame nach c5 – Beginn eines erzwungenen Matts."],"en":["The black king is cramped and a chain of sacrifices shatters his cover.","Queen and rook break in before the bishop delivers the final stroke.","Queen to c5 — start of a forced mate."],"hr":["Crni kralj je skučen, a niz žrtava razbija mu zaštitu.","Dama i top prodiru prije nego lovac zada konačni udarac.","Dama na c5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.052' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird aus der Ecke gelockt und von den weißen Figuren umstellt.","Springer und Dame koordinieren die Jagd bis zum erstickten Schlussbild.","Springer schlägt auf g6 – Beginn eines erzwungenen Matts."],"en":["The black king is lured from the corner and surrounded by White''s pieces.","Knight and queen coordinate the hunt down to a smothered finish.","Knight takes on g6 — start of a forced mate."],"hr":["Crni kralj se izvlači iz kuta i okružuju ga bijele figure.","Skakač i dama usklađuju hajku do ugušenog završetka.","Skakač uzima na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.053' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch fortgesetzte Schachs an den Rand getrieben.","Dame und Turm verfolgen den König, bis der zweite Turm matt setzt.","Dame schlägt auf f7 – Beginn eines erzwungenen Matts."],"en":["A series of checks drives the black king to the edge with no shelter.","Queen and rook pursue the king until the second rook mates.","Queen takes on f7 — start of a forced mate."],"hr":["Niz šahova tjera crnog kralja prema rubu bez zaklona.","Dama i top progone kralja dok drugi top ne da mat.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.054' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König sitzt in der Ecke fest, seine Verteidiger sind überlastet.","Nach Opfern auf der Königslinie schließt der Turm das Mattnetz.","Dame schlägt auf g2 – Beginn eines erzwungenen Matts."],"en":["The white king is trapped in the corner with overloaded defenders.","After sacrifices near the king, a rook closes the mating net.","Queen takes on g2 — start of a forced mate."],"hr":["Bijeli kralj je zarobljen u kutu s preopterećenim braniteljima.","Nakon žrtava kraj kralja, top zatvara matnu mrežu.","Dama uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.055' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird durch ein Opfer aus seiner Rochadestellung gerissen.","Dame und Springer jagen den entblößten König quer über das Brett.","Turm schlägt auf g7 – Beginn eines erzwungenen Matts."],"en":["A sacrifice rips the black king out of his castled position.","Queen and knight then chase the bare king right across the board.","Rook takes on g7 — start of a forced mate."],"hr":["Žrtva izvlači crnog kralja iz rokirane pozicije.","Dama i skakač zatim progone ogoljenog kralja preko cijele ploče.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.056' AND BookFileName IN ('chessable-u5-49690.pgn','1001 Deadly Checkmates_firstkey.pgn');
